INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', 'rust-fundamentals', '{"EN": "Rust Fundamentals", "ES": "Fundamentos de Rust"}', '{"EN": "The complete guide to the Rust programming language. From installation and ownership to advanced concurrency, unsafe code, and cross-compilation.", "ES": "La gu\u00eda completa del lenguaje de programaci\u00f3n Rust. Desde la instalaci\u00f3n y ownership hasta concurrencia avanzada, c\u00f3digo unsafe y compilaci\u00f3n cruzada."}', 'Beginner', 'https://placehold.co/800x500/CE412B/FFFFFF/png?text=Rust+Fundamentals&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('66539634-a088-58c5-baef-f4a870c3fbb2', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "1. Introduction to Rust", "ES": "1. Introducci\u00f3n a Rust"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a2773a83-df34-5503-aaa4-1bced4dab5e5', '66539634-a088-58c5-baef-f4a870c3fbb2', '{"EN": "Philosophy & History", "ES": "Filosof\u00eda e Historia"}', '{"EN": "# Origins\nRust started as a personal project by **Graydon Hoare** at Mozilla in 2006. The browser engine **Servo** was the testbed for the language. Version 1.0 was released in 2015, guaranteeing backward compatibility (\"Stability without Stagnation\").\n\n## The Three Pillars\nRust aims to solve the \"Trilemma\" of systems programming:\n1.  **Memory Safety**: Rust guarantees memory safety at compile-time preventing segfaults, dangling pointers, and buffer overflows without a Garbage Collector (GC).\n2.  **Concurrency**: The type system prevents data races. If code compiles, it is free of data races. This is known as \"Fearless Concurrency\".\n3.  **Performance**: Rust uses LLVM as a backend. It features zero-cost abstractions, meaning high-level constructs (like iterators) compile down to the same assembly as hand-written loops.\n\n## Used By\n*   **Linux Kernel**: Since version 6.1, Rust is the second official language of the Kernel.\n*   **Android**: Used for low-level system components (Bluetooth, Keystore) to reduce vulnerabilities.\n*   **AWS/Microsoft/Google**: For critical infrastructure requiring high performance and security.", "ES": "# Or\u00edgenes\nRust comenz\u00f3 como un proyecto personal de **Graydon Hoare** en Mozilla en 2006. El motor de navegador **Servo** fue el banco de pruebas. La versi\u00f3n 1.0 se lanz\u00f3 en 2015, garantizando retrocompatibilidad (\"Estabilidad sin Estancamiento\").\n\n## Los Tres Pilares\nRust busca resolver el \"Trilema\" de la programaci\u00f3n de sistemas:\n1.  **Seguridad de Memoria**: Garantiza seguridad en tiempo de compilaci\u00f3n previniendo segfaults, punteros colgantes y desbordamientos de buffer sin usar un Recolector de Basura (GC).\n2.  **Concurrencia**: El sistema de tipos previene condiciones de carrera (data races). Si compila, est\u00e1 libre de ellas. Conocido como \"Concurrencia sin Miedo\".\n3.  **Rendimiento**: Usa LLVM como backend. Posee abstracciones de costo cero; construcciones de alto nivel (como iteradores) compilan al mismo ensamblador que bucles manuales.\n\n## Usado Por\n*   **Kernel de Linux**: Desde la versi\u00f3n 6.1, Rust es el segundo lenguaje oficial del Kernel.\n*   **Android**: Usado para componentes de bajo nivel (Bluetooth, Keystore) para reducir vulnerabilidades.\n*   **AWS/Microsoft/Google**: Para infraestructura cr\u00edtica que requiere alto rendimiento."}', false, NULL, NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!(\"Reliability + Performance = Rust\");\n    \n    let year = 2015;\n    println!(\"Stable since {}\", year);\n}', NULL, E'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, E'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, E'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!(\"Reliability + Performance = Rust\");\n    \n    let year = 2015;\n    println!(\"Stable since {}\", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!(\"Reliability + Performance = Rust\");\n    \n    let year = 2015;\n    println!(\"Stable since {}\", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!("Reliability + Performance = Rust");\n    \n    let year = 2015;\n    println!("Stable since {}", year);\n}', NULL, 'fn main() {\n    // Rust is statically typed and compiled.\n    // This macro prints to stdout.\n    println!(\"Reliability + Performance = Rust\");\n    \n    let year = 2015;\n    println!(\"Stable since {}\", year);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('88139d2d-d848-5fbb-8df5-c2f83be61164', '66539634-a088-58c5-baef-f4a870c3fbb2', '{"EN": "Toolchain Internals", "ES": "Internos del Toolchain"}', '{"EN": "# Rustup: The Multiplexer\nYou don''t install `rustc` directly. You use `rustup`, which manages toolchains:\n*   **Channels**: `stable` (every 6 weeks), `beta`, `nightly` (bleeding edge features).\n*   **Targets**: Cross-compilation targets (e.g., `wasm32-unknown-unknown`).\n*   **Overrides**: You can pin a specific directory to use a specific compiler version (`rustup override set nightly`).\n\n## Cargo: The Build System\nCargo handles the entire lifecycle:\n1.  **Dependency Resolution**: Uses `Cargo.toml` (manifest) and `Cargo.lock` (exact versions) to ensure reproducible builds.\n2.  **Compilation**: Invokes `rustc` with correct flags.\n3.  **Testing**: A built-in test runner.\n4.  **Documentation**: `cargo doc` generates HTML docs from comments.\n\n## Profiles\n*   `dev`: Default. Debug symbols enabled, optimizations disabled. Fast compile.\n*   `release`: Optimizations enabled (O3), LTO (Link Time Optimization). Slow compile, fast runtime.", "ES": "# Rustup: El Multiplexor\nNo instalas `rustc` directamente. Usas `rustup`, que gestiona toolchains:\n*   **Canales**: `stable` (cada 6 sem), `beta`, `nightly` (experimental).\n*   **Targets**: Objetivos de compilaci\u00f3n cruzada (ej. `wasm32-unknown-unknown`).\n*   **Overrides**: Puedes fijar un directorio espec\u00edfico a una versi\u00f3n del compilador (`rustup override set nightly`).\n\n## Cargo: Sistema de Construcci\u00f3n\nCargo maneja el ciclo de vida completo:\n1.  **Resoluci\u00f3n de Dependencias**: Usa `Cargo.toml` (manifiesto) y `Cargo.lock` (versiones exactas) para builds reproducibles.\n2.  **Compilaci\u00f3n**: Invoca `rustc` con las banderas correctas.\n3.  **Testing**: Ejecutor de pruebas integrado.\n4.  **Documentaci\u00f3n**: `cargo doc` genera HTML desde comentarios.\n\n## Perfiles\n*   `dev`: Por defecto. S\u00edmbolos de debug, sin optimizaci\u00f3n. Compilaci\u00f3n r\u00e1pida.\n*   `release`: Optimizado (O3), LTO. Compilaci\u00f3n lenta, ejecuci\u00f3n r\u00e1pida."}', false, NULL, NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!(\"Running in Debug mode (slower)\");\n\n    #[cfg(not(debug_assertions))]\n    println!(\"Running in Release mode (optimized)\");\n}', NULL, E'// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, E'// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, E'// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!(\"Running in Debug mode (slower)\");\n\n    #[cfg(not(debug_assertions))]\n    println!(\"Running in Release mode (optimized)\");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!(\"Running in Debug mode (slower)\");\n\n    #[cfg(not(debug_assertions))]\n    println!(\"Running in Release mode (optimized)\");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!("Running in Debug mode (slower)");\n\n    #[cfg(not(debug_assertions))]\n    println!("Running in Release mode (optimized)");\n}', NULL, '// To compile for release:\n// cargo build --release\n\nfn main() {\n    #[cfg(debug_assertions)]\n    println!(\"Running in Debug mode (slower)\");\n\n    #[cfg(not(debug_assertions))]\n    println!(\"Running in Release mode (optimized)\");\n}', 2);
