INSERT INTO modules (id, course_id, title, "order") VALUES ('afc7d5b7-8920-5c60-aff0-e20234f1a359', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "2. Memory & Primitive Types", "ES": "2. Memoria y Tipos Primitivos"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('7a86de71-facc-5d55-8d66-2132079d6cc6', 'afc7d5b7-8920-5c60-aff0-e20234f1a359', '{"EN": "Scalar Types Internals", "ES": "Internos de Tipos Escalares"}', '{"EN": "# Deep Dive: Integer Representation\nRust integers have fixed widths. Signed integers (`i8`-`i128`) use **Two''s Complement** representation.\n*   **Max Value**: $2^{(n-1)} - 1$\n*   **Min Value**: $-2^{(n-1)}$\n*   **usize/isize**: These are \"pointer-sized\" integers. Their size depends on the target architecture (4 bytes on 32-bit systems, 8 bytes on 64-bit systems). They are required for indexing arrays and vectors because an index cannot exceed the addressable memory space.\n\n## Floating Point (IEEE 754)\nRust follows the IEEE 754-2008 standard for floating-point arithmetic.\n*   `f32`: Single precision. 1 sign bit, 8 exponent bits, 23 mantissa bits.\n*   `f64`: Double precision. 1 sign bit, 11 exponent bits, 52 mantissa bits.\n*   **Warning**: Floats cannot be used as HashMap keys because `NaN != NaN`, breaking the `Eq` trait contract.\n\n## The Boolean Layout\nA `bool` is 1 byte in size, not 1 bit.\n*   Representation: `0x00` (false) and `0x01` (true).\n*   **Safety**: Creating a bool with any other byte value (e.g., via `unsafe` transmutation) is **Undefined Behavior**.\n\n## The Character Type (Unicode Scalar Value)\nUnlike C++ `char` (1 byte) or Java `char` (2 bytes UTF-16), Rust''s `char` is **always 4 bytes** (32 bits).\n*   It represents a **Unicode Scalar Value**.\n*   Valid Range: `U+0000` to `U+D7FF` and `U+E000` to `U+10FFFF`.\n*   It explicitly excludes \"Surrogate Pairs\" used in UTF-16.\n*   This makes `char` fundamentally different from `String` (which is UTF-8 encoded bytes).\n\n## Overflow Safety\n*   **Debug Build**: Rust enables overflow checks. Panics on overflow.\n*   **Release Build**: Rust disables checks for performance. Overflow wraps (255 + 1 = 0 for u8).\n*   **Manual Control**: Use `wrapping_add`, `checked_add` (returns Option), or `saturating_add` (stops at MAX) to explicitly define behavior regardless of build profile.", "ES": "# Profundizaci\u00f3n: Representaci\u00f3n de Enteros\nLos enteros en Rust tienen anchos fijos. Los enteros con signo (`i8`-`i128`) usan **Complemento a Dos**.\n*   **Valor M\u00e1x**: $2^{(n-1)} - 1$\n*   **Valor M\u00edn**: $-2^{(n-1)}$\n*   **usize/isize**: Enteros del \"tama\u00f1o del puntero\". Su tama\u00f1o depende de la arquitectura (4 bytes en 32-bit, 8 bytes en 64-bit). Son requeridos para indexar arrays porque un \u00edndice no puede exceder el espacio de memoria direccionable.\n\n## Punto Flotante (IEEE 754)\nRust sigue el est\u00e1ndar IEEE 754-2008.\n*   `f32`: Precisi\u00f3n simple. 1 bit signo, 8 exponente, 23 mantisa.\n*   `f64`: Doble precisi\u00f3n. 1 bit signo, 11 exponente, 52 mantisa.\n*   **Advertencia**: Los Floats no pueden ser claves de HashMap porque `NaN != NaN`, rompiendo el contrato del trait `Eq`.\n\n## Layout del Booleano\nUn `bool` ocupa 1 byte, no 1 bit.\n*   Representaci\u00f3n: `0x00` (false) y `0x01` (true).\n*   **Seguridad**: Crear un bool con otro valor (ej. v\u00eda `unsafe`) es **Comportamiento Indefinido (UB)**.\n\n## El Tipo Car\u00e1cter (Valor Escalar Unicode)\nA diferencia de C++ `char` (1 byte) o Java `char` (2 bytes UTF-16), el `char` de Rust es **siempre 4 bytes** (32 bits).\n*   Representa un **Valor Escalar Unicode**.\n*   Rango V\u00e1lido: `U+0000` a `U+D7FF` y `U+E000` a `U+10FFFF`.\n*   Excluye expl\u00edcitamente \"Pares Sustitutos\" de UTF-16.\n*   Esto lo hace fundamentalmente diferente a `String` (que es UTF-8).\n\n## Seguridad de Desbordamiento (Overflow)\n*   **Debug**: Rust activa chequeos. P\u00e1nico si hay overflow.\n*   **Release**: Desactiva chequeos por rendimiento. Hace wrap (255 + 1 = 0 en u8).\n*   **Control Manual**: Usa `wrapping_add`, `checked_add` (retorna Option), o `saturating_add` para definir comportamiento expl\u00edcito."}', false, NULL, NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!(\"Wrapped: {}\", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!(\"Result: {}\", v),\n        None => println!(\"Overflow detected!\"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''\ud83d\ude3b'';\n    println!(\"Char size: {} bytes\", std::mem::size_of_val(&heart_cat));\n    println!(\"Char value: {:x}\", heart_cat as u32);\n}', NULL, E'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, E'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, E'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!(\"Wrapped: {}\", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!(\"Result: {}\", v),\n        None => println!(\"Overflow detected!\"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''\ud83d\ude3b'';\n    println!(\"Char size: {} bytes\", std::mem::size_of_val(&heart_cat));\n    println!(\"Char value: {:x}\", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!(\"Wrapped: {}\", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!(\"Result: {}\", v),\n        None => println!(\"Overflow detected!\"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''\ud83d\ude3b'';\n    println!(\"Char size: {} bytes\", std::mem::size_of_val(&heart_cat));\n    println!(\"Char value: {:x}\", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!("Wrapped: {}", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!("Result: {}", v),\n        None => println!("Overflow detected!"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''😻'';\n    println!("Char size: {} bytes", std::mem::size_of_val(&heart_cat));\n    println!("Char value: {:x}", heart_cat as u32);\n}', NULL, 'fn main() {\n    // Integer overflow handling\n    let a: u8 = 255;\n    \n    // Explicit wrapping (safe in all modes)\n    let wrapped = a.wrapping_add(1); \n    println!(\"Wrapped: {}\", wrapped); // 0\n    \n    // Checked arithmetic (returns Option)\n    match a.checked_add(1) {\n        Some(v) => println!(\"Result: {}\", v),\n        None => println!(\"Overflow detected!\"),\n    }\n    \n    // Char is 4 bytes\n    let heart_cat = ''\ud83d\ude3b'';\n    println!(\"Char size: {} bytes\", std::mem::size_of_val(&heart_cat));\n    println!(\"Char value: {:x}\", heart_cat as u32);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('2cbcbcd9-8c4e-581f-9d41-3b0cb1fb64e2', 'afc7d5b7-8920-5c60-aff0-e20234f1a359', '{"EN": "Alignment & Padding", "ES": "Alineaci\u00f3n y Padding"}', '{"EN": "# Memory Alignment\nCPU reads are efficient when data is aligned to specific addresses (usually multiples of the data size).\n*   A `u32` usually needs 4-byte alignment.\n*   A `u64` usually needs 8-byte alignment.\n\n## Tuple Layout & Padding\nConsider the tuple `t: (u8, u32)`.\n1.  `u8` takes 1 byte.\n2.  `u32` takes 4 bytes, but it **must** start at a memory address multiple of 4.\n3.  The compiler inserts **3 bytes of padding** after the `u8`.\n4.  Total Size = 1 (u8) + 3 (padding) + 4 (u32) = **8 bytes**.\n\nThis explains why reordering fields in structs can save memory (Rust does this automatically for structs, but tuples retain order).\n\n## Zero Sized Types (ZST)\nThe Unit Type `()` occupies **0 bytes** of memory.\nIt exists only at compile time for type checking. Vectors of ZSTs (e.g., `Vec<()>`) allocate no heap memory; they essentially just store a length counter. This allows highly optimized sets like `HashSet<T>` which is just a `HashMap<T, ()>`.", "ES": "# Alineaci\u00f3n de Memoria\nLas lecturas del CPU son eficientes cuando los datos est\u00e1n alineados a direcciones espec\u00edficas.\n*   Un `u32` usualmente requiere alineaci\u00f3n de 4 bytes.\n*   Un `u64` usualmente requiere alineaci\u00f3n de 8 bytes.\n\n## Layout de Tuplas y Padding\nConsidera la tupla `t: (u8, u32)`.\n1.  `u8` toma 1 byte.\n2.  `u32` toma 4 bytes, pero **debe** iniciar en una direcci\u00f3n m\u00faltiplo de 4.\n3.  El compilador inserta **3 bytes de padding (relleno)** despu\u00e9s del `u8`.\n4.  Tama\u00f1o Total = 1 (u8) + 3 (padding) + 4 (u32) = **8 bytes**.\n\nEsto explica por qu\u00e9 reordenar campos en structs puede ahorrar memoria.\n\n## Tipos de Tama\u00f1o Cero (ZST)\nEl Tipo Unidad `()` ocupa **0 bytes**.\nExiste solo en compilaci\u00f3n. Vectores de ZSTs (ej. `Vec<()>`) no asignan memoria en el heap; esencialmente solo guardan un contador de longitud. Esto permite optimizaciones como `HashSet<T>` que es internamente `HashMap<T, ()>`."}', false, NULL, NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!("Size of unit: {} bytes", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!("Size of [(); 1000]: {} bytes", mem::size_of_val(&array_of_units));\n}', NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!("Size of unit: {} bytes", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!("Size of [(); 1000]: {} bytes", mem::size_of_val(&array_of_units));\n}', NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!("Size of unit: {} bytes", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!("Size of [(); 1000]: {} bytes", mem::size_of_val(&array_of_units));\n}', NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!("Size of unit: {} bytes", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!("Size of [(); 1000]: {} bytes", mem::size_of_val(&array_of_units));\n}', NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!("Size of unit: {} bytes", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!("Size of [(); 1000]: {} bytes", mem::size_of_val(&array_of_units));\n}', NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!("Size of unit: {} bytes", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!("Size of [(); 1000]: {} bytes", mem::size_of_val(&array_of_units));\n}', NULL, 'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!(\"Size of (u8, u32): {} bytes\", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let unit: () = ();\n    println!(\"Size of unit: {} bytes\", mem::size_of_val(&unit));\n    \n    let array_of_units = [(); 1000];\n    println!(\"Size of [(); 1000]: {} bytes\", mem::size_of_val(&array_of_units));\n}', NULL, E'use std::mem;\n\nfn main() {\n    // Alignment demonstration\n    let tuple: (u8, u32) = (1, 100);\n    \n    // Size is NOT 1 + 4 = 5. It is 8 due to padding.\n    println!("Size of (u8, u32): {} bytes", mem::size_of_val(&tuple));\n    \n    // ZST (Zero Sized Type)\n    let uni