INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('c45408de-91cd-5827-8a0e-6d82e592472a', 'afc7d5b7-8920-5c60-aff0-e20234f1a359', '{"EN": "Lab: Memory Internals", "ES": "Lab: Internos de Memoria"}', '{"EN": "Test your understanding of memory layout.", "ES": "Prueba tu entendimiento del layout de memoria."}', true, NULL, '[{"id": "q2-1", "question": {"EN": "What is the size of `(u8, u16)` on most architectures?", "ES": "\u00bfCu\u00e1l es el tama\u00f1o de `(u8, u16)` en la mayor\u00eda de arquitecturas?"}, "options": {"EN": ["3 bytes", "4 bytes", "2 bytes"], "ES": ["3 bytes", "4 bytes", "2 bytes"]}, "correctIndex": 1, "explanation": {"EN": "1 byte (u8) + 1 byte (padding) + 2 bytes (u16) = 4 bytes to satisfy u16 alignment.", "ES": "1 byte (u8) + 1 byte (padding) + 2 bytes (u16) = 4 bytes para satisfacer la alineaci\u00f3n de u16."}}, {"id": "q2-2", "question": {"EN": "Does `char` in Rust support UTF-16 surrogates?", "ES": "\u00bfSoporta `char` en Rust surrogates UTF-16?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "No, `char` represents a valid Unicode Scalar Value, excluding surrogates.", "ES": "No, `char` representa un Valor Escalar Unicode v\u00e1lido, excluyendo surrogates."}}]', NULL, '[{"id": "q2-1", "question": {"EN": "What is the size of `(u8, u16)` on most architectures?", "ES": "\u00bfCu\u00e1l es el tama\u00f1o de `(u8, u16)` en la mayor\u00eda de arquitecturas?"}, "options": {"EN": ["3 bytes", "4 bytes", "2 bytes"], "ES": ["3 bytes", "4 bytes", "2 bytes"]}, "correctIndex": 1, "explanation": {"EN": "1 byte (u8) + 1 byte (padding) + 2 bytes (u16) = 4 bytes to satisfy u16 alignment.", "ES": "1 byte (u8) + 1 byte (padding) + 2 bytes (u16) = 4 bytes para satisfacer la alineaci\u00f3n de u16."}}, {"id": "q2-2", "question": {"EN": "Does `char` in Rust support UTF-16 surrogates?", "ES": "\u00bfSoporta `char` en Rust surrogates UTF-16?"}, "options": {"EN": ["Yes", "No