INSERT INTO modules (id, course_id, title, "order") VALUES ('16d881e5-be7e-58aa-9ec2-68a9b63fb227', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "3. Control Flow & Patterns", "ES": "3. Flujo de Control y Patrones"}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('69124689-6140-5bda-946c-7c1ced093519', '16d881e5-be7e-58aa-9ec2-68a9b63fb227', '{"EN": "Expression-Oriented Design", "ES": "Dise\u00f1o Orientado a Expresiones"}', '{"EN": "# Everything is an Expression\nIn Rust, the distinction between statements and expressions is paramount.\n*   **Expressions**: Evaluate to a value. `5`, `x + 1`, `if ...`, `loop ...`, `{ ... }`.\n*   **Statements**: Instructions ending in `;`. They return the Unit type `()`.\n\nThis allows powerful composition. You can assign the result of a block directly to a variable.\n```rust\nlet y = {\n    let x = 3;\n    x + 1 // No semicolon = return value\n};\n```\n\n## Diverging Functions (Never Type `!`)\nControl flow constructs like `return`, `break`, and `panic!` evaluate to the **Never type** (denoted as `!`). \nSince `!` can never effectively exist at runtime, it can be coerced into *any* type. This is why you can use `break` or `panic!` in a match arm that expects an integer; the compiler knows that code path never returns a value, so type safety is preserved.", "ES": "# Todo es una Expresi\u00f3n\nEn Rust, la distinci\u00f3n entre sentencias y expresiones es primordial.\n*   **Expresiones**: Eval\u00faan a un valor. `5`, `x + 1`, `if ...`, `loop ...`, `{ ... }`.\n*   **Sentencias**: Instrucciones terminadas en `;`. Retornan el tipo Unidad `()`.\n\nEsto permite composici\u00f3n poderosa. Puedes asignar el resultado de un bloque a una variable.\n\n## Funciones Divergentes (Tipo Never `!`)\nConstrucciones como `return`, `break`, y `panic!` eval\u00faan al **tipo Never** (denotado como `!`).\nComo `!` nunca puede existir efectivamente en runtime, puede ser forzado (coerced) a *cualquier* tipo. Por eso puedes usar `break` o `panic!` en un match que espera un entero; el compilador sabe que ese camino nunca retorna valor."}', false, NULL, NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!(\"Y: {}\", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!(\"Unexpected number!\"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, E'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, E'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, E'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!(\"Y: {}\", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!(\"Unexpected number!\"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!(\"Y: {}\", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!(\"Unexpected number!\"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!("Y: {}", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!("Unexpected number!"), // Evaluates to ! which coerces to i32\n    };\n}', NULL, 'fn main() {\n    let num = 10;\n    \n    // Block expression\n    let y = {\n        let x = 3;\n        x + num // Returns 13\n    };\n    \n    println!(\"Y: {}\", y);\n\n    // Using the Never type behavior\n    let x: i32 = match y {\n        13 => 100,\n        _ => panic!(\"Unexpected number!\"), // Evaluates to ! which coerces to i32\n    };\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('6048a9b9-0abd-51ab-961b-ceb319919b50', '16d881e5-be7e-58aa-9ec2-68a9b63fb227', '{"EN": "Loop Mechanics & Optimization", "ES": "Mec\u00e1nicas y Optimizaci\u00f3n de Bucles"}', '{"EN": "# Loops Under the Hood\n\n## The `loop` construct\nThis is the infinite loop primitive. It is distinct from `while true` because the compiler *knows* it doesn''t terminate (unless `break` is encountered). This aids flow analysis (e.g., initializing variables).\n*   Can return values: `break value;`.\n\n## The `for` Loop & IntoIterator\nRust''s `for` loop is syntactic sugar for the `IntoIterator` trait.\n```rust\nfor x in collection { ... }\n```\nIs roughly desugared to:\n```rust\nlet mut iter = collection.into_iter();\nwhile let Some(x) = iter.next() { ... }\n```\n\n## Range Optimization\nRanges like `0..10` are structs implementing `Iterator`. LLVM is extremely good at optimizing these. A standard `for i in 0..n` loop in Rust often compiles to the exact same assembly as a standard C `for(int i=0; i<n; i++)` loop, employing vectorization (SIMD) where possible.", "ES": "# Bucles Bajo el Cap\u00f3\n\n## La construcci\u00f3n `loop`\nEs la primitiva de bucle infinito. Distinto a `while true` porque el compilador *sabe* que no termina (a menos que haya `break`). Ayuda al an\u00e1lisis de flujo.\n*   Puede retornar valores: `break valor;`.\n\n## El Bucle `for` e IntoIterator\nEl `for` de Rust es az\u00facar sint\u00e1ctica para el trait `IntoIterator`.\nSe desglosa aproximadamente en un `while let Some(x) = iter.next()`.\n\n## Optimizaci\u00f3n de Rangos\nRangos como `0..10` son structs implementando `Iterator`. LLVM los optimiza extremadamente bien. Un bucle `for i in 0..n` en Rust a menudo compila al mismo ensamblador exacto que un bucle C, empleando vectorizaci\u00f3n (SIMD) donde es posible."}', false, NULL, NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!(\"[{}] = {}\", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!(\"Breaking at {}*{}\", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, E'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, E'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 because .iter() yields references\n    for (idx, val) in data.iter().enumerate() {\n        println!("[{}] = {}", idx, val);\n    }\n    \n    // Loop label\n    ''search: for i in 0..5 {\n        for j in 0..5 {\n            if i * j > 6 {\n                println!("Breaking at {}*{}", i, j);\n                break ''search;\n            }\n        }\n    }\n}', NULL, 'fn main() {\n    let data = [10, 20, 30];\n    \n    // ''val'' is &i32 