INSERT INTO modules (id, course_id, title, "order") VALUES ('c14eb783-1d07-5127-a7b4-f8ee602b41c5', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "4. Complex Data Types", "ES": "4. Tipos de Datos Complejos"}', 4);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('217b098a-7021-5908-8285-435eadffd354', 'c14eb783-1d07-5127-a7b4-f8ee602b41c5', '{"EN": "Struct Layout & Optimization", "ES": "Layout de Structs y Optimizaci\u00f3n"}', '{"EN": "# Struct Memory Layout\nIn C/C++, fields in a struct are laid out in memory exactly in the order they are defined.\nIn Rust, by default (`#[repr(Rust)]`), the compiler **reorders fields** to minimize padding and reduce size.\n\nExample:\n```rust\nstruct A {\n    a: u8,  // 1 byte\n    b: u32, // 4 bytes (needs alignment)\n    c: u8,  // 1 byte\n}\n```\n*   **C-Style**: u8 + 3 pad + u32 + u8 + 3 pad = **12 bytes**.\n*   **Rust**: u32 + u8 + u8 + 2 pad = **8 bytes**. Rust moves `b` to the start or end to align efficiently.\n\n## Field Visibility\nBy default, fields are private. You must use `pub` per field to make them accessible outside the defining module.\n\n## Tuple Structs (Newtype Pattern)\n`struct Meters(u32);`.\nUsed to create strict type boundaries. It allows the compiler to prevent you from adding `Meters` to `Seconds`, even though both are `u32` in memory. Zero-cost safety.", "ES": "# Layout de Memoria de Structs\nEn C/C++, los campos est\u00e1n en orden de definici\u00f3n.\nEn Rust, por defecto (`#[repr(Rust)]`), el compilador **reordena los campos** para minimizar el padding.\n\nEjemplo:\n```rust\nstruct A {\n    a: u8,  // 1 byte\n    b: u32, // 4 bytes (necesita alineaci\u00f3n)\n    c: u8,  // 1 byte\n}\n```\n*   **Estilo C**: u8 + 3 pad + u32 + u8 + 3 pad = **12 bytes**.\n*   **Rust**: u32 + u8 + u8 + 2 pad = **8 bytes**. Rust mueve `b` para alinear eficientemente.\n\n## Patr\u00f3n Newtype\n`struct Metros(u32);`.\nUsado para crear l\u00edmites de tipo estrictos. Permite al compilador prevenir que sumes `Metros` con `Segundos`, aunque ambos sean `u32`. Seguridad de costo cero."}', false, NULL, NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!(\"Rust Optimized Size: {}\", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!(\"C Unoptimized Size: {}\", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, E'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, E'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', NULL, 'use std::mem;\n\nstruct Optimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\n// Prevents reordering\n#[repr(C)]\nstruct Unoptimized {\n    a: u8,\n    b: u64,\n    c: u8,\n}\n\nfn main() {\n    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)\n    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)\n}', 