INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('3c523458-238d-515c-88db-1cb03254cea3', 'c14eb783-1d07-5127-a7b4-f8ee602b41c5', '{"EN": "Enum Internals & NPO", "ES": "Internos de Enum y NPO"}', '{"EN": "# Algebraic Data Types (Enums)\nRust Enums are Sum Types. Size = Size of largest variant + Discriminant (tag).\n\n## Discriminant\nAn integer tag used to determine which variant is active. Usually 1 byte, but can be larger if alignment requires it.\n\n## Null Pointer Optimization (NPO)\nThis is a critical optimization.\nConsider `Option<Box<i32>>`.\n*   `Box<i32>` is a pointer (cannot be null, non-zero).\n*   `Option::None` needs a way to be represented.\n*   Rust uses the \"0\" address to represent `None`.\n*   Therefore, `Option<Box<i32>>` takes **exactly the same space** as `Box<i32>`. There is no extra memory cost for the Option wrapper. This works for references `&T`, `Vec`, `String`, and `NonZero*` types.", "ES": "# Tipos de Datos Algebraicos (Enums)\nTama\u00f1o = Tama\u00f1o de la variante m\u00e1s grande + Discriminante (tag).\n\n## Discriminante\nUn tag entero usado para determinar la variante activa. Usualmente 1 byte.\n\n## Optimizaci\u00f3n de Puntero Nulo (NPO)\nUna optimizaci\u00f3n cr\u00edtica.\nConsidera `Option<Box<i32>>`.\n*   `Box<i32>` es un puntero (no puede ser null, no-cero).\n*   `Option::None` necesita representarse.\n*   Rust usa la direcci\u00f3n \"0\" para representar `None`.\n*   Por tanto, `Option<Box<i32>>` ocupa **exactamente el mismo espacio** que `Box<i32>`. Sin costo extra de memoria."}', false, NULL, NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!(\"Box<i32>: {}\", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!(\"Option<Box<i32>>: {}\", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!(\"Option<u8>: {}\", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, E'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, E'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, E'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!(\"Box<i32>: {}\", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!(\"Option<Box<i32>>: {}\", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!(\"Option<u8>: {}\", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!(\"Box<i32>: {}\", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!(\"Option<Box<i32>>: {}\", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!(\"Option<u8>: {}\", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', NULL, 'use std::mem;\n\nenum MyOption<T> {\n    Some(T),\n    None,\n}\n\nfn main() {\n    // Standard pointer\n    println!(\"Box<i32>: {}\", mem::size_of::<Box<i32>>());\n    \n    // Optimized Option (NPO)\n    println!(\"Option<Box<i32>>: {}\", mem::size_of::<Option<Box<i32>>>());\n    \n    // Unoptimized (u8 can be 0, so no NPO possible)\n    println!(\"Option<u8>: {}\", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag\n}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('0535de0f-15ca-5381-a10e-22174763b3d6', 'c14eb783-1d07-5127-a7b4-f8ee602b41c5', '{"EN": "Lab: Types Layout", "ES": "Lab: Layout de Tipos"}', '{"EN": "Check memory layout knowledge.", "ES": "Revisa conocimiento de layout de memoria."}', true, NULL, '[{"id": "q4-1", "question": {"EN": "Does `Option<&i32>` use more memory than `&i32`?", "ES": "\u00bfUsa `Option<&i32>` m\u00e1s memoria que `&i32`?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "No, thanks to Null Pointer Optimization, `None` is represented as the null address.", "ES": "No, gracias a la Optimizaci\u00f3n de Puntero Nulo, `None` se representa como direcci\u00f3n nula."}}, {"id": "q4-2", "question": {"EN": "Why does Rust reorder struct fields?", "ES": "\u00bfPor qu\u00e9 Rust reordena campos de structs?"}, "options": {"EN": ["Alphabetical sorting", "To reduce padding/size", "Randomly"], "ES": ["Orden alfab\u00e9tico", "Para reducir padding/tama\u00f1o", "Aleatoriamente"]}, "correctIndex": 1, "explanation": {"EN": "It packs smaller types together to satisfy alignment rules efficiently.", "ES": "Empaqueta tipos peque\u00f1os juntos para satisfacer reglas de alineaci\u00f3n eficientemente."}}]', NULL, '[{"id": "q4-1", "question": {"EN": "Does `Option<&i32>` use more memory than `&i32`?", "ES": "\u00bfUsa `Option<&i32>` m\u00e1s memoria que `&i32`?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "No, thanks to Null Pointer Optimization, `None` is represented as the null address.", "ES": "No, gracias a la Optimizaci\u00f3n de Puntero Nulo, `None` se representa como direcci\u00f3n nula."}}, {"id": "q4-2", "question": {"EN": "Why does Rust reorder struct fields?", "ES": "\u00bfPor qu\u00e9 Rust reordena campos de structs?"}, "options": {"EN": ["Alphabetical sorting", "To reduce padding/size", "Randomly"], "ES": ["Or