INSERT INTO modules (id, course_id, title, "order") VALUES ('d86ddafa-2264-5d4c-8d0b-bfbb9f340f93', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "6. Testing & Debugging", "ES": "6. Pruebas y Depuraci\u00f3n"}', 6);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('f47ce236-41c4-55ae-8c9e-c094adc102d9', 'd86ddafa-2264-5d4c-8d0b-bfbb9f340f93', '{"EN": "Unit & Doc Tests Architecture", "ES": "Arquitectura de Pruebas Unitarias y Doc"}', '{"EN": "# Unit Tests Structure\nRust supports test-driven development natively.\n*   **Location**: Typically in a `mod tests` inside the same file as the code.\n*   **Visibility**: Using `use super::*;`, tests can access **private** functions of the parent module. This allows white-box testing.\n*   **Compilation**: `#[cfg(test)]` ensures the test module (and its imports/helpers) is completely stripped from the final binary in normal builds. It only exists when running `cargo test`.\n\n## Documentation Tests\nCode blocks in `///` comments are compiled as separate executables.\n*   Ensures docs are never outdated.\n*   Strict: If the example doesn''t compile or panics, the test suite fails.\n*   Hidden lines: Lines starting with `#` in doc blocks are hidden from HTML output but run in the test (useful for setup code).", "ES": "# Estructura de Pruebas Unitarias\nRust soporta TDD nativamente.\n*   **Ubicaci\u00f3n**: T\u00edpicamente en `mod tests` en el mismo archivo.\n*   **Visibilidad**: Usando `use super::*;`, los tests acceden a funciones **privadas**. Permite pruebas de caja blanca.\n*   **Compilaci\u00f3n**: `#[cfg(test)]` asegura que el m\u00f3dulo de tests se elimina completamente del binario final. Solo existe al correr `cargo test`.\n\n## Pruebas de Documentaci\u00f3n\nBloques de c\u00f3digo en comentarios `///` se compilan como ejecutables separados.\n*   Asegura que la documentaci\u00f3n no caduque.\n*   Estricto: Si el ejemplo no compila, falla.\n*   L\u00edneas ocultas: L\u00edneas que inician con `#` se ocultan en HTML pero corren en el test (\u00fatil para setup)."}', false, NULL, NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, '// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, E'// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', NULL, E'// Private function\nfn internal_add(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n/// Adds two number