wo numbers.\n/// # Examples\n/// ```\n/// // This setup line is hidden in docs\n/// # let x = 5;\n/// assert_eq!(my_crate::add(x, 5), 10);\n/// ```\npub fn add(a: i32, b: i32) -> i32 {\n    internal_add(a, b)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_internal() {\n        // Can access private ''internal_add''\n        assert_eq!(internal_add(2, 2), 4);\n    }\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('92c90461-0ec6-5a7c-9e13-a261bcfe0ae4', 'd86ddafa-2264-5d4c-8d0b-bfbb9f340f93', '{"EN": "Integration Tests & Tools", "ES": "Pruebas de Integraci\u00f3n y Herramientas"}', '{"EN": "# Integration Tests\nLocated in a `tests/` folder at the project root.\n*   **Separate Crates**: Each file in `tests/*.rs` is compiled as a distinct crate that links to your library.\n*   **Black-box**: They can **only** call public API functions (`pub`). They cannot see private items.\n*   **Shared Code**: To share helpers between integration tests, create a `tests/common/mod.rs` module, not just `tests/common.rs` (to avoid it being treated as a test file itself).\n\n## Debugging Tools\n*   `dbg!(x)`: Macro that prints file/line and value to stderr. Returns the value (pass-through).\n*   `RUST_BACKTRACE=1`: Env var to print stack trace on panic.\n*   **Miri**: An interpreter for Rust''s MIR (Mid-level IR). It can detect Undefined Behavior (UB), memory leaks, and alignment issues that standard tests might miss. Run via `cargo miri test`.", "ES": "# Pruebas de Integraci\u00f3n\nUbicadas en la carpeta `tests/`.\n*   **Crates Separados**: Cada archivo en `tests/*.rs` se compila como un crate distinto que se enlaza a tu librer\u00eda.\n*   **Caja Negra**: Solo pueden llamar a la API p\u00fablica (`pub`).\n*   **C\u00f3digo Compartido**: Para compartir helpers, crea `tests/common/mod.rs`.\n\n## Herramientas de Depuraci\u00f3n\n*   `dbg!(x)`: Imprime archivo/l\u00ednea y valor a stderr. Retorna el valor.\n*   `RUST_BACKTRACE=1`: Variable de entorno para ver stack trace.\n*   **Miri**: Int\u00e9rprete para MIR. Detecta Comportamiento Indefinido (UB), fugas de memoria y problemas de alineaci\u00f3n que tests normales no ven. Corre v\u00eda `cargo miri test`."}', false, NULL, NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!(\"Y: {}\", y);\n}', NULL, E'// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, E'// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, E'// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // Only public functions available\n    // assert_eq!(my_crate::add(2, 2), 4);\n}\n\nfn main() {\n    let x = vec![1, 2, 3];\n    // dbg! prints to stderr but returns the value\n    let y = dbg!(x.len()) + 1; \n    println!("Y: {}", y);\n}', NULL, '// tests/integration_test.rs\n// use my_crate;\n\n#[test]\nfn test_public_api() {\n    // On