INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('d780cbf0-e772-51b5-ba7d-327a6f480ef1', 'd86ddafa-2264-5d4c-8d0b-bfbb9f340f93', '{"EN": "Lab: QA Strategy", "ES": "Lab: Estrategia QA"}', '{"EN": "Verify testing strategy.", "ES": "Verifica estrategia de pruebas."}', true, NULL, '[{"id": "q6-1", "question": {"EN": "Can integration tests access private functions?", "ES": "\u00bfPueden los tests de integraci\u00f3n acceder a funciones privadas?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "Integration tests compile as separate crates, treating your library as an external dependency (Black-box).", "ES": "Los tests de integraci\u00f3n compilan como crates separados, tratando tu librer\u00eda como dependencia externa (Caja negra)."}}]', NULL, '[{"id": "q6-1", "question": {"EN": "Can integration tests access private functions?", "ES": "\u00bfPueden los tests de integraci\u00f3n acceder a funciones privadas?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "Integration tests compile as separate crates, treating your library as an external dependency (Black-box).", "ES": "Los tests de integraci\u00f3n compilan como crates separados, tratando tu librer\u00eda como dependencia externa (Caja negra)."}}]', NULL, '[{"id": "q6-1", "question": {"EN": "Can integration tests access private functions?", "ES": "\u00bfPueden los tests de integraci\u00f3n acceder a funciones privadas?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "Integration tests compile as separate crates, treating your library as an external dependency (Black-box).", "ES": "Los tests de integraci\u00f3n compilan como crates separados, tratando tu librer\u00eda como dependencia externa (Caja negra)."}}]', NULL, '[{"id": "q6-1", "question": {"EN": "Can integration tests access private functions?", "ES": "\u00bfPue