INSERT INTO modules (id, course_id, title, "order") VALUES ('7c2b1c33-1f99-5427-ac04-e356e122fa10', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "7. OOP & Generics", "ES": "7. OOP y Gen\u00e9ricos"}', 7);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('1cd02565-9b25-5eb9-a759-d5493779d51e', '7c2b1c33-1f99-5427-ac04-e356e122fa10', '{"EN": "Structs, Enums & Traits", "ES": "Structs, Enums y Traits"}', '{"EN": "# OOP in Rust\nRust uses **Structs** for data and **Impl** blocks for methods.\nIt favors **Composition over Inheritance**. There is no class inheritance in Rust.\n\n## Traits (Encapsulation)\nTraits are like Interfaces. They define shared behavior.\n*   **Encapsulation**: You can use `pub` to control visibility.\n*   **Dynamic Dispatch**: Using `Box<dyn Trait>` allows polymorphism at runtime (vtable).", "ES": "# OOP en Rust\nRust usa **Structs** para datos y bloques **Impl** para m\u00e9todos.\nFavorece **Composici\u00f3n sobre Herencia**. No hay herencia de clases en Rust.\n\n## Traits (Encapsulamiento)\nLos Traits son como Interfaces. Definen comportamiento compartido.\n*   **Encapsulamiento**: Puedes usar `pub` para controlar visibilidad.\n*   **Despacho Din\u00e1mico**: Usar `Box<dyn Trait>` permite polimorfismo en runtime (vtable)."}', false, NULL, NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!(\"Drawing button\"); }\n}', NULL, E'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, E'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, E'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!(\"Drawing button\"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!(\"Drawing button\"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!("Drawing button"); }\n}', NULL, 'trait Draw {\n    fn draw(&self);\n}\n\nstruct Button { width: u32 }\nimpl Draw for Button {\n    fn draw(&self) { println!(\"Drawing button\"); }\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('e0d97ee0-4791-5743-af69-09912e42baac', '7c2b1c33-1f99-5427-ac04-e356e122fa10', '{"EN": "Generics & Static Dispatch", "ES": "Gen\u00e9ricos y Despacho Est\u00e1tico"}', '{"EN": "# Generics\nSolve the problem of code duplication. Write code once, use for many types.\n\n## Static Dispatch (Monomorphization)\nWhen you use Generics (e.g., `fn foo<T: Trait>(item: T)`), Rust generates a unique version of the function for *each concrete type* used at compile time. This means generic code is **just as fast** as code written for specific types. There is no runtime overhead.", "ES": "# Gen\u00e9ricos\nResuelven el problema de duplicaci\u00f3n de c\u00f3digo. Escribe una vez, usa para muchos tipos.\n\n## Despacho Est\u00e1tico (Monomorfizaci\u00f3n)\nCuando usas Gen\u00e9ricos (ej., `fn foo<T: Trait>(item: T)`), Rust genera una versi\u00f3n \u00fanica de la funci\u00f3n para *cada tipo concreto* usado al compilar. Esto significa que el c\u00f3digo gen\u00e9rico es **igual de r\u00e1pido** que el c\u00f3digo espec\u00edfico. Sin sobrecarga en runtime."}', false, NULL, NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!(\"{}\", item);\n}', NULL, E'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, E'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, E'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!(\"{}\", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!(\"{}\", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!("{}", item);\n}', NULL, 'fn print<T: std::fmt::Display>(item: T) {\n    println!(\"{}\", item);\n}', 2);
