INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('35f14d96-8039-5b77-9841-dd4df7f1b116', '047f33d0-785d-5b05-a48a-3d9ae79509d6', '{"EN": "Closures", "ES": "Closures"}', '{"EN": "# Introduction to Closures\nAnonymous functions saved in variables. Syntax: `|param| body`.\nThey can capture their environment (variables from the scope they are defined in).\n\n## Capture Types\n1.  **Fn**: Borrows immutably.\n2.  **FnMut**: Borrows mutably.\n3.  **FnOnce**: Takes ownership (moves).", "ES": "# Introducci\u00f3n a Closures\nFunciones an\u00f3nimas guardadas en variables. Sintaxis: `|param| cuerpo`.\nPueden capturar su entorno (variables del \u00e1mbito donde se definen).\n\n## Tipos de Captura\n1.  **Fn**: Presta inmutablemente.\n2.  **FnMut**: Presta mutablemente.\n3.  **FnOnce**: Toma propiedad (mueve)."}', false, NULL, NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!(\"{}\", add_x(5));\n}', NULL, E'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, E'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, E'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!(\"{}\", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!(\"{}\", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!("{}", add_x(5));\n}', NULL, 'fn main() {\n    let x = 10;\n    let add_x = |y| y + x;\n    println!(\"{}\", add_x(5));\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('b7e8437c-ec33-5ba9-b61a-0f8a4492130b', '047f33d0-785d-5b05-a48a-3d9ae79509d6', '{"EN": "Iterators", "ES": "Iteradores"}', '{"EN": "# Iterators\nLazy sequences. \n*   **Consumers**: `sum`, `collect`, `find`. These drive the iterator.\n*   **Adapters**: `map`, `filter`, `zip`. These transform the iterator into a new one.\n\nRust iterators compile to highly optimized assembly, often faster than manual loops due to bounds check elision.", "ES": "# Iteradores\nSecuencias perezosas.\n*   **Consumidores**: `sum`, `collect`, `find`. Estos conducen el iterador.\n*   **Adaptadores**: `map`, `filter`, `zip`. Transforman el iterador en uno nuevo.\n\nLos iteradores de Rust compilan a ensamblador altamente optimizado, a menudo m\u00e1s r\u00e1pido que bucles manuales debido a la elisi\u00f3n de chequeos de l\u00edmites."}', false, NULL, NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, E'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, E'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1).collect();\n}', NULL, 'fn main() {\n    let v = vec![1, 2, 3];\n    let v2: Vec<_> = v.iter().map(|x| x + 1