INSERT INTO modules (id, course_id, title, "order") VALUES ('ed822be1-6d89-5b5a-9661-9c35028a0350', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "9. Lifetimes", "ES": "9. Lifetimes"}', 9);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('f698ac60-4f5d-53be-8f51-bef1c5b8c06a', 'ed822be1-6d89-5b5a-9661-9c35028a0350', '{"EN": "Lifetimes Basics", "ES": "B\u00e1sicos de Lifetimes"}', '{"EN": "# Lifetimes (''a)\nLifetimes ensure that references are valid as long as we use them. They prevent **Dangling References**.\n\nUsually, Rust infers lifetimes (Elision Rules). But when functions return references that depend on input references, we must annotate them explicitly to tell the compiler how the output lifetime relates to the inputs.", "ES": "# Lifetimes (''a)\nLos lifetimes aseguran que las referencias sean v\u00e1lidas mientras las usemos. Previenen **Referencias Colgantes**.\n\nUsualmente, Rust infiere lifetimes (Reglas de Elisi\u00f3n). Pero cuando las funciones retornan referencias que dependen de referencias de entrada, debemos anotarlas expl\u00edcitamente para decirle al compilador c\u00f3mo se relaciona el lifetime de salida con las entradas."}', false, NULL, NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, E'// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, E'// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, E'// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', NULL, '// x and y must live at least as long as ''a\n// return value lives as long as ''a\nfn longest<''a>(x: &''a str, y: &''a str) -> &''a str {\n    if x.len() > y.len() { x } else { y }\n}', 1);
