INSERT INTO modules (id, course_id, title, "order") VALUES ('d1c0d64c-151a-535f-88d4-a31b699ad529', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "10. Crates & Structure", "ES": "10. Crates y Estructura"}', 10);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('728fe4af-d07c-50d5-bf01-f3d025d9a181', 'd1c0d64c-151a-535f-88d4-a31b699ad529', '{"EN": "Organization & Workspaces", "ES": "Organizaci\u00f3n y Workspaces"}', '{"EN": "# Code Organization\n*   **Crates**: A compilation unit (binary or library).\n*   **Modules**: Organize code within a crate (`mod`).\n*   **Paths**: `use crate::module::Item`.\n\n## File Structure\n*   `src/main.rs`: Binary root.\n*   `src/lib.rs`: Library root.\n*   `src/my_mod.rs` OR `src/my_mod/mod.rs`.\n\n## Workspaces\nManage multiple crates in one repo sharing a `Cargo.lock`. Essential for \"Programming in the large\".", "ES": "# Organizaci\u00f3n de C\u00f3digo\n*   **Crates**: Unidad de compilaci\u00f3n (binario o librer\u00eda).\n*   **M\u00f3dulos**: Organizan c\u00f3digo dentro de un crate (`mod`).\n*   **Rutas**: `use crate::modulo::Item`.\n\n## Estructura de Archivos\n*   `src/main.rs`: Ra\u00edz de binario.\n*   `src/lib.rs`: Ra\u00edz de librer\u00eda.\n*   `src/mi_mod.rs` O `src/mi_mod/mod.rs`.\n\n## Workspaces\nGestionan m\u00faltiples crates en un repo compartiendo `Cargo.lock`. Esencial para \"Programaci\u00f3n en grande\"."}', false, NULL, NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = [\"lib_a\", \"bin_b\"]', NULL, E'// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, E'// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, E'// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = [\"lib_a\", \"bin_b\"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = [\"lib_a\", \"bin_b\"]', NULL, '// Cargo.toml [workspace]\n// members = ["lib_a", "bin_b"]', NULL, '// Cargo.toml [workspace]\n// members = [\"lib_a\", \"bin_b\"]', 1);
