INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('db5e1556-5668-506c-aa57-1302bc0dc6dd', '4e61b292-33fc-52d6-b908-cb9b97534896', '{"EN": "OS Functions", "ES": "Funciones del SO"}', '{"EN": "# OS Interaction\n*   **ENV Vars**: `std::env::var`.\n*   **File I/O**: `std::fs::File`. Reading/Writing.\n*   **Processes**: `std::process::Command`. Spawning child processes.\n*   **Cargo.toml additions**: Adding crates like `inotify` for file watching.", "ES": "# Interacci\u00f3n con SO\n*   **Variables ENV**: `std::env::var`.\n*   **I/O de Archivos**: `std::fs::File`. Lectura/Escritura.\n*   **Procesos**: `std::process::Command`. Lanzar procesos hijos.\n*   **Adiciones Cargo.toml**: A\u00f1adir crates como `inotify` para vigilancia de archivos."}', false, NULL, NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var(\"PATH\").unwrap();\n    println!(\"System Path: {}\", path);\n}', NULL, E'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, E'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, E'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var(\"PATH\").unwrap();\n    println!(\"System Path: {}\", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var(\"PATH\").unwrap();\n    println!(\"System Path: {}\", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var("PATH").unwrap();\n    println!("System Path: {}", path);\n}', NULL, 'use std::env;\nfn main() {\n    let path = env::var(\"PATH\").unwrap();\n    println!(\"System Path: {}\", path);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('ebde6894-75ee-55d8-b469-15d957007367', '4e61b292-33fc-52d6-b908-cb9b97534896', '{"EN": "Benchmarking", "ES": "Benchmarking"}', '{"EN": "# Benchmarking\nMeasuring code performance.\n1.  **Simple**: `std::time::Instant`.\n2.  **Advanced**: `criterion` crate. Statistical analysis of performance.\n\n# Profiling\nTools like `perf`, `valgrind`, or `flamegraph` can be used with Rust binaries to find bottlenecks.", "ES": "# Benchmarking\nMidiendo rendimiento de c\u00f3digo.\n1.  **Simple**: `std::time::Instant`.\n2.  **Avanzado**: crate `criterion`. An\u00e1lisis estad\u00edstico de rendimiento.\n\n# Profiling\nHerramientas como `perf`, `valgrind`, o `flamegraph` pueden usarse con binarios Rust para hallar cuellos de botella."}', false, NULL, NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!(\"Time: {:?}\", duration);\n}', NULL, E'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, E'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, E'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!(\"Time: {:?}\", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!(\"Time: {:?}\", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!("Time: {:?}", duration);\n}', NULL, 'use std::time::Instant;\nfn main() {\n    let start = Instant::now();\n    // Do work\n    let duration = start.elapsed();\n    println!(\"Time: {:?}\", duration);\n}', 2);
