INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a41d8d5f-cc0b-59c5-844a-ebcb1cd1c33d', 'ff7197cb-d29d-5a53-856d-6499b6e8c00b', '{"EN": "Box & Rc", "ES": "Box y Rc"}', '{"EN": "# Box<T>\nAllocates data on the Heap. Owns the data. Useful for recursive types (linked lists) where size must be known.\n\n# Rc<T>\nReference Counting. Allows **multiple owners** of the same data. Only for single-threaded use. Data is dropped when count reaches 0.", "ES": "# Box<T>\nAsigna datos en el Heap. Posee el dato. \u00datil para tipos recursivos (listas enlazadas) donde el tama\u00f1o debe ser conocido.\n\n# Rc<T>\nConteo de Referencias. Permite **m\u00faltiples propietarios** del mismo dato. Solo para uso en un solo hilo. El dato se elimina cuando la cuenta llega a 0."}', false, NULL, NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!(\"References: {}\", Rc::strong_count(&a));\n}', NULL, E'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, E'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, E'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!(\"References: {}\", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!(\"References: {}\", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!("References: {}", Rc::strong_count(&a));\n}', NULL, 'use std::rc::Rc;\nfn main() {\n    let a = Rc::new(5);\n    let b = Rc::clone(&a);\n    println!(\"References: {}\", Rc::strong_count(&a));\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a1889332-81af-5cff-897a-3c8066d196b4', 'ff7197cb-d29d-5a53-856d-6499b6e8c00b', '{"EN": "RefCell & Mutex", "ES": "RefCell y Mutex"}', '{"EN": "# Interior Mutability\nAllows mutating data even when there are immutable references to it. Checked at runtime.\n\n*   **RefCell<T>**: Single thread. Panics at runtime if borrowing rules are violated.\n*   **Mutex<T>**: Thread safe. Locks data.\n*   **RwLock<T>**: Read/Write lock. Multiple readers or one writer.", "ES": "# Mutabilidad Interior\nPermite mutar datos incluso cuando hay referencias inmutables a ellos. Chequeado en runtime.\n\n*   **RefCell<T>**: Un solo hilo. Entra en p\u00e1nico en runtime si se violan reglas de pr\u00e9stamo.\n*   **Mutex<T>**: Seguro entre hilos. Bloquea datos.\n*   **RwLock<T>**: Bloqueo Lectura/Escritura. M\u00faltiples lectores o un escritor."}', false, NULL, NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!(\"{:?}\", x);\n}', NULL, E'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, E'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, E'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!(\"{:?}\", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!(\"{:?}\", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!("{:?}", x);\n}', NULL, 'use std::cell::RefCell;\nfn main() {\n    let x = RefCell::new(5);\n    *x.borrow_mut() += 1;\n    println!(\"{:?}\", x);\n}', 2);
