INSERT INTO modules (id, course_id, title, "order") VALUES ('23802be8-72f5-5b51-8350-6b6103b1fce5', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "13. Concurrency", "ES": "13. Concurrencia"}', 13);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('00b319b1-d59e-5bab-8e59-d090f02b965c', '23802be8-72f5-5b51-8350-6b6103b1fce5', '{"EN": "Threads & Channels", "ES": "Hilos y Canales"}', '{"EN": "# Threads\nRust uses 1:1 OS threads. `thread::spawn`. Use `move` closures to transfer ownership to the thread.\n\n# Message Passing\n\"Do not communicate by sharing memory; share memory by communicating.\"\n**Channels** (`mpsc`): Multiple Producer, Single Consumer.\n*   `tx.send(val)`\n*   `rx.recv()`", "ES": "# Hilos\nRust usa hilos del SO 1:1. `thread::spawn`. Usa closures `move` para transferir propiedad al hilo.\n\n# Paso de Mensajes\n\"No comuniques compartiendo memoria; comparte memoria comunicando.\"\n**Canales** (`mpsc`): M\u00faltiples Productores, Un Consumidor.\n*   `tx.send(val)`\n*   `rx.recv()`"}', false, NULL, NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send(\"Hello form thread\").unwrap();\n    });\n    println!(\"{}\", rx.recv().unwrap());\n}', NULL, E'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, E'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, E'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send(\"Hello form thread\").unwrap();\n    });\n    println!(\"{}\", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send(\"Hello form thread\").unwrap();\n    });\n    println!(\"{}\", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send("Hello form thread").unwrap();\n    });\n    println!("{}", rx.recv().unwrap());\n}', NULL, 'use std::thread;\nuse std::sync::mpsc;\n\nfn main() {\n    let (tx, rx) = mpsc::channel();\n    thread::spawn(move || {\n        tx.send(\"Hello form thread\").unwrap();\n    });\n    println!(\"{}\", rx.recv().unwrap());\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('79e046f7-86fa-5137-a6a6-38a7596ed2d6', '23802be8-72f5-5b51-8350-6b6103b1fce5', '{"EN": "Shared State", "ES": "Estado Compartido"}', '{"EN": "# Shared State\nTo share memory:\n*   **Mutex<T>**: Protects data.\n*   **Arc<T>**: Allows multiple threads to own the Mutex.\n\n# Atomics\n`std::sync::atomic`. Low level primitives like `AtomicUsize` for counters without Mutex overhead.\n\n# Async\nRust supports Asynchronous Programming (`async/await`) via external runtimes like **Tokio**. It uses a \"poll\" model.", "ES": "# Estado Compartido\nPara compartir memoria:\n*   **Mutex<T>**: Protege datos.\n*   **Arc<T>**: Permite a m\u00faltiples hilos poseer el Mutex.\n\n# Atomics\n`std::sync::atomic`. Primitivas de bajo nivel como `AtomicUsize` para contadores sin la sobrecarga de Mutex.\n\n# Async\nRust soporta Programaci\u00f3n As\u00edncrona (`async/await`) v\u00eda runtimes externos como **Tokio**. Usa un modelo \"poll\"."}', false, NULL, NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, E'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, E'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, 'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock().unwrap();\n        *num += 1;\n    }).join().unwrap();\n}', NULL, E'use std::sync::{Arc, Mutex};\nuse std::thread;\n\nfn main() {\n    let counter = Arc::new(Mutex::new(0));\n    let c = Arc::clone(&counter);\n    \n    thread::spawn(move || {\n        let mut num = c.lock