INSERT INTO modules (id, course_id, title, "order") VALUES ('713c0631-7cf8-5414-9778-28de1e810de4', '09e98e70-34ad-5a7c-90c9-47a3b1d55fcb', '{"EN": "14. Deployment", "ES": "14. Despliegue"}', 14);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('59589e87-d06c-5db7-aedd-dfc0973f31dd', '713c0631-7cf8-5414-9778-28de1e810de4', '{"EN": "Containers & Cross-Compiling", "ES": "Contenedores y Compilaci\u00f3n Cruzada"}', '{"EN": "# Containers\nRust is ideal for containers (Docker/Podman).\n*   **Multi-stage builds**: Compile in a heavy image, copy binary to a tiny `scratch` or `alpine` image.\n*   Result: Extremely small images (< 20MB).\n\n# Cross-Compiling\nRust makes it easy to compile for other architectures.\n*   `rustup target add ...`\n*   Tools like **cross** simplify compiling for Linux from Mac/Windows using Docker.", "ES": "# Contenedores\nRust es ideal para contenedores (Docker/Podman).\n*   **Builds multi-etapa**: Compila en una imagen pesada, copia el binario a una imagen diminuta `scratch` o `alpine`.\n*   Resultado: Im\u00e1genes extremadamente peque\u00f1as (< 20MB).\n\n# Compilaci\u00f3n Cruzada\nRust facilita compilar para otras arquitecturas.\n*   `rustup target add ...`\n*   Herramientas como **cross** simplifican compilar para Linux desde Mac/Windows usando Docker."}', false, NULL, NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD [\"app\"]', NULL, E'# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, E'# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, E'# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD [\"app\"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD [\"app\"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD ["app"]', NULL, '# Dockerfile Example\nFROM rust:1.75 as builder\nWORKDIR /app\nCOPY . .\nRUN cargo build --release\n\nFROM debian:buster-slim\nCOPY --from=builder /app/target/release/app /usr/local/bin/app\nCMD [\"app\"]', 1);
