INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('24911c6b-fe33-5aba-8eea-d99f7a95105d', '04194b16-fcc2-5ab9-b053-d1882b4d2e46', '{"EN": "Unsafe Rust & FFI", "ES": "Rust Unsafe y FFI"}', '{"EN": "# Unsafe Rust\nA hidden language inside Rust. Allows:\n1.  Dereference raw pointers.\n2.  Call unsafe functions (FFI).\n3.  Access mutable statics.\n4.  Implement unsafe traits.\n\nIt removes the safety net. You promise the compiler \"I know what I am doing\".\n\n# FFI (Foreign Function Interface)\nCalling C code from Rust or Rust from C.\n*   `extern \"C\"` blocks.\n*   `#[no_mangle]` to export Rust functions to C.", "ES": "# Rust Unsafe\nUn lenguaje oculto dentro de Rust. Permite:\n1.  Desreferenciar punteros crudos.\n2.  Llamar funciones inseguras (FFI).\n3.  Acceder a est\u00e1ticos mutables.\n4.  Implementar traits inseguros.\n\nQuita la red de seguridad. Le prometes al compilador \"S\u00e9 lo que estoy haciendo\".\n\n# FFI (Interfaz de Funci\u00f3n Extranjera)\nLlamar c\u00f3digo C desde Rust o Rust desde C.\n*   Bloques `extern \"C\"`.\n*   `#[no_mangle]` para exportar funciones Rust a C."}', false, NULL, NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!(\"r1 is: {}\", *r1); // Unsafe dereference\n    }\n}', NULL, E'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, E'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, E'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!(\"r1 is: {}\", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!(\"r1 is: {}\", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!("r1 is: {}", *r1); // Unsafe dereference\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    let r1 = &num as *const i32; // Raw pointer\n    \n    unsafe {\n        println!(\"r1 is: {}\", *r1); // Unsafe dereference\n    }\n}', 1);
