INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('d9c396c3-731b-560c-a8be-6961282bd5c5', 'fde33563-5500-5bdf-9873-d4b187725f96', '{"EN": "Send & Sync Deep Dive", "ES": "Profundizaci\u00f3n en Send y Sync"}', '{"EN": "# The Marker Traits\nRust''s fearless concurrency is built on two auto-traits (traits implemented automatically by the compiler).\n\n## Send: \"Safe to Move\"\nA type is `Send` if it is safe to send it (move ownership) to another thread.\n*   **Almost everything is Send**: Primitives (`u8`, `f64`), Structs containing Send types, `Arc`, `Mutex`.\n*   **What is NOT Send?**:\n    *   `Rc<T>`: Reference counting is non-atomic. Moving it to another thread could lead to race conditions on the reference count.\n    *   Raw Pointers (`*const T`, `*mut T`) unless explicitly implemented.\n    *   `MutexGuard`: On some OS (like pthread), a mutex must be unlocked by the *same thread* that locked it. Sending the guard to another thread to drop/unlock it causes Undefined Behavior.\n\n## Sync: \"Safe to Share\"\nA type `T` is `Sync` if it is safe to access it via a shared reference (`&T`) from multiple threads.\n**Mathematical Definition**: `T` is `Sync` if and only if `&T` is `Send`.\n\n*   **What is NOT Sync?**:\n    *   `RefCell<T>`, `Cell<T>`: They use non-atomic interior mutability. Accessing them from multiple threads causes data races.\n    *   `Rc<T>`.\n*   **The Magic**: `Mutex<T>` is `Sync` even if `T` is not (e.g., `Mutex<Cell<i32>>`), because the Mutex enforces exclusive access, making the unsafe inner type safe to use.\n\n## Implementing them manually\nThese are `unsafe` traits. Implementing them manually tells the compiler \"I have verified this is thread-safe\".", "ES": "# Los Traits Marcadores\nLa concurrencia de Rust se basa en dos auto-traits.\n\n## Send: \"Seguro de Mover\"\nUn tipo es `Send` si es seguro enviarlo (mover ownership) a otro hilo.\n*   **Casi todo es Send**: Primitivos, Structs normales, `Arc`, `Mutex`.\n*   **\u00bfQu\u00e9 NO es Send?**:\n    *   `Rc<T>`: El conteo no es at\u00f3mico. Moverlo causar\u00eda carreras de datos.\n    *   Punteros Crudos.\n    *   `MutexGuard`: En algunos SO, un mutex debe ser desbloqueado por el *mismo hilo* que lo bloque\u00f3.\n\n## Sync: \"Seguro de Compartir\"\nUn tipo `T` es `Sync` si es seguro accederlo v\u00eda referencia compartida (`&T`) desde m\u00faltiples hilos.\n**Definici\u00f3n**: `T` es `Sync` si y solo si `&T` es `Send`.\n\n*   **\u00bfQu\u00e9 NO es Sync?**:\n    *   `RefCell<T>`, `Cell<T>`: Usan mutabilidad interior no at\u00f3mica.\n    *   `Rc<T>`.\n*   **La Magia**: `Mutex<T>` es `Sync` incluso si `T` no lo es, porque el Mutex fuerza acceso exclusivo."}', false, NULL, NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!(\"{}\", pointer);\n    });\n    */\n    \n    println!(\"Uncommenting the thread block will cause a compile error because Rc is !Send\");\n}', NULL, E'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, E'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, E'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!(\"{}\", pointer);\n    });\n    */\n    \n    println!(\"Uncommenting the thread block will cause a compile error because Rc is !Send\");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!(\"{}\", pointer);\n    });\n    */\n    \n    println!(\"Uncommenting the thread block will cause a compile error because Rc is !Send\");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!("{}", pointer);\n    });\n    */\n    \n    println!("Uncommenting the thread block will cause a compile error because Rc is !Send");\n}', NULL, 'use std::rc::Rc;\nuse std::thread;\n\nfn main() {\n    let pointer = Rc::new(5);\n    \n    // ERROR: Rc<i32> cannot be sent between threads safely\n    /*\n    thread::spawn(move || {\n        println!(\"{}\", pointer);\n    });\n    */\n    \n    println!(\"Uncommenting the thread block will cause a compile error because Rc is !Send\");\n}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('1d94b5b4-9040-5305-a3f3-1191709dc691', 'fde33563-5500-5bdf-9873-d4b187725f96', '{"EN": "Mutex & RwLock Architecture", "ES": "Arquitectura de Mutex y RwLock"}', '{"EN": "# Mutex (Mutual Exclusion)\nA Mutex ensures that only one thread accesses the data at a time. In Rust, `Mutex<T>` **owns** the data. You cannot access `T` without locking.\n\n## Internals: Poisoning & Guards\n1.  **Locking**: `mutex.lock()` blocks the thread until the lock is acquired. It works via OS primitives (like `futex` on Linux), putting the thread to sleep to save CPU.\n2.  **The Guard**: `lock()` returns a `MutexGuard`. This is a smart pointer implementing `Deref`. When the guard goes out of scope (drop), it automatically unlocks the Mutex.\n3.  **Poisoning**: If a thread panics while holding the lock, the generic state might be inconsistent. Rust \"poisons\" the lock. Subsequent `lock()` calls return `Err(PoisonError)`. You can `unwrap()` to ignore this and propagate the panic, or handle the error to try and recover the data.\n\n# RwLock (Read-Write Lock)\nOptimization for workloads with **many readers and few writers**.\n*   **Read Mode**: Multiple threads can hold read locks simultaneously.\n*   **Write Mode**: Exclusive access. No other readers or writers allowed.\n*   **Starvation**: Be careful. A constant stream of readers can starve a writer, preventing it from ever acquiring the lock (implementation dependent).\n\n## Deadlocks\nCalling `lock()` twice on the same Mutex from the same thread will cause a Deadlock (the thread waits for itself forever). Rust does not prevent this at compile time.", "ES": "# Mutex (Exclusi\u00f3n Mutua)\nAsegura que solo un hilo acceda al dato. En Rust, `Mutex<T>` **posee** el dato.\n\n## Internos\n1.  **Bloqueo**: `mutex.lock()` bloquea el hilo usando primitivas del SO (como `futex`), durmi\u00e9ndolo para ahorrar CPU.\n2.  **El Guard**: Retorna un `MutexGuard`. Es un puntero inteligente (RAII). Cuando sale de \u00e1mbito (drop), desbloquea autom\u00e1ticamente.\n3.  **Envenenamiento (Poisoning)**: Si un hilo entra en p\u00e1nico teniendo el lock, este se \"envenena\". Futuros `lock()` retornan Error. Esto protege contra datos inconsistentes.\n\n# RwLock\nOptimizaci\u00f3n para **muchos lectores, pocos escritores**.\n*   **Modo Lectura**: M\u00faltiples hilos a la vez.\n*   **Modo Escritura**: Acceso exclusivo.\n*   **Inanici\u00f3n (Starvation)**: Un flujo constante de lectores puede impedir que un escritor consiga el lock.\n\n## Deadlocks\nLlamar `lock()` dos veces en el mismo Mutex desde el mismo hilo causa un Deadlock (el hilo se espera a s\u00ed mismo por siempre)."}', false, NULL, NULL, 'use std::sync::{RwLock, Arc};\nuse std::thread;\n\nfn main() {\n    let lock = Arc::new(RwLock::new(5));\n    let c_lock = Arc::clone(&lock);\n\n    {\n        // Multiple readers allowed\n        let r1 = lock.read().unwrap();\n        let r2 = lock.read().unwrap();\n        println!("Readers: {}, {}", *r1, *r2);\n        // r1 and r2 drop here, releasing read locks\n    }\n\n    let handle = thread::spawn(move || {\n        // Write lock requires exclusivity\n        let mut w = c_lock.write().unwrap();\n        *w += 1;\n        println!("Writer updated value");\n    });\n    \n    handle.join().unwrap();\n}', NULL, 'use std::sync::{RwLock, Arc};\nuse std::thread;\n\nfn main() {\n    let lock = Arc::new(RwLock::new(5));\n    let c_lock = Arc::clone(&lock);\n\n    {\n        // Multiple readers allowed\n        let r1 = lock.read().unwrap();\n        let r2 = lock.read().unwrap();\n        println!("Readers: {}, {}", *r1, *r2);\n        // r1 and r2 drop here, releasing read locks\n    }\n\n    let handle = thread::spawn(move || {\n        // Write lock requires exclusivity\n        let mut w = c_lock.write().unwrap();\n        *w += 1;\n        println!("Writer updated value");\n    });\n    \n    handle.join().unwrap();\n}', NULL, 'use std::sync::{RwLock, Arc};\nuse std::thread;\n\nfn main() {\n    let lock = Arc::new(RwLock::new(5));\n    let c_lock = Arc::clone(&lock);\n\n    {\n        // Multiple readers allowed\n        let r1 = lock.read().unwrap();\n        let r2 = lock.read().unwrap();\n        println!("Readers: {}, {}", *r1, *r2);\n        // r1 and r2 drop here, releasing read locks\n    }\n\n    let handle = thread::spawn(move || {\n        // Write lock requires exclusivity\n        let mut w = c_lock.write().unwrap();\n        *w += 1;\n        println!("Writer updated value");\n    });\n    \n    handle.join().unwrap();\n}', NULL, 'use std::sync::{RwLock, Arc};\nuse std::thread;\n\nfn main() {\n    let lock = Arc::new(RwLock::new(5));\n    let c_lock = Arc::clone(&lock);\n\n    {\n        // Multiple readers allowed\n        let r1 = lock.read().unwrap();\n        let r2 = lock.read().unwrap();\n        println!("Readers: {}, {}", *r1, *r2);\n        // r1 and r2 drop here, releasing read locks\n    }\n\n    let handle = thread::spawn(move || {\n        // Write lock requires exclusivity\n        let mut w = c_lock.write().unwrap();\n        *w += 1;\n        println!("Writer updated value");\n    });\n    \n    handle.join().unwrap();\n}', NULL, 'use std::sync::{RwLock, Arc};\nuse std::thread;\n\nfn main() {\n    let lock = Arc::new(RwLock::new(5));\n    let c_lock = Arc::clone(&lock);\n\n    {\n        // Multiple readers allowed\n        let r1 = lock.read().unwrap();\n        let r2 = lock.read().unwrap();\n        println!("Readers: {}, {}", *r1, *r2);\n        // r1 and r2 drop here, releasing read locks\n    }\n\n    let handle = thread::spawn(move || {\n        // Write lock requires exclusivity\n        let mut w = c_lock.write().unwrap();\n        *w += 1;\n        println!("Writer updated value");\n    });\n    \n    handle.join().unwrap();\n}', NULL, 'use std::sync::{RwLock, Arc};\nuse std::thread;\n\nfn main() {\n    let lock = Arc::new(RwLock::new(5));\n    let c_l