INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('5e4a68bf-a7d8-5b93-b109-8cf655a11d91', 'fde33563-5500-5bdf-9873-d4b187725f96', '{"EN": "Condvar & Spurious Wakeups", "ES": "Condvar y Despertares Espurios"}', '{"EN": "# Condition Variables\nSometimes a thread needs to wait for a specific business logic condition (e.g., \"is the queue empty?\").\n*   **Spinning**: `while !ready { check(); }` burns 100% CPU. Bad.\n*   **Sleeping**: `sleep(1ms)` introduces latency. Bad.\n*   **Condvar**: Allows a thread to atomically release a Mutex and go to sleep until notified.\n\n## The Pattern\nCondvars are always associated with a Mutex.\n1.  Lock Mutex.\n2.  Check condition. If false, call `cvar.wait(guard)`. This atomically unlocks and sleeps.\n3.  When woken, `wait` re-acquires the lock and returns the guard.\n\n## Spurious Wakeups\nThe OS can wake up a thread even if nobody signaled the condition variable (due to optimizations or signal handling).\n**Rule**: Always check the condition in a `while` loop, never an `if`.\n```rust\n// Correct\nwhile !*started {\n    started = cvar.wait(started).unwrap();\n}\n// Incorrect\nif !*started {\n    started = cvar.wait(started).unwrap();\n}\n```\n\n## Notify\n*   `notify_one()`: Wakes one waiting thread. Efficient but can cause deadlocks if logic depends on all threads waking.\n*   `notify_all()`: Wakes all threads (\"Thundering Herd\"). Safe but can cause contention burst.", "ES": "# Variables de Condici\u00f3n\nA veces un hilo debe esperar una condici\u00f3n l\u00f3gica (ej. \"\u00bfcola vac\u00eda?\").\n*   **Condvar**: Permite liberar un Mutex at\u00f3micamente y dormir hasta ser notificado.\n\n## El Patr\u00f3n\nSiempre asociadas a un Mutex.\n1.  Bloquear Mutex.\n2.  Chequear condici\u00f3n. Si falso, `cvar.wait(guard)`. Esto desbloquea y duerme.\n3.  Al despertar, `wait` readquiere el lock.\n\n## Despertares Espurios (Spurious Wakeups)\nEl SO puede despertar un hilo sin raz\u00f3n aparente.\n**Regla**: Siempre chequea la condici\u00f3n en un bucle `while`, nunca un `if`.\n\n## Notificaci\u00f3n\n*   `notify_one()`: Despierta uno. Eficiente.\n*   `notify_all()`: Despierta todos (\"Estampida\"). Seguro pero causa pico de contenci\u00f3n."}', false, NULL, NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!(\"Waiting...\");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!(\"Worker started!\");\n}', NULL, E'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, E'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, E'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!(\"Waiting...\");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!(\"Worker started!\");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!(\"Waiting...\");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!(\"Worker started!\");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!("Waiting...");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!("Worker started!");\n}', NULL, 'use std::sync::{Arc, Mutex, Condvar};\nuse std::thread;\n\nfn main() {\n    let pair = Arc::new((Mutex::new(false), Condvar::new()));\n    let pair2 = Arc::clone(&pair);\n\n    thread::spawn(move || {\n        let (lock, cvar) = &*pair2;\n        let mut started = lock.lock().unwrap();\n        // Business logic...\n        *started = true;\n        // Notify the waiting thread\n        cvar.notify_one();\n    });\n\n    let (lock, cvar) = &*pair;\n    let mut started = lock.lock().unwrap();\n    \n    // MUST use while loop to handle spurious wakeups\n    while !*started {\n        println!(\"Waiting...\");\n        started = cvar.wait(started).unwrap();\n    }\n    \n    println!(\"Worker started!\");\n}', 5);
INSERT INTO modules (id, course_id, title, "order") VALUES ('226ccd7a-3330-5fe2-aa82-c5023196e50e', '2c20e72b-36b9-581d-a7de-b94661a4f498', '{"EN": "2. Future Trait & Internals", "ES": "2. Trait Future e Internos"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('b74c98b9-9631-5c2c-b4ac-867dd451bce9', '226ccd7a-3330-5fe2-aa82-c5023196e50e', '{"EN": "Async Desugaring: State Machines", "ES": "Desglosando Async: M\u00e1quinas de Estado"}', '{"EN": "# The Magic of Async\nHow does Rust achieve async without the runtime overhead of Go (green threads stack resizing) or Java?\nIt converts your linear `async fn` code into a **State Machine** Enum at compile time.\n\n## The Transformation\nCode:\n```rust\nasync fn example(arg: u8) {\n    let x = big_calculation();\n    read_file().await; // Yield point 1\n    let y = x + 1;\n    send_network(y).await; // Yield point 2\n}\n```\n\nBecomes (Simplified Enum):\n```rust\nenum ExampleFuture {\n    Start { arg: u8 },\n    State1 { x: u64, future: ReadFileFuture }, // Saving ''x'' across await\n    State2 { y: u64, future: SendNetworkFuture },\n    Done,\n}\n```\n\n## Zero-Cost Abstraction\n*   **No Heap Allocation**: The state machine size is known at compile time. It can be embedded into other structs or allocated on the stack.\n*   **One Allocation**: Typically, you allocate the top-level future once (e.g., `tokio::spawn`), and all inner futures live inside that single allocation. This is much faster than chaining Promises in JS where each `.then` creates a new object.", "ES": "# La Magia de Async\n\u00bfC\u00f3mo logra Rust async sin la sobrecarga de Go o Java?\nConvierte tu c\u00f3digo lineal `async fn` en una **M\u00e1quina de Estados (Enum)** en tiempo de compilaci\u00f3n.\n\n## La Transformaci\u00f3n\nCada punto `.await` es una variante del Enum. El compilador guarda solo las variables vivas que cruzan el punto `.await`.\n\n## Abstracci\u00f3n de Costo Cero\n*   **Sin Asignaci\u00f3n de Heap**: El tama\u00f1o se conoce al compilar.\n*   **Una Asignaci\u00f3n**: T\u00edpicamente, asignas el futuro de nivel superior una vez (ej. `tokio::spawn`), y todos los futuros internos viven dentro de esa \u00fanica asignaci\u00f3n. Mucho m\u00e1s r\u00e1pido que las Promesas en JS donde cada `.then` crea un objeto nuevo."}', false, NULL, NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!(\"Start\");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!(\"Resumed with state {}\", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, E'// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, E'// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, E'// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!(\"Start\");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!(\"Resumed with state {}\", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!(\"Start\");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!(\"Resumed with state {}\", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!("Start");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!("Resumed with state {}", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', NULL, '// Concept code - Manual State Machine\nenum MyFuture {\n    Init,\n    WaitingForTimer { state: i32 },\n    Done,\n}\n\nimpl MyFuture {\n    fn poll(&mut self) -> bool {\n        match self {\n            MyFuture::Init => {\n                println!(\"Start\");\n                *self = MyFuture::WaitingForTimer { state: 10 };\n                false // Pending\n            },\n            MyFuture::WaitingForTimer { state } => {\n                println!(\"Resumed with state {}\", state);\n                *self = MyFuture::Done;\n                true // Ready\n            },\n            MyFuture::Done => true,\n        }\n    }\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('baaec474-765b-523f-8b77-b9c0c805ef81', '226ccd7a-3330-5fe2-aa82-c5023196e50e', '{"EN": "The Future Trait in Depth", "ES": "El Trait Future en Profundidad"}', '{"EN": "# The Interface\n```rust\npub trait Future {\n    type Output;\n    fn poll(self: Pin<&mut Self>, cx: &mut Context<''_>) -> Poll<Self::Output>;\n}\n```\n\n## 1. Poll Based\nUnlike Callback-based async (Node.js) where the IO subsystem calls your function when ready, Rust uses a **Poll** model. The executor asks the future: \"Are you ready?\".\n*   **Ready(val)**: Yes, here is the value.\n*   **Pending**: No. (Crucially, implies \"I have arranged to be woken up later\").\n\n## 2. Context\nThe `Context` argument basically wraps the `Waker`. It allows the Future to register itself with the reactor (e.g., the OS Epoll queue).\n\n## 3. Pin<&mut Self>\nWhy not just `&mut Self`? Because of Self-Referential Structs. Async functions often keep pointers to their own stack variables. If the Future moved in memory while executing, those pointers would break. `Pin` prevents moving.", "ES": "# La Interfaz\n```rust\npub trait Future {\n    type Output;\n    fn poll(self: Pin<&mut Self>, cx: &mut Context<''_>) -> Poll<Self::Output>;\n}\n```\n\n## 1. Basado en Poll (Sondeo)\nEl ejecutor pregunta al futuro: \"\u00bfEst\u00e1s listo?\".\n*   **Ready**: S\u00ed.\n*   **Pending**: No. (Implica \"Ya arregl\u00e9 que me despierten luego\").\n\n## 2. Contexto\nEnvuelve al `Waker`. Permite al Futuro registrarse con el reactor (ej. cola Epoll).\n\n## 3. Pin<&mut Self>\n\u00bfPor qu\u00e9 no `&mut Self`? Por Structs Auto-Referenciales. Las funciones async guardan punteros a sus propias variables. Si el Futuro se moviera en memoria, esos punteros se romper\u00edan. `Pin` previene el movimiento."}', false, NULL, NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!(\"Polled!\");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, E'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, E'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, E'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!(\"Polled!\");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!(\"Polled!\");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!("Polled!");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\nstruct SimpleFuture;\n\nimpl Future for SimpleFuture {\n    type Output = ();\n\n    fn poll(self: Pin<&mut Self>, _cx: &mut Context<''_>) -> Poll<Self::Output> {\n        println!(\"Polled!\");\n        Poll::Ready(())\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    SimpleFuture.await;\n}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('3f90aba2-791c-562f-9841-b18b9c28e5d6', '226ccd7a-3330-5fe2-aa82-c5023196e50e', '{"EN": "Wakers & The Reactor", "ES": "Wakers y el Reactor"}', '{"EN": "# The Wakeup Mechanism\nIf `poll` returns `Pending`, the Executor puts the task to sleep. How does it know when to poll again? **The Waker**.\n\n## The Flow\n1.  **Poll**: Executor calls `future.poll(cx)`.\n2.  **Register**: The future creates an I/O request (e.g., read socket). It passes the `cx.waker()` to the Reactor (the part handling Epoll/Kqueue).\n3.  **Sleep**: Future returns `Pending`. Executor puts task in \"Waiting\" state.\n4.  **Event**: Network packet arrives. OS notifies Reactor.\n5.  **Wake**: Reactor finds the associated `Waker` and calls `waker.wake()`.\n6.  **Schedule**: The `wake()` call moves the task back to the \"Ready\" queue. Executor polls it again.\n\n## RawWaker\nUnder the hood, Waker uses a VTable (`RawWakerVTable`) to allow dynamic dispatch and cloning without the overhead of standard trait objects, allowing efficient integration with any runtime (Tokio, async-std).", "ES": "# El Mecanismo de Despertar\nSi `poll` retorna `Pending`, el Ejecutor duerme la tarea. \u00bfC\u00f3mo sabe cu\u00e1ndo volver a sondear? **El Waker**.\n\n## El Flujo\n1.  **Poll**: Ejecutor llama `poll`.\n2.  **Registro**: El futuro crea una petici\u00f3n I/O. Pasa el `cx.waker()` al Reactor.\n3.  **Dormir**: Retorna `Pending`.\n4.  **Evento**: Paquete llega. SO notifica al Reactor.\n5.  **Wake**: Reactor llama `waker.wake()`.\n6.  **Programar**: La tarea vuelve a la cola \"Ready\". El Ejecutor hace poll de nuevo.\n\n## RawWaker\nInternamente, usa una VTable (`RawWakerVTable`) para permitir despacho din\u00e1mico y clonaci\u00f3n eficiente."}', false, NULL, NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, E'// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, E'// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, E'// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', NULL, '// Conceptual usage inside a leaf future (like a Timer)\n/*\nfn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<T> {\n    if self.is_ready() {\n        Poll::Ready(val)\n    } else {\n        // Crucial: Store the waker so the timer thread can call it later\n        self.register_waker(cx.waker().clone());\n        Poll::Pending\n    }\n}\n*/', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('bda8c125-4a1b-5df9-a53e-61c46eedc432', '226ccd7a-3330-5fe2-aa82-c5023196e50e', '{"EN": "Pinning & Unpin", "ES": "Pinning y Unpin"}', '{"EN": "# The Hardest Part of Async Rust: Pinning\n\n## The Problem: Self-Referential Structs\nAsync functions desugar into structs that may hold references to their own fields.\n```rust\nstruct MyFuture {\n    data: [u8; 1024],\n    pointer_to_data: *const u8, // Points to ''data'' field\n}\n```\nIf we move `MyFuture` to a new memory location (e.g., returning it from a function or resizing a vector), `data` moves, but `pointer_to_data` still points to the old address. **This is undefined behavior.**\n\n## The Solution: Pin<P>\n`Pin<P>` is a wrapper around a pointer `P` (like `&mut T` or `Box<T>`). It effectively says: \"The value pointed to by P will strictly **never move** again until it is dropped\".\nOnce you Pin a value, you can never get a `&mut T` to it (unless `T: Unpin`), because `mem::swap` or `mem::replace` requires mutable references and could move the data.\n\n## The Unpin Trait\nMost types (integers, bools, standard structs) don''t have self-references. They implement the `Unpin` auto-trait. For `Unpin` types, `Pin<&mut T>` behaves exactly like `&mut T`.\nGenerated Async Futures are `!Unpin`.\n\n## Stack vs Heap Pinning\n*   **Box::pin(x)**: Easiest. Moves data to Heap (stable address) and pins it.\n*   **pin_utils::pin_mut!(x)**: Pins data to the Stack (Shadows variable). Dangerous if not careful about scope.", "ES": "# La Parte M\u00e1s Dif\u00edcil: Pinning\n\n## El Problema: Structs Auto-Referenciales\nLas funciones async se convierten en structs que pueden tener referencias a sus propios campos.\nSi movemos el struct en memoria, los punteros internos apuntar\u00edan a la direcci\u00f3n antigua (basura).\n\n## La Soluci\u00f3n: Pin<P>\n`Pin<P>` envuelve un puntero. Dice: \"El valor apuntado **nunca se mover\u00e1** hasta ser eliminado\".\nUna vez anclado (pinned), no puedes obtener `&mut T` (salvo que `T: Unpin`), porque permitir\u00eda mover el dato (swap).\n\n## El Trait Unpin\nLa mayor\u00eda de tipos (enteros, structs normales) son `Unpin`. Para ellos, Pin es transparente.\nLos Futuros Async son `!Unpin`.\n\n## Stack vs Heap Pinning\n*   **Box::pin(x)**: F\u00e1cil. Mueve al Heap y ancla.\n*   **pin_mut!(x)**: Ancla en el Stack (sombra la variable)."}', false, NULL, NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: "Hello".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = "New".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: "Hello".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = "New".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: "Hello".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = "New".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: "Hello".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = "New".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: "Hello".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = "New".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: "Hello".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = "New".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\n\nfn main() {\n    let val = SelfRef { \n        data: \"Hello\".into(), \n        _marker: PhantomPinned \n    };\n    \n    // Pinning on heap\n    let pinned: Pin<Box<SelfRef>> = Box::pin(val);\n    \n    // pinned.data = \"New\".into(); // Error! Cannot mutate !Unpin content easily\n}', NULL, E'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// A struct that cannot be moved safely\nstruct SelfRef {\n    data: String,\n    _marker: PhantomPinned, // Makes it !Unpin\n}\