INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('fdbee766-d110-5f01-8075-3c8b8259c36a', '5e30e4bb-0918-5e82-80ce-1a07a1786a40', '{"EN": "Runtime Architecture & Spawning", "ES": "Arquitectura del Runtime y Spawning"}', '{"EN": "# Tokio Architecture\nTokio is more than just a crate; it''s a runtime environment.\n\n1.  **Multi-threaded Scheduler**: Uses a **Work-Stealing** strategy. It spawns N worker threads (usually equal to CPU cores). Each worker has a local queue of tasks.\n    *   If a worker runs out of tasks, it \"steals\" from another worker''s queue.\n    *   This maximizes CPU usage and balances load automatically.\n2.  **I/O Driver**: An abstraction over Mio (which wraps epoll/kqueue/IOCP). It polls the OS for network events.\n3.  **Time Driver**: Manages timers (`sleep`, `timeout`).\n\n## Spawning Tasks\n`tokio::spawn` takes a Future and submits it to the scheduler.\n*   **Green Threads**: Allocation is ~64 bytes + the size of the Future.\n*   **Lifetime**: Spawned tasks must be `''static`. They are detached from the spawning context.\n*   **JoinHandle**: Returns a handle to await the result or cancel the task.", "ES": "# Arquitectura de Tokio\nTokio es un entorno de ejecuci\u00f3n completo.\n\n1.  **Planificador Multihilo**: Usa estrategia de **Robo de Trabajo (Work-Stealing)**. Lanza N hilos worker. Cada uno tiene una cola local.\n    *   Si un worker se queda sin tareas, \"roba\" de la cola de otro.\n    *   Maximiza uso de CPU y balancea carga.\n2.  **Driver I/O**: Abstracci\u00f3n sobre Mio (epoll/kqueue). Sondea eventos del SO.\n3.  **Driver de Tiempo**: Gestiona timers.\n\n## Lanzar Tareas (Spawning)\n`tokio::spawn` env\u00eda un Futuro al planificador.\n*   **Green Threads**: Asignaci\u00f3n ~64 bytes.\n*   **Lifetime**: Deben ser `''static`.\n*   **JoinHandle**: Retorna un handle para esperar resultado o cancelar."}', false, NULL, NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        \"Background work\"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', NULL, E'#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, E'#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, E'#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        \"Background work\"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        \"Background work\"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        "Background work"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        // This runs on a thread pool\n        \"Background work\"\n    });\n\n    // We must await the JoinHandle to get the result\n    // The result is Result<T, JoinError> (error if panicked or cancelled)\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a3b78d67-bed3-5f48-8052-0988498d5b9e', '5e30e4bb-0918-5e82-80ce-1a07a1786a40', '{"EN": "Blocking Operations: The Hazard", "ES": "Operaciones Bloqueantes: El Peligro"}', '{"EN": "# The Golden Rule: Never Block\n**Never block an async thread.**\nIf you run `std::thread::sleep` or perform heavy CPU computation (crypto, video encoding) directly in an async function, you stop the Worker Thread from polling other tasks.\nSince Tokio defaults to 1 worker per CPU core, blocking just a few tasks can freeze your entire server (latency spikes from microseconds to seconds).\n\n## Handling Blocking Code\n1.  **spawn_blocking**: Tokio maintains a separate, dedicated thread pool for blocking operations. This pool can grow huge (default 512 threads) because these threads are expected to sleep. `spawn_blocking` offloads the task there and returns a Future.\n2.  **rayon**: For CPU-heavy parallel tasks (not waiting on I/O), use Rayon combined with `spawn_blocking` or dedicated channels.", "ES": "# La Regla de Oro: Nunca Bloquees\nSi corres `std::thread::sleep` o c\u00f3mputo pesado (cripto, video) en una funci\u00f3n async, detienes al Worker Thread.\nComo Tokio tiene pocos workers, bloquear algunos congela el servidor.\n\n## Manejando C\u00f3digo Bloqueante\n1.  **spawn_blocking**: Tokio mantiene un pool de hilos separado y dedicado para operaciones bloqueantes. Este pool puede crecer mucho (512 hilos) porque se espera que duerman.\n2.  **rayon**: Para tareas intensivas en CPU, usa Rayon."}', false, NULL, NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        \"Done\"\n    }).await.unwrap();\n    \n    println!(\"{}\", res);\n}', NULL, E'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, E'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, E'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        \"Done\"\n    }).await.unwrap();\n    \n    println!(\"{}\", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        \"Done\"\n    }).await.unwrap();\n    \n    println!(\"{}\", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        "Done"\n    }).await.unwrap();\n    \n    println!("{}", res);\n}', NULL, 'use std::thread;\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    // WRONG: Blocks the runtime worker\n    // thread::sleep(Duration::from_secs(5));\n    \n    // CORRECT: Offload to blocking pool\n    let res = tokio::task::spawn_blocking(|| {\n        // This runs on a OS thread meant for blocking\n        thread::sleep(Duration::from_secs(1));\n        \"Done\"\n    }).await.unwrap();\n    \n    println!(\"{}\", res);\n}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('aac53604-4bf1-5beb-80ad-026a01ea884f', '5e30e4bb-0918-5e82-80ce-1a07a1786a40', '{"EN": "Async I/O Deep Dive", "ES": "Profundizaci\u00f3n en I/O As\u00edncrono"}', '{"EN": "# AsyncRead & AsyncWrite\nTokio provides async versions of standard traits: `AsyncRead` and `AsyncWrite`.\nThese traits are low-level (using `Pin` and `Poll`). Usually, you use the extension trait `AsyncReadExt` which provides user-friendly methods like `read_to_end`, `read_to_string`.\n\n## How it works (Epoll)\nWhen you call `file.read().await`:\n1.  Tokio attempts a non-blocking read syscall.\n2.  If the OS returns `EWOULDBLOCK`, Tokio registers the file descriptor with the OS selector (epoll).\n3.  The task yields (`Pending`).\n4.  When data arrives, the OS wakes the selector, which wakes the task via the Waker.\n\n## Compatibility\nYou cannot use `std::fs::File` inside async code (it blocks). You MUST use `tokio::fs::File`.", "ES": "# AsyncRead y AsyncWrite\nTokio provee versiones async de traits est\u00e1ndar. Son de bajo nivel. Usualmente usas `AsyncReadExt` para m\u00e9todos c\u00f3modos como `read_to_string`.\n\n## C\u00f3mo funciona (Epoll)\nCuando llamas `file.read().await`:\n1.  Tokio intenta lectura no bloqueante.\n2.  Si el SO retorna `EWOULDBLOCK`, Tokio registra el descriptor en el selector (epoll).\n3.  La tarea cede (`Pending`).\n4.  Cuando llega data, el SO despierta al selector, y este a la tarea.\n\n## Compatibilidad\nNo puedes usar `std::fs::File` en async (bloquea). DEBES usar `tokio::fs::File`."}', false, NULL, NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open(\"foo.txt\").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, E'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, E'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, E'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open(\"foo.txt\").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open(\"foo.txt\").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open("foo.txt").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', NULL, 'use tokio::fs::File;\nuse tokio::io::AsyncReadExt;\n\n#[tokio::main]\nasync fn main() -> std::io::Result<()> {\n    // Open file asynchronously\n    let mut f = File::open(\"foo.txt\").await?;\n    let mut buffer = Vec::new();\n\n    // Read asynchronously\n    f.read_to_end(&mut buffer).await?;\n    Ok(())\n}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('622ae5de-b221-54e4-a6d2-9c2dd8c41068', '5e30e4bb-0918-5e82-80ce-1a07a1786a40', '{"EN": "Time & Scheduling Budgets", "ES": "Tiempo y Presupuestos de Planificaci\u00f3n"}', '{"EN": "# Async Sleep\nUse `tokio::time::sleep`. It registers a deadline in a \"Timer Wheel\" (or Heap) inside the Runtime. It is efficient and handles millions of timers.\n\n## Cooperative Scheduling & Budgets\nTokio uses **Cooperative Multitasking**. Tasks must yield voluntarily.\nHowever, what if a task runs a tight loop that never awaits?\n```rust\nwhile true { /* math */ }\n```\nThis \"starves\" other tasks on the same worker thread.\n\n**Automatic Yielding**: Tokio has a \"budget\" system. After a certain number of \"polls\" (default 128), it forces a yield to ensure fairness. But for pure CPU loops, this doesn''t trigger.\n**Manual Yield**: Use `tokio::task::yield_now()` inside heavy loops to manually give control back to the scheduler.", "ES": "# Sue\u00f1o Async\nUsa `tokio::time::sleep`. Registra un plazo en una \"Rueda de Tiempo\" en el Runtime. Eficiente para millones de timers.\n\n## Planificaci\u00f3n Cooperativa\nSi una tarea corre un bucle cerrado sin awaits, \"mata de hambre\" a otras tareas.\n\n**Yield Autom\u00e1tico**: Tokio tiene un sistema de \"presupuesto\". Tras cierto n\u00famero de polls (128), fuerza un yield. Pero en bucles de CPU puros esto no activa.\n**Yield Manual**: Usa `tokio::task::yield_now()` en bucles pesados para devolver control."}', false, NULL, NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, E'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, E'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, E'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', NULL, 'use tokio::task;\n\n#[tokio::main]\nasync fn main() {\n    tokio::spawn(async {\n        for i in 0..1_000_000 {\n            if i % 1000 == 0 {\n                // Be a good citizen, let others run\n                task::yield_now().await;\n            }\n        }\n    });\n}', 4);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('c83108d1-57fd-59d8-87b1-a2612686dccc', '5e30e4bb-0918-5e82-80ce-1a07a1786a40', '{"EN": "Quiz: Tokio", "ES": "Quiz: Tokio"}', '{"EN": "Check runtime concepts.", "ES": "Verifica conceptos del runtime."}', true, NULL, '[{"id": "q3-1", "question": {"EN": "What scheduling strategy does Tokio use?", "ES": "\u00bfQu\u00e9 estrategia de planificaci\u00f3n usa Tokio?"}, "options": {"EN": ["Round Robin", "Work Stealing", "FIFO"], "ES": ["Round Robin", "Robo de Trabajo (Work Stealing)", "FIFO"]}, "correctIndex": 1, "explanation": {"EN": "Work Stealing allows idle threads to take tasks from busy threads.", "ES": "Work Stealing permite a hilos ociosos tomar tareas de hilos ocupados."}}, {"id": "q3-2", "question": {"EN": "How do you run synchronous CPU-heavy code in Tokio?", "ES": "\u00bfC\u00f3mo corres c\u00f3digo s\u00edncrono pesado en Tokio?"}, "options": {"EN": ["Just run it", "spawn_blocking", "async block"], "ES": ["Solo c\u00f3rrelo", "spawn_blocking", "bloque async"]}, "correctIndex": 1, "explanation": {"EN": "`spawn_blocking` moves it to a separate thread pool to avoid blocking the async event loop.", "ES": "`spawn_blocking` lo mueve a un pool separado para evitar bloquear el bucle de eventos."}}]', NULL, '[{"id": "q3-1", "question": {"EN": "What scheduling strategy does Tokio use?", "ES": "\u00bfQu\u00e9 estrategia de planificaci\u00f3n usa Tokio?"}, "options": {"EN": ["Round Robin", "Work Stealing", "FIFO"], "ES": ["Round Robin", "Robo de Trabajo (Work Stealing)", "FIFO"]}, "correctIndex": 1, "explanation": {"EN": "Work Stealing allows idle threads to take tasks from busy threads.", "ES": "Work Stealing permite a hilos ociosos tomar tareas de hilos ocupados."}}, {"id": "q3-2", "question": {"EN": "How do you run synchronous CPU-heavy code in Tokio?", "ES": "\u00bfC\u00f3mo corres c\u00f3digo s\u00edncrono pesado en Tokio?"}, "options": {"EN": ["Just run it", "spawn_blocking", "async block"], "ES": ["Solo c\u00f3rrelo", "spawn_blocking", "bloque async"]}, "correctIndex": 1, "explanation": {"EN": "`spawn_blocking` moves it to a separate thread pool to avoid blocking the async event loop.", "ES": "`spawn_blocking` lo mueve a un pool separado para evitar bloquear el bucle de eventos."}}]', NULL, '[{"id": "q3-1", "question": {"EN": "What scheduling strategy does Tokio use?", "ES": "\u00bfQu\u00e9 estrategia de planificaci\u00f3n usa Tokio?"}, "options": {"EN": ["Round Robin", "Work Stealing", "FIFO"], "ES": ["Round Robin", "Robo de Trabajo (Work Stealing)", "FIFO"]}, "correctIndex": 1, "explanation": {"EN": "Work Stealing allows idle threads to take tasks from busy threads.", "ES": "Work Stealing permite a hilos ociosos tomar tareas de hilos ocupados."}}, {"id": "q3-2", "question": {"EN": "How do you run synchronous CPU-heavy code in Tokio?", "ES": "\u00bfC\u00f3mo corres c\u00f3digo s\u00edncrono pesado en Tokio?"}, "options": {"EN": ["Just run it", "spawn_blocking", "async block"], "ES": ["Solo c\u00f3rrelo", "spawn_blocking", "bloque async"]}, "correctIndex": 1, "explanation": {"EN": "`spawn_blocking` moves it to a separate thread pool to avoid blocking the async event loop.", "ES": "`spawn_blocking` lo mueve a un pool separado para evitar bloquear el bucle de eventos."}}]', NULL, '[{"id": "q3-1", "question": {"EN": "What scheduling strategy does Tokio use?", "ES": "\u00bfQu\u00e9 estrategia de planificaci\u00f3n usa Tokio?"}, "options": {"EN": ["Round Robin", "Work Stealing", "FIFO"], "ES": ["Round Robin", "Robo de Trabajo (Work Stealing)", "FIFO"]}, "correctIndex": 1, "explanation": {"EN": "Work Stealing allows idle threads to take tasks from busy threads.", "ES": "Work Stealing permite a hilos ociosos tomar tareas de hilos ocupados."}}, {"id": "q3-2", "question": {"EN": "How do you run synchronous CPU-heavy code in Tokio?", "ES": "\u00bfC\u00f3mo corres c\u00f3digo s\u00edncrono pesado en Tokio?"}, "options": {"EN": ["Just run it", "spawn_blocking", "async block"], "ES": ["Solo c\u00f3rrelo", "spawn_blocking", "bloque async"]}, "correctIndex": 1, "explanation": {"EN": "`spawn_blocking` moves it to a separate thread pool to avoid blocking the async event loop.", "ES": "`spawn_blocking` lo mueve a un pool separado para evitar bloquear el bucle de eventos."}}]', NULL, '[{"id": "q3-1", "question": {"EN": "What scheduling strategy does Tokio use?", "ES": "\u00bfQu\u00e9 estrategia de planificaci\u00f3n usa Tokio?"}, "options": {"EN": ["Round Robin", "Work Stealing", "FIFO"], "ES": ["Round Robin", "Robo de Trabajo (Work Stealing)", "FIFO"]}, "correctIndex": 1, "explanation": {"EN": "Work Stealing allows idle threads to take tasks from busy threads.", "ES": "Work Stealing permite a hilos ociosos tomar tareas de hilos ocupados."}}, {"id": "q3-2", "question": {"EN": "How do you run synchronous CPU-heavy code in Tokio?", "ES": "\u00bfC\u00f3mo corres c\u00f3digo s\u00edncrono pesado en Tokio?"}, "options": {"EN": ["Just run it", "spawn_blocking", "async block"], "ES": ["Solo c\u00f3rrelo", "spawn_blocking", "bloque async"]}, "correctIndex": 1, "explanation": {"EN": "`spawn_blocking` moves it to a separate thread pool to avoid blocking the async event loop.", "ES": "`spawn_blocking` lo mueve a un pool separado para evitar bloquear el bucle de eventos."}}]', NULL, '[{"id": "q3-1", "question": {"EN": "What scheduling strategy does Tokio use?", "ES": "\u00bfQu\u00e9 estrategia de planificaci\u00f3n usa Tokio?"}, "options": {"EN": ["Round Robin", "Work Stealing", "FIFO"], "ES": ["Round Robin", "Robo de Trabajo (Work Stealing)", "FIFO"]}, "correctIndex": 1, "explanation": {"EN": "Work Stealing allows idle threads to take tasks from busy threads.", "ES": "Work Stealing permite a hilos ociosos tomar tareas de hilos ocupados."}}, {"id": "q3-2", "question": {"EN": "How do you run synchronous CPU-heavy code in Tokio?", "ES": "\u00bfC\u00f3mo corres c\u00f3digo s\u00edncrono pesado en Tokio?"}, "options": {"EN": ["Just r