reporting").await.unwrap();\n    });\n    \n    tokio::spawn(async move {\n        tx2.send("Actor 2 reporting").await.unwrap();\n    });\n\n    while let Some(message) = rx.recv().await {\n        println!("GOT = {}", message);\n    }\n}', NULL, 'use tokio::sync::mpsc;\n\n#[tokio::main]\nasync fn main() {\n    // Capacity 32. If 33 messages are sent before any read, the 33rd sender sleeps.\n    let (tx, mut rx) = mpsc::channel(32);\n\n    let tx2 = tx.clone();\n    tokio::spawn(async move {\n        tx.send(\"Actor 1 reporting\").await.unwrap();\n    });\n    \n    tokio::spawn(async move {\n        tx2.send(\"Actor 2 reporting\").await.unwrap();\n    });\n\n    while let Some(message) = rx.recv().await {\n        println!(\"GOT = {}\", message);\n    }\n}', NULL, 'use tokio::sync::mpsc;\n\n#[tokio::main]\nasync fn main() {\n    // Capacity 32. If 33 messages are sent before any read, the 33rd sender sleeps.\n    let (tx, mut rx) = mpsc::channel(32);\n\n    let tx2 = tx.clone();\n    tokio::spawn(async move {\n        tx.send("Actor 1 reporting").await.unwrap();\n    });\n    \n    tokio::spawn(async move {\n        tx2.send("Actor 2 reporting").await.unwrap();\n    });\n\n    while let Some(message) = rx.recv().await {\n        println!("GOT = {}", message);\n    }\n}', NULL, 'use tokio::sync::mpsc;\n\n#[tokio::main]\nasync fn main() {\n    // Capacity 32. If 33 messages are sent before any read, the 33rd sender sleeps.\n    let (tx, mut rx) = mpsc::channel(32);\n\n    let tx2 = tx.clone();\n    tokio::spawn(async move {\n        tx.send(\"Actor 1 reporting\").await.unwrap();\n    });\n    \n    tokio::spawn(async move {\n        tx2.send(\"Actor 2 reporting\").await.unwrap();\n    });\n\n    while let Some(message) = rx.recv().await {\n        println!(\"GOT = {}\", message);\n    }\n}', NULL, 'use tokio::sync::mpsc;\n\n#[tokio::main]\nasync fn main() {\n    // Capacity 32. If 33 messages are sent before any read, the 33rd sender sleeps.\n    let (tx, mut rx) = mpsc::channel(32);\n\n    let tx2 = tx.clone();\n    tokio::spawn(async move {\n        tx.send("Actor 1 reporting").await.unwrap();\n    });\n    \n    tokio::spawn(async move {\n        tx2.send("Actor 2 reporting").await.unwrap();\n    });\n\n    while let Some(message) = rx.recv().await {\n        println!("GOT = {}", message);\n    }\n}', NULL, 'use tokio::sync::mpsc;\n\n#[tokio::main]\nasync fn main() {\n    // Capacity 32. If 33 messages are sent before any read, the 33rd sender sleeps.\n    let (tx, mut rx) = mpsc::channel(32);\n\n    let tx2 = tx.clone();\n    tokio::spawn(async move {\n        tx.send(\"Actor 1 reporting\").await.unwrap();\n    });\n    \n    tokio::spawn(async move {\n        tx2.send(\"Actor 2 reporting\").await.unwrap();\n    });\n\n    while let Some(message) = rx.recv().await {\n        println!(\"GOT = {}\", message);\n    }\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('6ef6551b-d4be-5794-87a1-a1bebebd50d6', 'cd1772a0-87b3-5262-8159-2302ce4a50f7', '{"EN": "Broadcast & Watch Channels", "ES": "Canales Broadcast y Watch"}', '{"EN": "# Broadcast (MPMC)\n**Multi-Producer, Multi-Consumer**.\nEvery message sent is seen by **ALL** active receivers.\n*   **Use Cases**: Chat rooms, Event bus, Pub/Sub.\n*   **Lag**: If a receiver is too slow and the internal buffer fills up, the slow receiver will miss messages. Tokio returns `RecvError::Lagged(count)`. This ensures one slow client doesn''t crash the whole system.\n\n# Watch (SPMC)\n**Single-Producer, Multi-Consumer**.\nOptimized for **State Synchronization** (e.g., Configuration, Shutdown signal).\n*   It only holds the **latest** value.\n*   It does NOT keep a history. If you send \"A\", then \"B\" quickly, a receiver might only see \"B\".\n*   Receivers use `changed().await` to wait for updates.", "ES": "# Broadcast (MPMC)\nCada mensaje es visto por **TODOS** los receptores.\n*   **Casos**: Chat, Bus de eventos.\n*   **Lag**: Si un receptor es lento y el buffer se llena, pierde mensajes (`RecvError::Lagged`). Asegura que un cliente lento no tumbe el sistema.\n\n# Watch (SPMC)\nOptimizado para **Sincronizaci\u00f3n de Estado** (Configuraci\u00f3n, Se\u00f1al de apagado).\n*   Solo guarda el **\u00faltimo** valor.\n*   NO guarda historia. Si env\u00edas \"A\" y luego \"B\" r\u00e1pido, un receptor podr\u00eda ver solo \"B\".\n*   Receptores usan `changed().await`."}', false, NULL, NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel(\"config_v1\");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send(\"config_v2\").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!(\"New config: {}\", *val);\n    } // Lock released here\n}', NULL, E'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, E'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, E'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel(\"config_v1\");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send(\"config_v2\").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!(\"New config: {}\", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel(\"config_v1\");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send(\"config_v2\").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!(\"New config: {}\", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel("config_v1");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send("config_v2").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!("New config: {}", *val);\n    } // Lock released here\n}', NULL, 'use tokio::sync::watch;\n\n#[tokio::main]\nasync fn main() {\n    let (tx, mut rx) = watch::channel(\"config_v1\");\n\n    tokio::spawn(async move {\n        // Atomic replacement of value\n        tx.send(\"config_v2\").unwrap();\n    });\n\n    // Detect change\n    rx.changed().await.unwrap();\n    {\n        let val = rx.borrow();\n        println!(\"New config: {}\", *val);\n    } // Lock released here\n}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('6d54ddc3-fa67-59a5-99be-a4004a9ad22d', 'cd1772a0-87b3-5262-8159-2302ce4a50f7', '{"EN": "OneShot & Barrier", "ES": "OneShot y Barrier"}', '{"EN": "# Oneshot\nA channel optimized for sending exactly **one** value from sender to receiver.\n*   **Zero Overhead**: Does not allocate a queue.\n*   **Use Case**: Returning the result of a spawned task to the spawner (like a Promise resolution).\n\n# Barrier\nSynchronization primitive. Allows N tasks to wait until all N have reached the barrier point.\n*   **Phase Synchronization**: Useful in parallel algorithms (e.g., \"Wait for all workers to finish Step 1 before starting Step 2\").", "ES": "# Oneshot\nOptimizado para enviar exactamente **un** valor.\n*   **Cero Sobrecarga**: No asigna cola.\n*   **Uso**: Retornar resultado de una tarea (como resolver una Promesa).\n\n# Barrier\nPermite a N tareas esperar hasta que las N lleguen al punto de barrera.\n*   **Sincronizaci\u00f3n de Fases**: \u00datil en algoritmos paralelos (\"Esperar a que todos terminen Paso 1 antes de Paso 2\")."}', false, NULL, NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!(\"Task 1 doing work...\");\n        b2.wait().await; // Waits for Main\n        println!(\"Task 1 Proceeding!\");\n    });\n\n    println!(\"Main setup...\");\n    barrier.wait().await; // Waits for Task 1\n    println!(\"Main Proceeding!\");\n}', NULL, E'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, E'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, E'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!(\"Task 1 doing work...\");\n        b2.wait().await; // Waits for Main\n        println!(\"Task 1 Proceeding!\");\n    });\n\n    println!(\"Main setup...\");\n    barrier.wait().await; // Waits for Task 1\n    println!(\"Main Proceeding!\");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!(\"Task 1 doing work...\");\n        b2.wait().await; // Waits for Main\n        println!(\"Task 1 Proceeding!\");\n    });\n\n    println!(\"Main setup...\");\n    barrier.wait().await; // Waits for Task 1\n    println!(\"Main Proceeding!\");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!("Task 1 doing work...");\n        b2.wait().await; // Waits for Main\n        println!("Task 1 Proceeding!");\n    });\n\n    println!("Main setup...");\n    barrier.wait().await; // Waits for Task 1\n    println!("Main Proceeding!");\n}', NULL, 'use tokio::sync::{oneshot, Barrier};\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // --- Barrier Example ---\n    let barrier = Arc::new(Barrier::new(2));\n    let b2 = barrier.clone();\n\n    tokio::spawn(async move {\n        println!(\"Task 1 doing work...\");\n        b2.wait().await; // Waits for Main\n        println!(\"Task 1 Proceeding!\");\n    });\n\n    println!(\"Main setup...\");\n    barrier.wait().await; // Waits for Task 1\n    println!(\"Main Proceeding!\");\n}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('cc8b0871-76f1-5514-8bf4-68a3848029c5', 'cd1772a0-87b3-5262-8159-2302ce4a50f7', '{"EN": "Semaphores (Rate Limiting)", "ES": "Sem\u00e1foros (Rate Limiting)"}', '{"EN": "# Controlling Concurrency\nA Semaphore maintains a set of \"permits\".\n*   `acquire()`: Takes a permit. Waits if count is 0.\n*   **Drop**: Unlike C semaphores, Tokio''s `SemaphorePermit` automatically releases the permit back to the semaphore when it goes out of scope (RAII).\n\n## Use Case: Database Connections\nIf you have 10,000 incoming web requests but your Database only supports 50 concurrent queries, use a Semaphore initialized to 50.\n1.  Request arrives.\n2.  `sem.acquire().await`. (Request waits in queue if DB busy).\n3.  Perform query.\n4.  Permit dropped. Next request wakes up.", "ES": "# Controlando Concurrencia\nUn Sem\u00e1foro mantiene un set de \"permisos\".\n*   `acquire()`: Toma permiso. Espera si es 0.\n*   **Drop**: `SemaphorePermit` libera autom\u00e1ticamente el permiso al salir de \u00e1mbito (RAII).\n\n## Caso: Conexiones a BD\nSi tienes 10,000 peticiones pero tu BD soporta 50 queries:\n1.  Llega petici\u00f3n.\n2.  `sem.acquire().await`. (Espera en cola si BD ocupada).\n3.  Ejecuta query.\n4.  Permiso liberado."}', false, NULL, NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!(\"Task {} running (acquired permit)\", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, E'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, E'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only