       // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!(\"Task {} running (acquired permit)\", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!("Task {} running (acquired permit)", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 simultaneous jobs allowed\n    let sem = Arc::new(Semaphore::new(2));\n\n    for i in 0..5 {\n        let sem = sem.clone();\n        tokio::spawn(async move {\n            let _permit = sem.acquire().await.unwrap();\n            println!(\"Task {} running (acquired permit)\", i);\n            // Simulate work\n            tokio::time::sleep(std::time::Duration::from_millis(100)).await;\n            // _permit dropped here, slot freed\n        });\n    }\n}', NULL, 'use tokio::sync::Semaphore;\nuse std::sync::Arc;\n\n#[tokio::main]\nasync fn main() {\n    // Only 2 si