INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('66e0c778-caf0-5ce8-b20d-f4b2a51aaf15', 'cd1772a0-87b3-5262-8159-2302ce4a50f7', '{"EN": "Quiz: Patterns", "ES": "Quiz: Patrones"}', '{"EN": "Check sync primitives.", "ES": "Revisa primitivas de sinc."}', true, NULL, '[{"id": "q4-1", "question": {"EN": "What happens if a Broadcast receiver is too slow?", "ES": "\u00bfQu\u00e9 pasa si un receptor Broadcast es muy lento?"}, "options": {"EN": ["Sender blocks", "Receiver lags and misses messages", "Panics"], "ES": ["Emisor se bloquea", "Receptor tiene lag y pierde mensajes", "P\u00e1nico"]}, "correctIndex": 1, "explanation": {"EN": "Broadcast uses a ring buffer. If a receiver falls behind the tail, it errors with Lagged.", "ES": "Broadcast usa un ring buffer. Si un receptor se queda atr\u00e1s, recibe error Lagged."}}, {"id": "q4-2", "question": {"EN": "Which channel is best for configuration updates?", "ES": "\u00bfQu\u00e9 canal es mejor para actualizaciones de configuraci\u00f3n?"}, "options": {"EN": ["mpsc", "oneshot", "watch"], "ES": ["mpsc", "oneshot", "watch"]}, "correctIndex": 2, "explanation": {"EN": "Watch is designed to share the latest value among many watchers.", "ES": "Watch est\u00e1 dise\u00f1ado para compartir el \u00faltimo valor entre muchos observadores."}}]', NULL, '[{"id": "q4-1", "question": {"EN": "What happens if a Broadcast receiver is too slow?", "ES": "\u00bfQu\u00e9 pasa si un receptor Broadcast es muy lento?"}, "options": {"EN": ["Sender blocks", "Receiver lags and misses messages", "Panics"], "ES": ["Emisor se bloquea", "Receptor tiene lag y pierde mensajes", "P\u00e1nico"]}, "correctIndex": 1, "explanation": {"EN": "Broadcast uses a ring buffer. If a receiver falls behind the tail, it errors with Lagged.", "ES": "Broadcast usa un ring buffer. Si un receptor se queda atr\u00e1s, recibe error Lagged."}}, {"id": "q4-2", "question": {"EN": "Which channel is best for configuration updates?", "ES": "\u00bfQ