INSERT INTO modules (id, course_id, title, "order") VALUES ('a42c8009-c00d-5877-88f4-f554e7f742c7', '2c20e72b-36b9-581d-a7de-b94661a4f498', '{"EN": "5. Control Flow & Select", "ES": "5. Flujo de Control y Select"}', 5);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('763e5684-d910-5ccd-98a0-d535b92f5801', 'a42c8009-c00d-5877-88f4-f554e7f742c7', '{"EN": "Join & TryJoin Logic", "ES": "L\u00f3gica de Join y TryJoin"}', '{"EN": "# Concurrent Execution\nWait for multiple futures to complete.\n*   `tokio::join!(f1, f2)`: Runs futures concurrently. Returns `(Res1, Res2)`. Wait for **ALL**.\n*   `tokio::try_join!(f1, f2)`: Same, but if **ANY** future returns `Err`, the macro returns immediately with that Error. The other futures are dropped (cancelled).\n\n## Sequential vs Concurrent\n*   **Sequential**: `f1.await; f2.await;`. Total time = T1 + T2.\n*   **Concurrent**: `join!(f1, f2)`. Total time = max(T1, T2).\n\nUse `join!` when tasks are independent.", "ES": "# Ejecuci\u00f3n Concurrente\nEsperar m\u00faltiples futuros.\n*   `tokio::join!`: Corre concurrentemente. Retorna tupla. Espera a **TODOS**.\n*   `tokio::try_join!`: Si **ALGUNO** da `Err`, retorna inmediatamente con ese Error. Los otros se cancelan.\n\n## Secuencial vs Concurrente\n*   **Secuencial**: `f1.await; f2.await;`. Tiempo = T1 + T2.\n*   **Concurrente**: `join!(f1, f2)`. Tiempo = max(T1, T2)."}', false, NULL, NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!(\"{}, {}\", a, b);\n}', NULL, E'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, E'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, E'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!(\"{}, {}\", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!(\"{}, {}\", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!("{}, {}", a, b);\n}', NULL, 'async fn work(n: u32) -> u32 { n }\n\n#[tokio::main]\nasync fn main() {\n    // Runs concurrently on the same task\n    let (a, b) = tokio::join!(\n        work(1),\n        work(2)\n    );\n    println!(\"{}, {}\", a, b);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('9b5f73b2-db39-5965-beee-cbbe9aab65f9', 'a42c8009-c00d-5877-88f4-f554e7f742c7', '{"EN": "The Select Macro", "ES": "La Macro Select"}', '{"EN": "# Racing Futures\n`tokio::select!` waits on multiple branches and runs the handler for the **first** one that completes.\nCrucially, **it cancels (drops) all other branches**.\n\n## Patterns\n1.  **Timeout**: Race a task against `time::sleep`.\n2.  **Cancellation**: Race a task against a `oneshot::Receiver` (cancel signal).\n3.  **Streams**: You can match on `Some(v) = stream.next()`.\n\n## Else branch\nYou can add an `else` branch which runs if no pattern matches (useful only with `try_recv` or similar non-async checks, otherwise select is typically infinite wait).", "ES": "# Carreras de Futuros\n`tokio::select!` espera en m\u00faltiples ramas y ejecuta el handler de la **primera** que completa.\nCrucialmente, **cancela (elimina) todas las otras ramas**.\n\n## Patrones\n1.  **Timeout**: Tarea vs `sleep`.\n2.  **Cancelaci\u00f3n**: Tarea vs se\u00f1al de cancelar.\n3.  **Streams**: Match `Some(v) = stream.next()`."}', false, NULL, NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!(\"Timer finished first\");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!(\"This will be cancelled\");\n        }\n    }\n}', NULL, E'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, E'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, E'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!(\"Timer finished first\");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!(\"This will be cancelled\");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!(\"Timer finished first\");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!(\"This will be cancelled\");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!("Timer finished first");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!("This will be cancelled");\n        }\n    }\n}', NULL, 'use tokio::time::{sleep, Duration};\n\n#[tokio::main]\nasync fn main() {\n    tokio::select! {\n        _ = sleep(Duration::from_millis(100)) => {\n            println!(\"Timer finished first\");\n        }\n        _ = sleep(Duration::from_millis(500)) => {\n            println!(\"This will be cancelled\");\n        }\n    }\n}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('098f0f40-dedb-5043-b7e5-94c5a8fdb97d', 'a42c8009-c00d-5877-88f4-f554e7f742c7', '{"EN": "Cancellation Safety", "ES": "Seguridad de Cancelaci\u00f3n"}', '{"EN": "# The Danger of Select: Data Loss\nWhen `select!` cancels a branch, the Future is **Dropped**.\nIf that Future was in the middle of a complex operation, partial state might be lost.\n\n## Unsafe Example: `write_all`\n`AsyncWrite::write_all(buf)` sends bytes in a loop.\n1.  You write 5 out of 10 bytes.\n2.  `select!` triggers the other branch.\n3.  The `write_all` future is dropped.\n4.  **Result**: You wrote 5 bytes to the socket, but you lost the knowledge that you did so. The next time you try to write, you might write the whole buffer again, corrupting the stream.\n\n## Safe Primitives\n*   `mpsc::recv()`: Safe. The message remains in the channel if cancelled.\n*   `TcpListener::accept()`: Safe.\n*   `AsyncRead::read_buf`: Usually safe (idempotent).\n\n## Mitigation\nTo handle unsafe futures in select, **Spawn** them.\nA spawned task (`tokio::spawn`) continues running in the background even if the handle is dropped (detached). It is not cancelled unless explicitly aborted.", "ES": "# El Peligro de Select: P\u00e9rdida de Datos\nCuando `select!` cancela, el Futuro se **Elimina (Drop)**.\nSi estaba a mitad de operaci\u00f3n, se pierde estado.\n\n## Ejemplo Inseguro: `write_all`\nEscribe bytes en bucle. Si se cancela a la mitad, escribiste bytes parciales pero perdiste el rastro. Reintentar corromper\u00eda el stream.\n\n## Primitivas Seguras\n*   `recv()`: Seguro. El mensaje queda en el canal.\n*   `accept()`: Seguro.\n\n## Mitigaci\u00f3n\nPara futuros inseguros, usa **Spawn**. Una tarea lanzada corre en fondo aunque pierdas el handle."}', false, NULL, NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!(\"Task finished: {:?}\", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!(\"Timeout! Task continues in background...\");\n    }\n}', NULL, E'// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, E'// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, E'// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!(\"Task finished: {:?}\", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!(\"Timeout! Task continues in background...\");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!(\"Task finished: {:?}\", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!(\"Timeout! Task continues in background...\");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!("Task finished: {:?}", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!("Timeout! Task continues in background...");\n    }\n}', NULL, '// Use Spawn for cancellation safety\nlet t = tokio::spawn(async {\n    // Critical work that shouldn''t be interrupted partially\n    write_critical_data().await\n});\n\ntokio::select! {\n    res = t => println!(\"Task finished: {:?}\", res),\n    _ = tokio::time::sleep(Duration::from_secs(1)) => {\n        println!(\"Timeout! Task continues in background...\");\n    }\n}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('62439112-7c8e-5b40-969f-f7cd0bb62f4b', 'a42c8009-c00d-5877-88f4-f554e7f742c7', '{"EN": "Quiz: Control Flow", "ES": "Quiz: Flujo de Control"}', '{"EN": "Test select logic.", "ES": "Prueba l\u00f3gica select."}', true, NULL, '[{"id": "q5-1", "question": {"EN": "What happens to losing branches in `select!`?", "ES": "\u00bfQu\u00e9 pasa con las ramas perdedoras en `select!`?"}, "options": {"EN": ["They continue in background", "They are dropped/cancelled", "They pause"], "ES": ["Siguen en fondo", "Son eliminadas/canceladas", "Se pausan"]}, "correctIndex": 1, "explanation": {"EN": "Select drops all uncompleted futures immediately. This triggers cleanup logic.", "ES": "Select elimina todos los futuros incompletos inmediatamente."}}, {"id": "q5-2", "question": {"EN": "Is `AsyncWrite::write_all` cancellation safe?", "ES": "\u00bfEs `AsyncWrite::write_all` segura ante cancelaci\u00f3n?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "No, it may write partial data and lose state if dropped mid-execution.", "ES": "No, puede escribir datos parciales y perder estado si se elimina a medias."}}]', NULL, '[{"id": "q5-1", "question": {"EN": "What happens to losing branches in `select!`?", "ES": "\u00bfQu\u00e9 pasa con las ramas perdedoras en `select!`?"}, "options": {"EN": ["They continue in background", "They are dropped/cancelled", "They pause"], "ES": ["Siguen en fondo", "Son eliminadas/canceladas", "Se pausan"]}, "correctIndex": 1, "explanation": {"EN": "Select drops all uncompleted futures immediately. This triggers cleanup logic.", "ES": "Select elimina todos los futuros incompletos inmediatamente."}}, {"id": "q5-2", "question": {"EN": "Is `AsyncWrite::write_all` cancellation safe?", "ES": "\u00bfEs `AsyncWrite::write_all` segura ante cancelaci\u00f3n?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, 