INSERT INTO modules (id, course_id, title, "order") VALUES ('a2e10782-e97d-5066-a4eb-37994ab47f93', '2c20e72b-36b9-581d-a7de-b94661a4f498', '{"EN": "6. Streams", "ES": "6. Streams (Flujos)"}', 6);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('e0177fb4-e007-5d24-a357-55b8e77d12a9', 'a2e10782-e97d-5066-a4eb-37994ab47f93', '{"EN": "The Stream Trait", "ES": "El Trait Stream"}', '{"EN": "# Async Iterators\nA `Stream` is the asynchronous equivalent of an `Iterator`. Instead of `next()`, it yields `poll_next()`.\n\n```rust\ntrait Stream {\n    type Item;\n    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<''_>) -> Poll<Option<Self::Item>>;\n}\n```\n\n## Iterating\nRust `for` loops do not support Streams yet. You must use:\n1.  `while let Some(v) = stream.next().await` (using `StreamExt`).\n2.  Adapters like `for_each` or `fold`.\n\n## Sources\n*   `tokio_stream::iter(vec)`: Converts a collection to a stream.\n*   `mpsc::Receiver`: Is effectively a stream of messages.\n*   `TcpListener`: A stream of incoming connections.", "ES": "# Iteradores As\u00edncronos\nUn `Stream` es el equivalente as\u00edncrono de un `Iterator`.\n\n## Iterando\nLos bucles `for` no soportan Streams. Usa:\n1.  `while let Some(v) = stream.next().await`.\n2.  Adaptadores como `for_each`.\n\n## Fuentes\n*   `tokio_stream::iter`.\n*   `mpsc::Receiver`.\n*   `TcpListener`: Stream de conexiones entrantes."}', false, NULL, NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!(\"Got: {}\", num);\n    }\n}', NULL, E'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, E'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, E'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!(\"Got: {}\", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!(\"Got: {}\", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!("Got: {}", num);\n    }\n}', NULL, 'use tokio_stream::{self as stream, StreamExt};\n\n#[tokio::main]\nasync fn main() {\n    let mut stream = stream::iter(vec![1, 2, 3]);\n\n    while let Some(num) = stream.next().await {\n        println!(\"Got: {}\", num);\n    }\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('61fe05a0-f2c0-5dbb-817d-79f635835f79', 'a2e10782-e97d-5066-a4eb-37994ab47f93', '{"EN": "Buffered Concurrency", "ES": "Concurrencia con Buffer"}', '{"EN": "# Processing Streams Concurrently\nTypically, iterating a stream is sequential:\n```rust\nwhile let Some(item) = stream.next().await {\n    process(item).await; // Waits for this to finish before next item\n}\n```\n\n## buffer_unordered(N)\nThis adapter allows processing up to `N` items concurrently.\nIt pulls items from the source stream, spawns the futures, and yields results as soon as *any* future completes (out of order).\n*   **Backpressure**: If N futures are running, it stops pulling from the source until one finishes.\n\n## buffered(N)\nSimilar, but ensures results are yielded in the **same order** as inputs (head-of-line blocking if the first item is slow).", "ES": "# Procesamiento Concurrente\nIterar suele ser secuencial.\n\n## buffer_unordered(N)\nPermite procesar hasta `N` \u00edtems concurrentemente.\nJala \u00edtems, corre futuros, y entrega resultados apenas *cualquiera* termine (desordenado).\n*   **Backpressure**: Si N corren, para de jalar.\n\n## buffered(N)\nSimilar, pero asegura que los resultados salgan en el **mismo orden** que entraron (bloqueo si el primero es lento)."}', false, NULL, NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!(\"Completed: {}\", res);\n    }).await;\n}', NULL, E'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, E'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, E'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(