L, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!("Completed: {}", res);\n    }).await;\n}', NULL, 'use futures::stream::{self, StreamExt};\nuse std::time::Duration;\n\n#[tokio::main]\nasync fn main() {\n    let fetches = stream::iter(1..=5)\n        .map(|i| async move {\n            tokio::time::sleep(Duration::from_millis(100)).await;\n            i * 10\n        })\n        .buffer_unordered(3); // Max 3 concurrent sleeps\n\n    fetches.for_each(|res| async move {\n        println!(\"Completed: {}\", res);\n    }).await;\n}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a156e62f-c3bc-5f94-9d5e-4b18f06134e3', 'a2e10782-e97d-5066-a4eb-37994ab47f93', '{"EN": "Quiz: Streams", "ES": "Quiz: Streams"}', '{"EN": "Stream basics.", "ES": "B\u00e1sicos de Stream."}', true, NULL, '[{"id": "q6-1", "question": {"EN": "What does `buffer_unordered` do?", "ES": "\u00bfQu\u00e9 hace `buffer_unordered`?"}, "options": {"EN": ["Sorts the stream", "Runs futures concurrently", "Buffers bytes"], "ES": ["Ordena el stream", "Corre futuros concurrentemente", "Bufferea bytes"]}, "correctIndex": 1, "explanation": {"EN": "It allows N futures to run at the same time, yielding results as they finish.", "ES": "Permite correr N futuros a la vez, entregando resultados al terminar."}}]', NULL, '[{"id": "q6-1", "question": {"EN": "What does `buffer_unordered` do?", "ES": "\u00bfQu\u00e9 hace `buffer_unordered`?"}, "options": {"EN": ["Sorts the stream", "Runs futures concurrently", "Buffers bytes"], "ES": ["Ordena el stream", "Corre futuros concurrentemente", "Bufferea bytes"]}, "correctIndex": 1, "explanation": {"EN": "It allows N futures to run at the same time, yielding results as they finish.", "ES": "Permite correr N futuros a la vez, entregando resultados al terminar."}}]', NULL, '[{"id": "q6-1", "question": {"EN": "What does `buffer_unordered` do?", "ES": "\u00bfQu\u00e9 hace `buffer_unordered`?"}, "options": {"EN": ["Sorts the stream", "Runs futures concurrently", "Buffers bytes"], "ES": ["Ordena el stream", "Corre futuros concurrentemente", "Bufferea bytes"]}, "correctIndex": 1, "explanation": {"EN": "It allows N futures to run at the same time, yielding results as they finish.", "ES": "Permite correr N futuros a la vez, entregando resultados al terminar."}}]', NULL, '[{"id": "q6-1", "question": {"EN": "What does `buffer_unordered` do?", "ES": "\u00bfQu\u00e9 hace `buffer_unordered`?"}, "options": {"EN": ["Sorts the stream", "Runs futures concurrently", "Buffers bytes"],