INSERT INTO modules (id, course_id, title, "order") VALUES ('22370ebf-248d-52dd-ba4d-b654b4b69377', '2c20e72b-36b9-581d-a7de-b94661a4f498', '{"EN": "7. Atomics & Parallelism", "ES": "7. At\u00f3micos y Paralelismo"}', 7);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('48b5ab6a-4c56-5154-8c32-a56b154b2901', '22370ebf-248d-52dd-ba4d-b654b4b69377', '{"EN": "Data Parallelism (Rayon)", "ES": "Paralelismo de Datos (Rayon)"}', '{"EN": "# CPU Bound Tasks\nAsync (Tokio) is designed for I/O (Waiting). For heavy calculation (Processing), use **Rayon**.\n\n## Work Stealing Strategy\nRayon uses a global thread pool. When you call `par_iter()`, it breaks your collection into chunks.\n*   **Adaptive**: If one CPU core finishes its chunk early, it \"steals\" work from the tail of another core''s queue.\n*   **Fork-Join**: You don''t manage threads. You say \"Do this in parallel\", and Rayon manages the execution graph.\n\n## Parallel Iterators\nSimply change `.iter()` to `.par_iter()`. Most adapters (`map`, `filter`, `reduce`) work identically but run in parallel.", "ES": "# Tareas CPU Bound\nAsync es para I/O. Para c\u00e1lculo pesado, usa **Rayon**.\n\n## Estrategia Work Stealing\nRayon usa un pool global. `par_iter()` rompe tu colecci\u00f3n en trozos.\n*   **Adaptativo**: Si un n\u00facleo acaba r\u00e1pido, \"roba\" trabajo de otro.\n*   **Fork-Join**: No gestionas hilos. Rayon gestiona el grafo de ejecuci\u00f3n.\n\n## Iteradores Paralelos\nCambia `.iter()` a `.par_iter()`. La mayor\u00eda de adaptadores funcionan id\u00e9ntico pero en paralelo."}', false, NULL, NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!(\"Rayon handles splitting and joining automatically\");\n}', NULL, E'// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, E'// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, E'// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!(\"Rayon handles splitting and joining automatically\");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!(\"Rayon handles splitting and joining automatically\");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!("Rayon handles splitting and joining automatically");\n}', NULL, '// use rayon::prelude::*;\nfn main() {\n    let arr = [1, 2, 3, 4, 5];\n    \n    // Sum of squares in parallel\n    // let sum: i32 = arr.par_iter()\n    //                   .map(|&x| x * x)\n    //                   .sum();\n    \n    println!(\"Rayon handles splitting and joining automatically\");\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('d9b4bbc6-5f75-5bd7-8d9a-71a0be611311', '22370ebf-248d-52dd-ba4d-b654b4b69377', '{"EN": "Atomic Memory Ordering", "ES": "Ordenamiento de Memoria At\u00f3mica"}', '{"EN": "# Synchronization without Locks\nAtomics allow modifying data from multiple threads without Mutexes using hardware instructions (CAS).\nThe challenge is **Memory Ordering**: telling the CPU/Compiler how to order instructions.\n\n## The Orderings\n1.  **Relaxed**: No synchronization. Only guarantees this specific operation is atomic. No guarantees on other reads/writes. (Use for: global counters).\n2.  **Acquire/Release**: Used for locks.\n    *   **Release** (Write): Ensures all previous writes in this thread are visible before this store.\n    *   **Acquire** (Read): Ensures all subsequent reads in this thread happen after this load.\n    *   This creates a \"Happens-Before\" relationship between threads.\n3.  **SeqCst (Sequentially Consistent)**: Strongest. Guarantees a total global order of operations observed by all threads. Expensive.\n\n## Example: Mutex\nA Mutex essentially uses an Atomic Bool.\n*   Lock: `compare_exchange(..., Acquire)`.\n*   Unlock: `store(..., Release)`.\nThis guarantees that all data writes inside the Critical Section (before unlock) are visible to the next thread (after lock).", "ES": "# Sincronizaci\u00f3n sin Locks\nAt\u00f3micos usan instrucciones de hardware (CAS). El reto es el **Ordenamiento de Memoria**.\n\n## Los Ordenamientos\n1.  **Relaxed**: Sin sincronizaci\u00f3n. Solo at\u00f3mico en s\u00ed mismo. (Uso: contadores).\n2.  **Acquire/Release**: Para locks.\n    *   **Release** (Escribir): Asegura que escrituras previas sean visibles.\n    *   **Acquire** (Leer): Asegura que lecturas posteriores pasen despu\u00e9s.\n    *   Crea relaci\u00f3n \"Sucede-Antes\".\n3.  **SeqCst**: El m\u00e1s fuerte. Orden global total. Costoso.\n\n## Ejemplo: Mutex\nUsa un Bool At\u00f3mico.\n*   Lock: `Acquire`.\n*   Unlock: `Release`.\nGarantiza que escrituras en la secci\u00f3n cr\u00edtica sean visibles al siguiente hilo."}', false, NULL, NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, E'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, E'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, E'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', NULL, 'use std::sync::atomic::{AtomicBool, Ordering};\nuse std::sync::Arc;\n\nfn main() {\n    let lock = Arc::new(AtomicBool::new(false));\n    \n    // Try to acquire lock\n    // compare_exchange(current, new, success_order, failure_order)\n    let won_lock = lock.compare_exchange(\n        false, true, \n        Ordering::Acquire, \n        Ordering::Relaxed\n    ).is_ok();\n    \n    if won_lock {\n        // Critical Section\n        // ...\n        \n        // Release\n        lock.store(false, Ordering::Release);\n    }\n}', 2);
