INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('3c93e87b-5351-5daf-8983-dda32c962697', 'rust-serialization', '{"EN": "Mastering Serialization: Serde", "ES": "Dominando la Serializaci\u00f3n: Serde"}', '{"EN": "The ultimate guide to data formats in Rust. JSON, Bincode, Zero-Copy (rkyv), and advanced Serde attribute patterns.", "ES": "La gu\u00eda definitiva de formatos de datos en Rust. JSON, Bincode, Zero-Copy (rkyv) y patrones avanzados de atributos Serde."}', 'Intermediate', 'https://placehold.co/800x500/A33322/FFFFFF/png?text=Serde+Mastery&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('24116de7-a947-5c59-a443-0f2b25f49b5e', '3c93e87b-5351-5daf-8983-dda32c962697', '{"EN": "1. Serde Foundations", "ES": "1. Fundamentos de Serde"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('277dc9a0-dc76-5ddf-a03d-3b5dc8df6bd2', '24116de7-a947-5c59-a443-0f2b25f49b5e', '{"EN": "Serialize & Deserialize Traits", "ES": "Traits Serialize y Deserialize"}', '{"EN": "# Serde: Serialize and Deserialize\n\nSerde (SERializing and DEserializing) is a framework for efficiently and generically serializing Rust data structures.\n\n## The Design\nUnlike other languages that use runtime reflection (like Java or Go), Serde uses Rust''s **Trait system** and **Macros** to generate serialization code at *compile time*. This means:\n1.  **Zero-Overhead**: The generated code is as fast as hand-written code.\n2.  **Format Agnostic**: The data structure doesn''t care if it''s being turned into JSON, YAML, or Bincode.\n\n## The Traits\nTo make a struct serializable, we derive the traits:\n```rust\nuse serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct User {\n    username: String,\n    level: u32,\n}\n```\n\n## serde_json\nThe most common format is JSON. We use `serde_json::to_string` to serialize and `serde_json::from_str` to deserialize.", "ES": "# Serde: Serializar y Deserializar\n\nSerde es un framework para serializar estructuras de datos de Rust de manera eficiente y gen\u00e9rica.\n\n## El Dise\u00f1o\nA diferencia de lenguajes que usan reflexi\u00f3n en runtime (como Java o Go), Serde usa el **sistema de Traits** de Rust y **Macros** para generar c\u00f3digo en *tiempo de compilaci\u00f3n*. Esto significa:\n1.  **Cero Sobrecarga**: El c\u00f3digo generado es tan r\u00e1pido como el escrito a mano.\n2.  **Agn\u00f3stico del Formato**: A la estructura no le importa si se convierte en JSON, YAML o Bincode.\n\n## Los Traits\nPara hacer un struct serializable, derivamos los traits:\n```rust\nuse serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct User {\n    username: String,\n    level: u32,\n}\n```\n\n## serde_json\nEl formato m\u00e1s com\u00fan es JSON. Usamos `serde_json::to_string` para serializar y `serde_json::from_str` para deserializar."}', false, NULL, NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from(\"Rustacean\"),\n        score: 1000,\n        items: vec![\"Sword\".to_string(), \"Shield\".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!(\"JSON: {}\", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!(\"Struct: {:?}\", p2);\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from(\"Rustacean\"),\n        score: 1000,\n        items: vec![\"Sword\".to_string(), \"Shield\".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!(\"JSON: {}\", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!(\"Struct: {:?}\", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from(\"Rustacean\"),\n        score: 1000,\n        items: vec![\"Sword\".to_string(), \"Shield\".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!(\"JSON: {}\", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!(\"Struct: {:?}\", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from("Rustacean"),\n        score: 1000,\n        items: vec!["Sword".to_string(), "Shield".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!("JSON: {}", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!("Struct: {:?}", p2);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Player {\n    name: String,\n    score: i32,\n    items: Vec<String>,\n}\n\nfn main() {\n    let p1 = Player {\n        name: String::from(\"Rustacean\"),\n        score: 1000,\n        items: vec![\"Sword\".to_string(), \"Shield\".to_string()],\n    };\n\n    // Serialize to JSON String\n    let json = serde_json::to_string(&p1).unwrap();\n    println!(\"JSON: {}\", json);\n\n    // Deserialize back to Struct\n    let p2: Player = serde_json::from_str(&json).unwrap();\n    println!(\"Struct: {:?}\", p2);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('db2917fc-befa-539e-8af5-479f5330fb7b', '24116de7-a947-5c59-a443-0f2b25f49b5e', '{"EN": "Working with Unstructured Data", "ES": "Trabajando con Datos No Estructurados"}', '{"EN": "# The serde_json::Value Type\n\nSometimes you receive JSON data where you don''t know the structure ahead of time, or you simply don''t want to define a Struct for it. For this, Serde provides the `Value` enum.\n\n## The Value Enum\nIt represents any valid JSON data:\n*   `Value::Null`\n*   `Value::Bool(bool)`\n*   `Value::Number(Number)`\n*   `Value::String(String)`\n*   `Value::Array(Vec<Value>)`\n*   `Value::Object(Map<String, Value>)`\n\n## The json! Macro\nYou can create arbitrary JSON literals inside your Rust code using the `json!` macro. This is very useful for constructing payloads for APIs dynamically.", "ES": "# El Tipo serde_json::Value\n\nA veces recibes datos JSON donde no conoces la estructura de antemano, o simplemente no quieres definir un Struct para ello. Para esto, Serde provee el enum `Value`.\n\n## El Enum Value\nRepresenta cualquier dato JSON v\u00e1lido:\n*   `Value::Null`\n*   `Value::Bool(bool)`\n*   `Value::Number(Number)`\n*   `Value::String(String)`\n*   `Value::Array(Vec<Value>)`\n*   `Value::Object(Map<String, Value>)`\n\n## La Macro json!\nPuedes crear literales JSON arbitrarios dentro de tu c\u00f3digo Rust usando la macro `json!`. Esto es muy \u00fatil para construir payloads para APIs din\u00e1micamente."}', false, NULL, NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        "status": "ok",\n        "code": 200,\n        "payload": {\n            "features": ["fast", "safe"],\n            "users": null\n        }\n    });\n\n    println!("Created JSON: {}", data);\n\n    // Accessing fields dynamically\n    let feature = data["payload"]["features"][0].as_str().unwrap();\n    println!("First feature: {}", feature);\n    \n    // Parsing unknown JSON\n    let raw = r#"{"name": "Unknown", "age": 99}"#;\n    let v: Value = serde_json::from_str(raw).unwrap();\n    println!("Parsed Name: {}", v["name"]);\n}', NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        "status": "ok",\n        "code": 200,\n        "payload": {\n            "features": ["fast", "safe"],\n            "users": null\n        }\n    });\n\n    println!("Created JSON: {}", data);\n\n    // Accessing fields dynamically\n    let feature = data["payload"]["features"][0].as_str().unwrap();\n    println!("First feature: {}", feature);\n    \n    // Parsing unknown JSON\n    let raw = r#"{"name": "Unknown", "age": 99}"#;\n    let v: Value = serde_json::from_str(raw).unwrap();\n    println!("Parsed Name: {}", v["name"]);\n}', NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        "status": "ok",\n        "code": 200,\n        "payload": {\n            "features": ["fast", "safe"],\n            "users": null\n        }\n    });\n\n    println!("Created JSON: {}", data);\n\n    // Accessing fields dynamically\n    let feature = data["payload"]["features"][0].as_str().unwrap();\n    println!("First feature: {}", feature);\n    \n    // Parsing unknown JSON\n    let raw = r#"{"name": "Unknown", "age": 99}"#;\n    let v: Value = serde_json::from_str(raw).unwrap();\n    println!("Parsed Name: {}", v["name"]);\n}', NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        "status": "ok",\n        "code": 200,\n        "payload": {\n            "features": ["fast", "safe"],\n            "users": null\n        }\n    });\n\n    println!("Created JSON: {}", data);\n\n    // Accessing fields dynamically\n    let feature = data["payload"]["features"][0].as_str().unwrap();\n    println!("First feature: {}", feature);\n    \n    // Parsing unknown JSON\n    let raw = r#"{"name": "Unknown", "age": 99}"#;\n    let v: Value = serde_json::from_str(raw).unwrap();\n    println!("Parsed Name: {}", v["name"]);\n}', NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        "status": "ok",\n        "code": 200,\n        "payload": {\n            "features": ["fast", "safe"],\n            "users": null\n        }\n    });\n\n    println!("Created JSON: {}", data);\n\n    // Accessing fields dynamically\n    let feature = data["payload"]["features"][0].as_str().unwrap();\n    println!("First feature: {}", feature);\n    \n    // Parsing unknown JSON\n    let raw = r#"{"name": "Unknown", "age": 99}"#;\n    let v: Value = serde_json::from_str(raw).unwrap();\n    println!("Parsed Name: {}", v["name"]);\n}', NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        "status": "ok",\n        "code": 200,\n        "payload": {\n            "features": ["fast", "safe"],\n            "users": null\n        }\n    });\n\n    println!("Created JSON: {}", data);\n\n    // Accessing fields dynamically\n    let feature = data["payload"]["features"][0].as_str().unwrap();\n    println!("First feature: {}", feature);\n    \n    // Parsing unknown JSON\n    let raw = r#"{"name": "Unknown", "age": 99}"#;\n    let v: Value = serde_json::from_str(raw).unwrap();\n    println!("Parsed Name: {}", v["name"]);\n}', NULL, 'use serde_json::{json, Value};\n\nfn main() {\n    // Constructing dynamic JSON\n    let data = json!({\n        \"status\": \"ok\",\n        \"code\": 200,\n        \"payload\": {\n            \"features\": [\"fast\", \"safe\"],\n            \"users\": null\n        }\n    });\n\n    println!(\"Created JSON: {}\", data);\n\n    // Accessing fields dynamically\n    let feature = data[\"payload\"][\"features\"][0].as_str().unwrap();\n    println!(\"First feature: {}\", feature);\n    \n   