INSERT INTO modules (id, course_id, title, "order") VALUES ('d66027d7-af6d-558a-aad1-5e8caf8ba868', '3c93e87b-5351-5daf-8983-dda32c962697', '{"EN": "2. Attributes & Customization", "ES": "2. Atributos y Personalizaci\u00f3n"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('b91c9493-4742-5c3c-854f-1e35f5ce963a', 'd66027d7-af6d-558a-aad1-5e8caf8ba868', '{"EN": "Renaming & Defaults", "ES": "Renombrado y Valores por Defecto"}', '{"EN": "# Serde Attributes\n\nRarely does your Rust struct match an external API 1:1. Rust uses `snake_case`, while APIs often use `camelCase`. Rust fields must exist, while API fields might be missing. We control this using `#[serde(...)]` attributes.\n\n## Renaming\n*   `#[serde(rename = \"name\")]`: Renames a specific field.\n*   `#[serde(rename_all = \"camelCase\")]`: Automatically renames all fields in the struct.\n\n## Default Values\n*   `#[serde(default)]`: If the field is missing in the JSON, use the `Default::default()` value for that type.\n*   `#[serde(skip_serializing)]`: Hides a field from the output.\n*   `#[serde(skip_deserializing)]`: Ignores a field from the input.", "ES": "# Atributos de Serde\n\nRaramente tu struct de Rust coincide 1:1 con una API externa. Rust usa `snake_case`, mientras las APIs a menudo usan `camelCase`. Los campos de Rust deben existir, mientras los de la API pueden faltar. Controlamos esto usando atributos `#[serde(...)]`.\n\n## Renombrado\n*   `#[serde(rename = \"nombre\")]`: Renombra un campo espec\u00edfico.\n*   `#[serde(rename_all = \"camelCase\")]`: Renombra autom\u00e1ticamente todos los campos del struct.\n\n## Valores por Defecto\n*   `#[serde(default)]`: Si el campo falta en el JSON, usa el valor `Default::default()` para ese tipo.\n*   `#[serde(skip_serializing)]`: Oculta un campo de la salida.\n*   `#[serde(skip_deserializing)]`: Ignora un campo de la entrada."}', false, NULL, NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(rename_all = "camelCase")] // Converts first_name -> firstName\nstruct UserConfig {\n    first_name: String,\n    \n    #[serde(rename = "lname")] // Manual override\n    last_name: String,\n    \n    #[serde(default)] // Use false if missing\n    is_admin: bool,\n    \n    #[serde(skip_serializing)] // Secret, never export\n    password_hash: String,\n}\n\nfn main() {\n    let json_input = r#"{\n        "firstName": "Alice",\n        "lname": "Smith"\n    }"#;\n    \n    let user: UserConfig = serde_json::from_str(json_input).unwrap();\n    println!("Deserialized: {:?}", user);\n    // Notice is_admin is false (default)\n    \n    let json_output = serde_json::to_string(&user).unwrap();\n    println!("Serialized: {}", json_output);\n    // Notice password_hash is missing\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(rename_all = "camelCase")] // Converts first_name -> firstName\nstruct UserConfig {\n    first_name: String,\n    \n    #[serde(rename = "lname")] // Manual override\n    last_name: String,\n    \n    #[serde(default)] // Use false if missing\n    is_admin: bool,\n    \n    #[serde(skip_serializing)] // Secret, never export\n    password_hash: String,\n}\n\nfn main() {\n    let json_input = r#"{\n        "firstName": "Alice",\n        "lname": "Smith"\n    }"#;\n    \n    let user: UserConfig = serde_json::from_str(json_input).unwrap();\n    println!("Deserialized: {:?}", user);\n    // Notice is_admin is false (default)\n    \n    let json_output = serde_json::to_string(&user).unwrap();\n    println!("Serialized: {}", json_output);\n    // Notice password_hash is missing\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(rename_all = "camelCase")] // Converts first_name -> firstName\nstruct UserConfig {\n    first_name: String,\n    \n    #[serde(rename = "lname")] // Manual override\n    last_name: String,\n    \n    #[serde(default)] // Use false if missing\n    is_admin: bool,\n    \n    #[serde(skip_serializing)] // Secret, never export\n    password_hash: String,\n}\n\nfn main() {\n    let json_input = r#"{\n        "firstName": "Alice",\n        "lname": "Smith"\n    }"#;\n    \n    let user: UserConfig = serde_json::from_str(json_input).unwrap();\n    println!("Deserialized: {:?}", user);\n    // Notice is_admin is false (default)\n    \n    let json_output = serde_json::to_string(&user).unwrap();\n    println!("Serialized: {}", json_output);\n    // Notice password_hash is missing\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(rename_all = "camelCase")] // Converts first_name -> firstName\nstruct UserConfig {\n    first_name: String,\n    \n    #[serde(rename = "lname")] // Manual override\n    last_name: String,\n    \n    #[serde(default)] // Use false if missing\n    is_admin: bool,\n    \n    #[serde(skip_serializing)] // Secret, never export\n    password_hash: String,\n}\n\nfn main() {\n    let json_input = r#"{\n        "firstName": "Alice",\n        "lname": "Smith"\n    }"#;\n    \n    let user: UserConfig = serde_json::from_str(json_input).unwrap();\n    println!("Deserialized: {:?}", user);\n    // Notice is_admin is false (default)\n    \n    let json_output = serde_json::to_string(&user).unwrap();\n    println!("Serialized: {}", json_output);\n    // Notice password_hash is missing\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(rename_all = "camelCase")] // Converts first_name -> firstName\nstruct UserConfig {\n    first_name: String,\n    \n    #[serde(rename = "lname")] // Manual override\n    last_name: String,\n    \n    #[serde(default)] // Use false if missing\n    is_admin: bool,\n    \n    #[serde(skip_serializing)] // Secret, never export\n    password_hash: String,\n}\n\nfn main() {\n    let json_input = r#"{\n        "firstName": "Alice",\n        "lname": "Smith"\n    }"#;\n    \n    let user: UserConfig = serde_json::from_str(json_input).unwrap();\n    println!("Deserialized: {:?}", user);\n    // Notice is_admin is false (default)\n    \n    let json_output = serde_