g)]\n#[serde(rename_all = \"camelCase\")] // Converts first_name -> firstName\nstruct UserConfig {\n    first_name: String,\n    \n    #[serde(rename = \"lname\")] // Manual override\n    last_name: String,\n    \n    #[serde(default)] // Use false if missing\n    is_admin: bool,\n    \n    #[serde(skip_serializing)] // Secret, never export\n    password_hash: String,\n}\n\nfn main() {\n    let json_input = r#\"{\n        \"firstName\": \"Alice\",\n        \"lname\": \"Smith\"\n    }\"#;\n    \n    let user: UserConfig = serde_json::from_str(json_input).unwrap();\n    println!(\"Deserialized: {:?}\", user);\n    // Notice is_admin is false (default)\n    \n    let json_output = serde_json::to_string(&user).unwrap();\n    println!(\"Serialized: {}\", json_output);\n    // Notice password_hash is missing\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('d0cd9b44-7adf-5e14-a4e1-c5047a8f959d', 'd66027d7-af6d-558a-aad1-5e8caf8ba868', '{"EN": "Flattening Structs", "ES": "Aplanando Estructuras (Flatten)"}', '{"EN": "# The Flatten Attribute\n\nSometimes you have a nested Rust struct for logical organization (composition), but the JSON you need to generate (or parse) is flat.\n\n## `#[serde(flatten)]`\nThis attribute inlines the keys of the nested struct into the parent struct during serialization.\n\n**Example Scenario**:\nYou have a `Pagination` struct with `page` and `limit`. You have a `Request` struct. Instead of `{\"pagination\": {\"page\": 1}}`, you want `{\"page\": 1, ...}`.", "ES": "# El Atributo Flatten\n\nA veces tienes un struct anidado en Rust para organizaci\u00f3n l\u00f3gica (composici\u00f3n), pero el JSON que necesitas generar (o leer) es plano.\n\n## `#[serde(flatten)]`\nEste atributo alinea (inlines) las claves del struct anidado dentro del struct padre durante la serializaci\u00f3n.\n\n**Escenario de Ejemplo**:\nTienes un struct `Pagination` con `page` y `limit`. Tienes un struct `Request`. En lugar de `{\"pagination\": {\"page\": 1}}`, quieres `{\"page\": 1, ...}`."}', false, NULL, NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''