 Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#"{\n        "filter": "active",\n        "page": 1,\n        "limit": 10,\n        "sort": "desc" \n    }"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#\"{\n        \"filter\": \"active\",\n        \"page\": 1,\n        \"limit\": 10,\n        \"sort\": \"desc\" \n    }\"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!(\"Struct: {:?}\", q);\n    // Notice \"sort\" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: Stri