uery = serde_json::from_str(raw).unwrap();\n    println!("Struct: {:?}", q);\n    // Notice "sort" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Pagination {\n    page: u32,\n    limit: u32,\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct UserQuery {\n    filter: String,\n    \n    #[serde(flatten)]\n    pagination: Pagination,\n    \n    // Capture any extra fields in a HashMap!\n    #[serde(flatten)]\n    extra: std::collections::HashMap<String, serde_json::Value>\n}\n\nfn main() {\n    let raw = r#\"{\n        \"filter\": \"active\",\n        \"page\": 1,\n        \"limit\": 10,\n        \"sort\": \"desc\" \n    }\"#;\n    \n    let q: UserQuery = serde_json::from_str(raw).unwrap();\n    println!(\"Struct: {:?}\", q);\n    // Notice \"sort\" ended up in the ''extra'' map\n    // Notice ''page'' and ''limit'' populated the inner Pagination struct\n}', 2);
INSERT INTO modules (id, course_id, title, "order") VALUES ('0ca90213-7c0c-5df9-8ac9-b0c73d89284a', '3c93e87b-5351-5daf-8983-dda32c962697', '{"EN": "3. Advanced Enum Patterns", "ES": "3. Patrones Avanzados de Enums"}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('12af1cb5-3866-587d-919a-b9f6acf84877', '0ca90213-7c0c-5df9-8ac9-b0c73d89284a', '{"EN": "Enum Representations (Tagging)", "ES": "Representaciones de Enum (Etiquetado)"}', '{"EN": "# Serializing Enums\n\nRust Enums can hold data. Representing this in JSON is tricky because JSON doesn''t have \"variants\". Serde offers 4 ways to tag enums.\n\n1.  **Externally Tagged** (Default): `{\"VariantName\": \"content\"}`.\n2.  **Internally Tagged**: `{\"type\": \"VariantName\", \"field\": \"content\"}`. Often used for polymorphic APIs.\n3.  **Adjacently Tagged**: `{\"t\": \"VariantName\", \"c\": \"content\"}`.\n4.  **Untagged**: Serde tries to match fields to variants one by one.\n\n## Internal Tagging\nThis is extremely popular for REST APIs where a `type` field determines the rest of the object structure.", "ES": "# Serializando Enums\n\nLos Enums de Rust pueden contener datos. Representar esto en JSON es dif\u00edcil porque JSON no tiene \"variantes\". Serde ofrece 4 formas de etiquetar enums.\n\n1.  **Externally Tagged** (Defecto): `{\"NombreVariante\": \"contenido\"}`.\n2.  **Internally Tagged**: `{\"type\": \"NombreVariante\", \"field\": \"contenido\"}`. A menudo usado para APIs polim\u00f3rficas.\n3.  **Adjacently Tagged**: `{\"t\": \"NombreVariante\", \"c\": \"contenido\"}`.\n4.  **Untagged**: Serde intenta coincidir campos con variantes uno por uno.\n\n## Etiquetado Interno\nEsto es extremadamente popular para APIs REST donde un campo `type` determina el resto de la estructura del objeto."}', false, NULL, NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = \"type\")] // Internal tagging\nenum Message {\n    #[serde(rename = \"text\")]\n    Text { content: String },\n    \n    #[serde(rename = \"image\")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: \"img.png\".into(), \n        width: 1024 \n    };\n    \n    // Output: {\"type\":\"image\",\"url\":\"img.png\",\"width\":1024}\n    println!(\"{}\", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#\"{\"type\": \"text\", \"content\": \"Hello!\"}\"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!(\"{:?}\", decoded);\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, E'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = \"type\")] // Internal tagging\nenum Message {\n    #[serde(rename = \"text\")]\n    Text { content: String },\n    \n    #[serde(rename = \"image\")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: \"img.png\".into(), \n        width: 1024 \n    };\n    \n    // Output: {\"type\":\"image\",\"url\":\"img.png\",\"width\":1024}\n    println!(\"{}\", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#\"{\"type\": \"text\", \"content\": \"Hello!\"}\"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!(\"{:?}\", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = \"type\")] // Internal tagging\nenum Message {\n    #[serde(rename = \"text\")]\n    Text { content: String },\n    \n    #[serde(rename = \"image\")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: \"img.png\".into(), \n        width: 1024 \n    };\n    \n    // Output: {\"type\":\"image\",\"url\":\"img.png\",\"width\":1024}\n    println!(\"{}\", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#\"{\"type\": \"text\", \"content\": \"Hello!\"}\"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!(\"{:?}\", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = "type")] // Internal tagging\nenum Message {\n    #[serde(rename = "text")]\n    Text { content: String },\n    \n    #[serde(rename = "image")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: "img.png".into(), \n        width: 1024 \n    };\n    \n    // Output: {"type":"image","url":"img.png","width":1024}\n    println!("{}", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#"{"type": "text", "content": "Hello!"}"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!("{:?}", decoded);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\n#[serde(tag = \"type\")] // Internal tagging\nenum Message {\n    #[serde(rename = \"text\")]\n    Text { content: String },\n    \n    #[serde(rename = \"image\")]\n    Image { url: String, width: u32 },\n}\n\nfn main() {\n    let msg = Message::Image { \n        url: \"img.png\".into(), \n        width: 1024 \n    };\n    \n    // Output: {\"type\":\"image\",\"url\":\"img.png\",\"width\":1024}\n    println!(\"{}\", serde_json::to_string(&msg).unwrap());\n    \n    let json = r#\"{\"type\": \"text\", \"content\": \"Hello!\"}\"#;\n    let decoded: Message = serde_json::from_str(json).unwrap();\n    println!(\"{:?}\", decoded);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('0755406c-ef88-57c1-8326-491f4c8685d4', '0ca90213-7c0c-5df9-8ac9-b0c73d89284a', '{"EN": "Custom Serialization", "ES": "Serializaci\u00f3n Personalizada"}', '{"EN": "# Custom Serializers\n\nSometimes `derive` isn''t enough. You might want to serialize a `DateTime` as a Unix timestamp number, or specialized formatting.\n\nTo do this, you can manually implement `Serialize` and `Deserialize`, OR simpler: use `#[serde(with = \"module\")]`.\n\n## Field-level Customization\nYou can write a function that matches the Serde signature and tell Serde to use it for a specific field.", "ES": "# Serializadores Personalizados\n\nA veces `derive` no es suficiente. Podr\u00edas querer serializar un `DateTime` como un n\u00famero timestamp Unix, o formateo especializado.\n\nPara hacer esto, puedes implementar manualmente `Serialize` y `Deserialize`, O m\u00e1s simple: usar `#[serde(with = \"modulo\")]`.\n\n## Personalizaci\u00f3n a Nivel de Campo\nPuedes escribir una funci\u00f3n que coincida con la firma de Serde y decirle que la use para un campo espec\u00edfico."}', false, NULL, NULL, 'use serde::{Serialize, Serializer, Deserialize, Deserializer};\n\nfn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>\nwhere S: Serializer {\n    serializer.serialize_str(&val.to_string())\n}\n\nfn deserialize_from_string<''de, D>(deserializer: D) -> Result<i32, D::Error>\nwhere D: Deserializer<''de> {\n    let s: String = Deserialize::deserialize(deserializer)?;\n    s.parse().map_err(serde::de::Error::custom)\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Data {\n    // Treat this int as a string in JSON\n    #[serde(serialize_with = "serialize_as_string")]\n    #[serde(deserialize_with = "deserialize_from_string")]\n    number: i32,\n}\n\nfn main() {\n    let d = Data { number: 42 };\n    let json = serde_json::to_string(&d).unwrap();\n    \n    // Output: {"number":"42"} (it''s a string!)\n    println!("{}", json);\n}', NULL, 'use serde::{Serialize, Serializer, Deserialize, Deserializer};\n\nfn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>\nwhere S: Serializer {\n    serializer.serialize_str(&val.to_string())\n}\n\nfn deserialize_from_string<''de, D>(deserializer: D) -> Result<i32, D::Error>\nwhere D: Deserializer<''de> {\n    let s: String = Deserialize::deserialize(deserializer)?;\n    s.parse().map_err(serde::de::Error::custom)\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Data {\n    // Treat this int as a string in JSON\n    #[serde(serialize_with = "serialize_as_string")]\n    #[serde(deserialize_with = "deserialize_from_string")]\n    number: i32,\n}\n\nfn main() {\n    let d = Data { number: 42 };\n    let json = serde_json::to_string(&d).unwrap();\n    \n    // Output: {"number":"42"} (it''s a string!)\n    println!("{}", json);\n}', NULL, 'use serde::{Serialize, Serializer, Deserialize, Deserializer};\n\nfn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>\nwhere S: Serializer {\n    serializer.serialize_str(&val.to_string())\n}\n\nfn deserialize_from_string<''de, D>(deserializer: D) -> Result<i32, D::Error>\nwhere D: Deserializer<''de> {\n    let s: String = Deserialize::deserialize(deserializer)?;\n    s.parse().map_err(serde::de::Error::custom)\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Data {\n    // Treat this int as a string in JSON\n    #[serde(serialize_with = "serialize_as_string")]\n    #[serde(deserialize_with = "deserialize_from_string")]\n    number: i32,\n}\n\nfn main() {\n    let d = Data { number: 42 };\n    let json = serde_json::to_string(&d).unwrap();\n    \n    // Output: {"number":"42"} (it''s a string!)\n    println!("{}", json);\n}', NULL, 'use serde::{Serialize, Serializer, Deserialize, Deserializer};\n\nfn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>\nwhere S: Serializer {\n    serializer.serialize_str(&val.to_string())\n}\n\nfn deserialize_from_string<''de, D>(deserializer: D) -> Result<i32, D::Error>\nwhere D: Deserializer<''de> {\n    let s: String = Deserialize::deserialize(deserializer)?;\n    s.parse().map_err(serde::de::Error::custom)\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Data {\n    // Treat this int as a string in JSON\n    #[serde(serialize_with = "serialize_as_string")]\n    #[serde(deserialize_with = "deserialize_from_string")]\n    number: i32,\n}\n\nfn main() {\n    let d = Data { number: 42 };\n    let json = serde_json::to_string(&d).unwrap();\n    \n    // Output: {"number":"42"} (it''s a string!)\n    println!("{}", json);\n}', NULL, 'use serde::{Serialize, Serializer, Deserialize, Deserializer};\n\nfn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>\nwhere S: Serializer {\n    serializer.serialize_str(&val.to_string())\n}\n\nfn deserialize_from_string<''de, D>(deserializer: D) -> Result<i32, D::Error>\nwhere D: Deserializer<''de> {\n    let s: String = Deserialize::deserialize(deserializer)?;\n    s.parse().map_err(serde::de::Error::custom)\n}\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct Data {\n    // Treat this int as a string in JSON\n    #[serde(serialize_with = "serialize_as_string")]\n    #[serde(deserialize_with = "deserialize_from_string")]\n    number: i32,\n}\n\nfn main() {\n    let d = Data { number: 42 };\n    let json = serde_json::to_string(&d).unwrap();\n    \n    // Output: {"number":"42"} (it''s a string!)\n    println!("{}", json);\n}', NULL, 'use serde::{Serialize, Serializer, Deserialize, Deserializer};\n\nfn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>\nwhere S: Serializer {\n    serializer.serialize_str(&val.to_string())\n}\n\nfn deserialize_from_string<''de, D>(deserializer: D) -> Result<i32, D::Error>\nwhere D: Deserializer<''de> {\n    let s: String = Deserialize::deserialize(deserializer)?;\n    s.parse().map_err(serde::de::Error: