INSERT INTO modules (id, course_id, title, "order") VALUES ('531c6c76-4b1e-59c7-a924-8a74b81fa7b8', '3c93e87b-5351-5daf-8983-dda32c962697', '{"EN": "4. Binary & Zero-Copy", "ES": "4. Formatos Binarios y Zero-Copy"}', 4);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('cfbb6d50-83c9-5351-ba21-3e7d053d8082', '531c6c76-4b1e-59c7-a924-8a74b81fa7b8', '{"EN": "Binary Formats: Bincode", "ES": "Formatos Binarios: Bincode"}', '{"EN": "# Why Binary?\n\nJSON is human-readable but slow to parse and large in size. For internal communication (e.g., between microservices or saving games), binary formats are superior.\n\n## Bincode\nBincode is a compact encoder/decoder for Rust types. It works natively with Serde.\n*   **Pros**: Extremely small size, extremely fast.\n*   **Cons**: Not self-describing. You need the exact same Rust struct definition on both sides to decode it properly.\n\nNote: In the playground, we can''t write binary files to disk, but we can see the byte array.", "ES": "# \u00bfPor qu\u00e9 Binario?\n\nJSON es legible por humanos pero lento de analizar y grande en tama\u00f1o. Para comunicaci\u00f3n interna (ej. entre microservicios o guardar juegos), los formatos binarios son superiores.\n\n## Bincode\nBincode es un codificador/decodificador compacto para tipos Rust. Funciona nativamente con Serde.\n*   **Pros**: Tama\u00f1o extremadamente peque\u00f1o, extremadamente r\u00e1pido.\n*   **Contras**: No se auto-describe. Necesitas la definici\u00f3n exacta del struct de Rust en ambos lados para decodificarlo.\n\nNota: En el playground no podemos escribir archivos binarios al disco, pero podemos ver el array de bytes."}', false, NULL, NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!("Serialized to {} bytes", bytes.len());\n    println!("Raw bytes: {:?}", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!("Serialized to {} bytes", bytes.len());\n    println!("Raw bytes: {:?}", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!("Serialized to {} bytes", bytes.len());\n    println!("Raw bytes: {:?}", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debu