bytes.len());\n    println!("Raw bytes: {:?}", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!(\"Serialized to {} bytes\", bytes.len());\n    println!(\"Raw bytes: {:?}\", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!("Serialized to {} bytes", bytes.len());\n    println!("Raw bytes: {:?}", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!(\"Serialized to {} bytes\", bytes.len());\n    println!(\"Raw bytes: {:?}\", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!("Serialized to {} bytes", bytes.len());\n    println!("Raw bytes: {:?}", bytes);\n}', NULL, 'use serde::{Serialize, Deserialize};\n\n// Mocking bincode for playground\nmod bincode {\n    use serde::{Serialize, Deserialize};\n    pub fn serialize<T: Serialize>(t: &T) -> Result<Vec<u8>, ()> {\n        // Simulating binary output (usually this uses the bincode crate)\n        Ok(vec![1, 0, 0, 0]) \n    }\n}\n\n#[derive(Serialize, Deserialize, PartialEq, Debug)]\nstruct Packet {\n    id: u32,\n    payload: Vec<u8>,\n}\n\nfn main() {\n    let p = Packet { id: 1, payload: vec![10, 20, 30] };\n    \n    // In real Rust: bincode::serialize(&p)\n    let bytes = bincode::serialize(&p).unwrap();\n    \n    println!(\"Serialized to {} bytes\", bytes.len());\n    println!(\"Raw bytes: {:?}\", bytes);\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('d7c7b837-f4d8-535b-bb94-2edd3dcd216f', '531c6c76-4b1e-59c7-a924-8a74b81fa7b8', '{"EN": "Zero-Copy with rkyv", "ES": "Zero-Copy con rkyv"}', '{"EN": "# Beyond Serde: rkyv\n\nSerde always deserializes into a *new* Rust struct. This involves allocating memory on the heap and copying data. For high-performance systems (game engines, databases), this copy is too slow.\n\n## Zero-Copy Deserialization\n**rkyv** (Archive) is a serialization framework that guarantees data representation in memory is the same as on disk.\n*   You don''t \"deserialize\" (parse). You just cast the pointer to the raw bytes.\n*   Instant access to data.\n*   Ideal for caching, mmap-ed files, and IPC.\n\nThis is technically not Serde, but it is the next step in the serialization evolution for Rust.", "ES": "# M\u00e1s all\u00e1 de Serde: rkyv\n\nSerde siempre deserializa en un *nuevo* struct de Rust. Esto involucra asignar memoria en el heap y copiar datos. Para sistemas de alto rendimiento (motores de juego, BDs), esta copia es muy lenta.\n\n## Deserializaci\u00f3n Zero-Copy (Copia Cero)\n**rkyv** (Archive) es un framework que garantiza que la representaci\u00f3n de datos en memoria sea la misma que en disco.\n*   No \"deserializas\" (parseas). Solo casteas el puntero a los bytes crudos.\n*   Acceso instant\u00e1neo a datos.\n*   Ideal para cach\u00e9, archivos mmap, e IPC.\n\nEsto t\u00e9cnicamente no es Serde, pero es el siguiente paso en la evoluci\u00f3n de serializaci\u00f3n para Rust."}', false, NULL, NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an \"Archived\" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!(\"rkyv enables accessing data directly from raw bytes.\");\n    println!(\"It skips the parsing step entirely.\");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!(\"Level: {}\", archived.level); // No allocation!\n}', NULL, E'// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, E'// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct G