cro to create an \"Archived\" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!(\"rkyv enables accessing data directly from raw bytes.\");\n    println!(\"It skips the parsing step entirely.\");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!(\"Level: {}\", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an \"Archived\" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!(\"rkyv enables accessing data directly from raw bytes.\");\n    println!(\"It skips the parsing step entirely.\");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!(\"Level: {}\", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an "Archived" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!("rkyv enables accessing data directly from raw bytes.");\n    println!("It skips the parsing step entirely.");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!("Level: {}", archived.level); // No allocation!\n}', NULL, '// rkyv uses a macro to create an \"Archived\" version of your struct\n// #[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]\nstruct GameState {\n    players: Vec<String>,\n    level: u32,\n}\n\nfn main() {\n    println!(\"rkyv enables accessing data directly from raw bytes.\");\n    println!(\"It skips the parsing step entirely.\");\n    \n    // Hypothetical usage:\n    // let archived = rkyv::check_archived_root::<GameState>(&bytes).unwrap();\n    // println!(\"Level: {}\", archived.level); // No allocation!\n}', 2);
INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('70fd81c3-844c-5700-b6cb-be4ee738e7a2', 'rust-macros', '{"EN": "Metaprogramming & Macros", "ES": "Metaprogramaci\u00f3n y Macros"}', '{"EN": "Master the art of code generation. From macro_rules! to advanced procedural macros using Syn and Quote.", "ES": "Domina el arte de la generaci\u00f3n de c\u00f3digo. Desde macro_rules! hasta macros procedimentales avanzadas usando Syn y Quote."}', 'Advanced', 'https://placehold.co/800x500/A020F0/FFFFFF/png?text=Rust+Macros&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('b0cb9712-539b-55d6-acd7-2ef7750812af', '70fd81c3-844c-5700-b6cb-be4ee738e7a2', '{"EN": "1. Declarative Macros", "ES": "1. Macros Declarativas"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('dc0815f1-d717-5295-abee-a0a82d55deaa', 'b0cb9712-539b-55d6-acd7-2ef7750812af', '{"EN": "Introduction to macro_rules!", "ES": "Introducci\u00f3n a macro_rules!"}', '{"EN": "# The Power of Metaprogramming\n\nMacros are code that writes other code. This is called **Metaprogramming**. In Rust, macros are distinct from functions:\n1.  **Time**: Macros expand at *compile time* (before the binary is built). Functions run at *runtime*.\n2.  **Args**: Functions accept specific types. Macros accept a stream of source code tokens.\n\n## Declarative Macros\nAlso known as \"macros by example\". They look like `match` expressions. You define a pattern, and if the input code matches that pattern, the macro replaces it with the code block you defined.\n\n## Syntax\n```rust\nmacro_rules! name {\n    (PATTERN) => { EXPANSION };\n}\n```\nWe use specific designators to match types of tokens:\n*   `$x:expr`: Matches an expression (e.g., `5 + 5`).\n*   `$x:ident`: Matches an identifier (variable name).\n*   `$x:ty`: Matches a Type.", "ES": "# El Poder de la Metaprogramaci\u00f3n\n\nLas macros son c\u00f3digo que escribe otro c\u00f3digo. Esto se llama **Metaprogramaci\u00f3n**. En Rust, son distintas a las funciones:\n1.  **Tiempo**: Las macros se expanden en *tiempo de compilaci\u00f3n* (antes de construir el binario). Las funciones corren en *runtime*.\n2.  **Argumentos**: Las funciones aceptan tipos espec\u00edficos. Las macros aceptan un flujo de tokens de c\u00f3digo fuente.\n\n## Macros Declarativas\nConocidas como \"macros por ejemplo\". Se parecen a expresiones `match`. Defines un patr\u00f3n, y si el c\u00f3digo de entrada coincide, la macro lo reemplaza con el bloque de c\u00f3digo definido.\n\n## Sintaxis\n```rust\nmacro_rules! nombre {\n    (PATRON) => { EXPANSION };\n}\n```\nUsamos designadores espec\u00edficos para coincidir tipos de tokens:\n*   `$x:expr`: Coincide con una expresi\u00f3n (ej. `5 + 5`).\n*   `$x:ident`: Coincide con un identificador (nombre de variable).\n*   `$x:ty`: Coincide con un Tipo."}', false, NULL, NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!(\"Hello!\");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!(\"Hello, {}!\", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!(\"Rustacean\");\n}', NULL, E'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, E'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, E'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!(\"Hello!\");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!(\"Hello, {}!\", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!(\"Rustacean\");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!(\"Hello!\");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!(\"Hello, {}!\", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!(\"Rustacean\");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!("Hello!");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!("Hello, {}!", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!("Rustacean");\n}', NULL, 'macro_rules! say_hello {\n    // Matches no arguments\n    () => {\n        println!(\"Hello!\");\n    };\n    // Matches one expression argument\n    ($name:expr) => {\n        println!(\"Hello, {}!\", $name);\n    };\n}\n\nfn main() {\n    say_hello!();\n    say_hello!(\"Rustacean\");\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('7912dc96-fefd-5405-9633-86e929db1b07', 'b0cb9712-539b-55d6-acd7-2ef7750812af', '{"EN": "Repetition & Hygiene", "ES": "Repetici\u00f3n e Higiene"}', '{"EN": "# Repetition\n        \nOften you want a macro to accept a variable number of arguments (like `vec![1, 2, 3]`).\nWe use the syntax `$(...)*` to indicate repetition.\n*   `$(...),*`: Repeat, separated by commas.\n*   `$(...);*`: Repeat, separated by semicolons.\n\n## Hygiene\nDeclarative macros in Rust are **partially hygienic**. This means strict rules prevent variable shadowing issues.\n*   A variable defined *inside* the macro usually cannot conflict with a variable defined *outside*.\n*   However, generic types and lifetimes can sometimes leak if not handled carefully.\n\n## Debugging\nTo see what your macro expands to, you can use the command:\n`cargo expand` (requires installing `cargo-expand`).", "ES": "# Repetici\u00f3n\n        \nA menudo quieres que una macro acepte un n\u00famero variable de argumentos (como `vec![1, 2, 3]`).\nUsamos la sintaxis `$(...)*` para indicar repetici\u00f3n.\n*   `$(...),*`: Repetir, separado por comas.\n*   `$(...);*`: Repetir, separado por punto y coma.\n\n## Higiene\nLas macros declarativas en Rust son **parcialmente higi\u00e9nicas**. Reglas estrictas previenen problemas de shadowing.\n*   Una variable definida *dentro* de la macro usualmente no puede entrar en conflicto con una *fuera*.\n*   Sin embargo, tipos gen\u00e9ricos y lifetimes pueden fugarse si no se tiene cuidado.\n\n## Debugging\nPara ver en qu\u00e9 se expande tu macro, usa el comando:\n`cargo expand` (requiere instalar `cargo-expand`)."}', false, NULL, NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        \"Blue\" => 10,\n        \"Red\" => 50,\n        \"Green\" => 20\n    );\n    \n    println!(\"Scores: {:?}\", scores);\n}', NULL, E'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, E'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, E'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        \"Blue\" => 10,\n        \"Red\" => 50,\n        \"Green\" => 20\n    );\n    \n    println!(\"Scores: {:?}\", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        \"Blue\" => 10,\n        \"Red\" => 50,\n        \"Green\" => 20\n    );\n    \n    println!(\"Scores: {:?}\", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        "Blue" => 10,\n        "Red" => 50,\n        "Green" => 20\n    );\n    \n    println!("Scores: {:?}", scores);\n}', NULL, 'macro_rules! create_map {\n    // Match keys ($k) and values ($v), separated by =>, \n    // and the whole pair separated by commas\n    ( $( $k:expr => $v:expr ),* ) => {\n        {\n            let mut map = std::collections::HashMap::new();\n            $(\n                map.insert($k, $v);\n            )*\n            map\n        }\n    };\n}\n\nfn main() {\n    let scores = create_map!(\n        \"Blue\" => 10,\n        \"Red\" => 50,\n        \"Green\" => 20\n    );\n    \n    println!(\"Scores: {:?}\", scores);\n}', 2);
