INSERT INTO modules (id, course_id, title, "order") VALUES ('ec52fcdb-46f8-5289-a434-f0d01828a624', '70fd81c3-844c-5700-b6cb-be4ee738e7a2', '{"EN": "2. Proc-Macros & Derive", "ES": "2. Proc-Macros y Derive"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('90b297e5-0ed8-57d3-8d57-bfe40ee20d46', 'ec52fcdb-46f8-5289-a434-f0d01828a624', '{"EN": "Procedural Macros Architecture", "ES": "Arquitectura de Macros Procedimentales"}', '{"EN": "# Procedural Macros\n\nUnlike declarative macros (which match patterns), procedural macros are functions that accept a **TokenStream** as input and return a new **TokenStream** as output. You are literally writing a compiler plugin.\n\n## The Architecture\n1.  **Separate Crate**: Proc-macros *must* live in their own crate with `proc-macro = true` in `Cargo.toml`.\n2.  **Input**: The source code (tokens) the macro is attached to.\n3.  **Output**: Valid Rust code (tokens) that replaces or augments the input.\n\n## The Holy Trinity\nTo write proc-macros effectively, we use three crates (referenced from developerlife.com):\n1.  **proc_macro** (std): The compiler''s interface types.\n2.  **syn**: Parses the TokenStream into a manipulatable AST (Abstract Syntax Tree).\n3.  **quote**: Generates TokenStreams efficiently using a macro syntax.", "ES": "# Macros Procedimentales\n\nA diferencia de las declarativas (que coinciden patrones), las macros procedimentales son funciones que aceptan un **TokenStream** de entrada y retornan un nuevo **TokenStream** de salida. Est\u00e1s escribiendo literalmente un plugin del compilador.\n\n## La Arquitectura\n1.  **Crate Separado**: Las proc-macros *deben* vivir en su propio crate con `proc-macro = true`.\n2.  **Entrada**: El c\u00f3digo fuente (tokens) al que se adjunta la macro.\n3.  **Salida**: C\u00f3digo Rust v\u00e1lido (tokens) que reemplaza o aumenta la entrada.\n\n## La Santa Trinidad\nPara escribir proc-macros efectivamente, usamos tres crates:\n1.  **proc_macro** (std): Tipos de interfaz del compilador.\n2.  **syn**: Parsea el TokenStream a un AST manipulable.\n3.  **quote**: Genera TokenStreams eficientemente."}', false, NULL, NULL, '// Example structure of a proc-macro lib.rs\n/*\nuse proc_macro::TokenStream;\nuse quote::quote;\nuse syn::{parse_macro_input, DeriveInput};\n\n#[proc_macro_derive(HelloMacro)]\npub fn hello_macro_derive(input: TokenStream) -> TokenStream {\n    // 1. Parse the input (The Struct)\n    let ast = parse_macro_input!(input as DeriveInput);\n\n    // 2. Generate code (impl HelloMacro for Struct...)\n    let gen = impl_hello_macro(&ast);\n\n    // 3. Return tokens\n    gen.into()\n}\n*/\n\nfn main() {\n    println!("Proc-macros require a separate crate type definition.");\n}', NULL, '// Example structure of a proc-macro lib.rs\n/*\nuse proc_macro::TokenStream;\nuse quote::quote;\nuse syn::{parse_macro_input, DeriveInput};\n\n#[proc_macro_derive(HelloMacro)]\npub fn hello_macro_derive(input: TokenStream) -> TokenStream {\n    // 1. Parse the input (The Struct)\n    let ast = parse_macro_input!(input as DeriveInput);\n\n    // 2. Generate code (impl HelloMacro for Struct...)\n    let gen = impl_hello_macro(&ast);\n\n    // 3. Return tokens\n    gen.into()\n}\n*/\n\nfn main() {\n    println!("Proc-macros require a separate crate type definition.");\n}', NULL, '// Example structure of a proc-macro lib.rs\n/*\nuse proc_macro::TokenStream;\nuse quote::quote;\nuse syn::{parse_macro_input, DeriveInput};\n\n#[proc_macro_derive(HelloMacro)]\npub fn hello_macro_derive(input: TokenStream) -> TokenStream {\n    // 1. Parse the input (The Struct)\n    let ast = parse_macro_input!(input as DeriveInput);\n\n    // 2. Generate code (impl HelloMacro for Struct...)\n    let gen = impl_hello_macro(&ast);\n\n    // 3. Return tokens\n    gen.into()\n}\n*/\n\nfn main() {\n    println!("Proc-macros require a separate crate type definition.");\n}', NULL, '// Example structure of a proc-macro lib.rs\n/*\nuse proc_macro::TokenStream;\nuse quote::quote;\nuse syn::{parse_macro_input, DeriveInput};\n\n#[proc_macro_derive(HelloMacro)]\npub fn hello_macro_derive(input: TokenStream) -> TokenStream {\n    // 1. Parse the input (T