INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('7ec42297-080f-5fa2-8933-271bf14c7cf6', 'ec52fcdb-46f8-5289-a434-f0d01828a624', '{"EN": "Quiz: Proc-Macros", "ES": "Quiz: Proc-Macros"}', '{"EN": "Understanding the basics of procedural macros.", "ES": "Entendiendo los b\u00e1sicos de macros procedimentales."}', true, NULL, '[{"id": "q-proc-1", "question": {"EN": "What trait represents the raw source code input?", "ES": "\u00bfQu\u00e9 trait representa la entrada de c\u00f3digo fuente crudo?"}, "options": {"EN": ["String", "TokenStream", "AST"], "ES": ["String", "TokenStream", "AST"]}, "correctIndex": 1, "explanation": {"EN": "Rust provides `TokenStream` to represent the sequence of tokens.", "ES": "Rust provee `TokenStream` para representar la secuencia de tokens."}}, {"id": "q-proc-2", "question": {"EN": "Can a Derive macro modify the struct it is placed on?", "ES": "\u00bfPuede una macro Derive modificar el struct en el que se coloca?"}, "options": {"EN": ["Yes", "No"], "ES": ["S\u00ed", "No"]}, "correctIndex": 1, "explanation": {"EN": "No, Derive macros are append-only. They generate new code but cannot change the original definition. You need Attribute macros for that.", "ES": "No, las macros Derive son solo de adjuntar. Generan c\u00f3digo nuevo pero no pueden cambiar la definici\u00f3n original. Necesitas macros de Atributo para eso."}}]', NULL, '[{"id": "q-proc-1", "question": {"EN": "What trait represents the raw source code input?", "ES": "\u00bfQu\u00e9 trait representa la entrada de c\u00f3digo fuente crudo?"}, "options": {"EN": ["String", "TokenStream", "AST"], "ES": ["String", "TokenStream", "AST"]}, "correctIndex": 1, "explanation": {"EN": "Rust provides `TokenStream` to represent the sequence of tokens.", "ES": "Rust provee `TokenStream` para representar la secuencia de tokens."}}, {"id": "q-proc-2", "question": {"EN": "Can a Derive macro modify the struct it is placed on?", "ES": "\u00bfPuede una macro Derive m