acros for that.", "ES": "No, las macros Derive son solo de adjuntar. Generan c\u00f3digo nuevo pero no pueden cambiar la definici\u00f3n original. Necesitas macros de Atributo para eso."}}]', NULL, 3);
INSERT INTO modules (id, course_id, title, "order") VALUES ('55043a0c-06e1-522f-914d-e4c7942db238', '70fd81c3-844c-5700-b6cb-be4ee738e7a2', '{"EN": "3. Attribute & Function-like", "ES": "3. Macros de Atributo y Funci\u00f3n"}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('89f0ef23-cfd8-5e9f-986f-4cc5dd0c082e', '55043a0c-06e1-522f-914d-e4c7942db238', '{"EN": "Attribute Macros", "ES": "Macros de Atributo"}', '{"EN": "# Attribute Macros\n\nAttribute macros are defined with `#[proc_macro_attribute]`. They are attached to items like `#[my_macro]` or `#[route(GET, \"/\")]`.\n\n## Power & Responsibility\nUnlike Derive macros, Attribute macros **replace** the item they are attached to.\n*   **Input**: The item (function, struct, etc.) AND the arguments passed to the attribute.\n*   **Output**: Whatever you return replaces the original code.\n\nThis allows you to modify functions completely (e.g., wrapping them in logging code, or registering them in a global list like web frameworks do for routes).\n\n## Example: Logging\nYou could write a `#[log_time]` macro that takes a user''s function body, and wraps it in a `std::time::Instant::now()` block.", "ES": "# Macros de Atributo\n\nSe definen con `#[proc_macro_attribute]`. Se adjuntan a \u00edtems como `#[mi_macro]` o `#[route(GET, \"/\")]`.\n\n## Poder y Responsabilidad\nA diferencia de las macros Derive, las de Atributo **reemplazan** el \u00edtem al que se adjuntan.\n*   **Entrada**: El \u00edtem (funci\u00f3n, struct, etc.) Y los argumentos pasados al atributo.\n*   **Salida**: Lo que retornes reemplaza el c\u00f3digo original.\n\nEsto permite modificar funciones completamente (ej. envolverlas en c\u00f3digo de logging, o registrarlas en una lista global como hacen los frameworks web para rutas).\n\n## Ejemplo: Logging\nPodr\u00edas escribir una macro `#[log_time]` que tome el cuerpo de la funci\u00f3n del usuario y lo envuelva en un bloque `std::time::Instant::now()`."}', false, NULL, NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!(\"Time: {:?}\", start.elapsed());\n   }\n*/', NULL, E'// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, E'// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, E'// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!(\"Time: {:?}\", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!(\"Time: {:?}\", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!("Time: {:?}", start.elapsed());\n   }\n*/', NULL, '// Usage:\n// #[log_execution]\n// fn heavy_computation() { ... }\n\n/* Implementation Logic:\n1. Parse input function: fn heavy_computation() { BODY }\n2. Create new body:\n   fn heavy_computation() {\n       let start = Instant::now();\n       { BODY } // Insert original body here\n       println!(\"Time: {:?}\", start.elapsed());\n   }\n*/', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('58d11f9b-2df3-5aa8-a112-b2209ac6f7b7', '55043a0c-06e1-522f-914d-e4c7942db238', '{"EN": "Function-like Macros", "ES": "Macros tipo Funci\u00f3n"}', '{"EN": "# Function-like Macros\n\nDefined with `#[proc_macro]`. These look like declarative macros (`my_macro!(...)`) but are powered by the full proc-macro engine.\n\n## Use Cases\nThese are useful when you need to define a **Domain Specific Language (DSL)** that doesn''t look like standard Rust code.\n*   **SQLx**: `sqlx::query!(\"SELECT * FROM users\")` parses the SQL string at compile time.\n*   **HTML templating**: `html! { <div> \"Hello\" </div> }`.\n\nBecause you control the parsing completely, the tokens inside `!(...)` don''t even have to be valid Rust, as long as your parser can handle them and produce valid Rust as output.", "ES": "# Macros tipo Funci\u00f3n\n\nDefinidas con `#[proc_macro]`. Se ven como macros declarativas (`mi_macro!(...)`) pero son impulsadas por el motor completo de proc-macro.\n\n## Casos de Uso\nSon \u00fatiles cuando necesitas definir un **Lenguaje de Dominio Espec\u00edfico (DSL)** que no parece c\u00f3digo Rust est\u00e1ndar.\n*   **SQLx**: `sqlx::query!(\"SELECT * FROM users\")` parsea el string SQL en tiempo de compilaci\u00f3n.\n*   **Plantillas HTML**: `html! { <div> \"Hola\" </div> }`.\n\nComo controlas el parsing completamente, los tokens dentro de `!(...)` no tienen que ser siquiera Rust v\u00e1lido, siempre que tu parser pueda manejarlos y producir Rust v\u00e1lido como salida."}', false, NULL, NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!(\"SELECT * FROM users WHERE active = true\");\n\n/* Logic:\n   The macro receives \"SELECT * FROM...\" as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query(\"SELECT...\").map(|row| User { ... })\n*/', NULL, E'// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, E'// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, E'// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!(\"SELECT * FROM users WHERE active = true\");\n\n/* Logic:\n   The macro receives \"SELECT * FROM...\" as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query(\"SELECT...\").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!(\"SELECT * FROM users WHERE active = true\");\n\n/* Logic:\n   The macro receives \"SELECT * FROM...\" as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query(\"SELECT...\").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!("SELECT * FROM users WHERE active = true");\n\n/* Logic:\n   The macro receives "SELECT * FROM..." as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query("SELECT...").map(|row| User { ... })\n*/', NULL, '// Example: Use SQL inside Rust\n// let users = sql!(\"SELECT * FROM users WHERE active = true\");\n\n/* Logic:\n   The macro receives \"SELECT * FROM...\" as a string literal token.\n   It connects to a DB at compile time to verify columns.\n   It generates Rust code: \n   db.query(\"SELECT...\").map(|row| User { ... })\n*/', 2);
INSERT INTO modules (id, course_id, title, "order") VALUES ('c261c64d-4603-5b36-bac5-e8428523ec62', '70fd81c3-844c-5700-b6cb-be4ee738e7a2', '{"EN": "4. Ecosystem & Testing", "ES": "4. Ecosistema y Testing"}', 4);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('be790298-b3ad-5726-9030-b5e4ec0a3ec8', 'c261c64d-4603-5b36-bac5-e8428523ec62', '{"EN": "Parsing with Syn", "ES": "Parseando con Syn"}', '{"EN": "# Deep Dive into Syn\n\nThe `syn` crate is the de-facto standard for parsing Rust code. It provides ready-made structs for almost every Rust syntax element.\n\n## Common Types\n*   `DeriveInput`: The input for a derive macro (Structs, Enums).\n*   `ItemFn`: Represents a function definition (useful for attribute macros).\n*   `Expr`: Represents an expression.\n*   `Lit`: Represents a literal (string, integer, bool).\n\n## Custom Parsing\nYou can implement the `syn::parse::Parse` trait for your own structs. This allows you to define how a stream of tokens should be converted into your strong types.", "ES": "# Profundizando en Syn\n\nEl crate `syn` es el est\u00e1ndar de facto para parsear c\u00f3digo Rust. Provee structs listos para casi todo elemento de sintaxis de Rust.\n\n## Tipos Comunes\n*   `DeriveInput`: La entrada para una macro derive (Structs, Enums).\n*   `ItemFn`: Representa una definici\u00f3n de funci\u00f3n (\u00fatil para macros de atributo).\n*   `Expr`: Representa una expresi\u00f3n.\n*   `Lit`: Representa un literal (string, entero, bool).\n\n## Parsing Personalizado\nPuedes implementar el trait `syn::parse::Parse` para tus propios structs. Esto te permite definir c\u00f3mo un flujo de tokens debe convertirse en tus tipos fuertes."}', false, NULL, NULL, '/*\nuse syn::{parse::Parse, parse::ParseStream, Result, Token};\n\nstruct MyArgs {\n    name: String,\n    count: u32,\n}\n\nimpl Parse for MyArgs {\n    fn parse(input: ParseStream) -> Result<Self> {\n        // Expect: "Name", 10\n        let name_lit: syn::LitStr = input.parse()?;\n        input.parse::<Token![,]>()?; // Comma\n        let count_lit: syn::LitInt = input.parse()?;\n        \n        Ok(MyArgs {\n            name: name_lit.value(),\n            count: count_lit.base10_parse()?,\n        })\n    }\n}\n*/', NULL, '/*\nuse syn::{parse::Parse, parse::ParseStream, Result, Token};\n\nstruct MyArgs {\n    name: String,\n    count: u32,\n}\n\nimpl Parse for MyArgs {\n    fn parse(input: ParseStream) -> Result<Self> {\n        // Expect: "Name", 10\n        let name_lit: syn::LitStr = input.parse()?;\n        input.parse::<Token![,]>()?; // Comma\n        let count_lit: syn::LitInt = input.parse()?;\n        \n        Ok(MyArgs {\n            name: name_lit.value(),\n            count: count_lit.base10_parse()?,\n        })\n    }\n}\n*/', NULL, '/*\nuse syn::{parse::Parse, parse::ParseStream, Result, Token};\n\nstruct MyArgs {\n    name: String,\n    count: u32,\n}\n\nimpl Parse for MyArgs {\n    fn parse(input: ParseStream) -> Result<Self> {\n        // Expect: "Name", 10\n        let name_lit: syn::LitStr = input.parse()?;\n        input.parse::<Token![,]>()?; // Comma\n        let count_lit: syn::LitInt = input.parse()?;\n        \n        Ok(MyArgs {\n            name: name_lit.value(),\n            count: count_lit.base10_parse()?,\n        })\n    }\n}\n*/', NULL, '/*\nuse syn::{parse::Parse, parse::ParseStream, Result, Token};\n\nstruct MyArgs {\n    name: String,\n    count: u32,\n}\n\nimpl Parse for MyArgs {\n    fn parse(input: ParseStream) -> Result<Self> {\n        // Expect: "Name", 10\n        let name_lit: syn::LitStr = input.parse()?;\n        input.parse::<Token![,]>()?; // Comma\n        let count_lit: syn::LitInt = input.parse()?;\n        \n        Ok(MyArgs {\n            name: name_lit.value(),\n            count: count_lit.base10_parse()?,\n        })\n    }\n}\n*/', NULL, '/*\nuse syn::{parse::Parse, parse::ParseStream, Result, Token};\n\nstruct MyArgs {\n    name: String,\n    count: u32,\n}\n\nimpl Parse for MyArgs {\n    fn parse(input: ParseStream) -> Result<Self> {\n        // Expect: "Name", 10\n        let name_lit: syn::LitStr = input.parse()?;\n        input.parse::<Token![,]>()?; // Co