  }\n\n    fn call(&mut self, req: i32) -> Pin<Box<dyn Future<Output = Result<i32, ()>>>> {\n        // Return a future that resolves to req + 1\n        Box::pin(async move {\n            Ok(req + 1)\n        })\n    }\n}\n\nfn main() {\n    println!("Tower abstracts ''Request -> Response'' logic.");\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\n// A simple service that adds 1 to a number\nstruct AddOneService;\n\n// Mocking the Service trait implementation structure\n// In real code, you implement tower::Service\nimpl AddOneService {\n    fn poll_ready(&mut self, _cx: &mut Context<''_>) -> Poll<Result<(), ()>> {\n        // Always ready to accept requests\n        Poll::Ready(Ok(()))\n    }\n\n    fn call(&mut self, req: i32) -> Pin<Box<dyn Future<Output = Result<i32, ()>>>> {\n        // Return a future that resolves to req + 1\n        Box::pin(async move {\n            Ok(req + 1)\n        })\n    }\n}\n\nfn main() {\n    println!(\"Tower abstracts ''Request -> Response'' logic.\");\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\n// A simple service that adds 1 to a number\nstruct AddOneService;\n\n// Mocking the Service trait implementation structure\n// In real code, you implement tower::Service\nimpl AddOneService {\n    fn poll_ready(&mut self, _cx: &mut Context<''_>) -> Poll<Result<(), ()>> {\n        // Always ready to accept requests\n        Poll::Ready(Ok(()))\n    }\n\n    fn call(&mut self, req: i32) -> Pin<Box<dyn Future<Output = Result<i32, ()>>>> {\n        // Return a future that resolves to req + 1\n        Box::pin(async move {\n            Ok(req + 1)\n        })\n    }\n}\n\nfn main() {\n    println!("Tower abstracts ''Request -> Response'' logic.");\n}', NULL, 'use std::future::Future;\nuse std::pin::Pin;\nuse std::task::{Context, Poll};\n\n// A simple service that adds 1 to a number\nstruct AddOneService;\n\n// Mocking the Service trait implementation structure\n// In real code, you implement tower::Service\nimpl AddOneService {\n    fn poll_ready(&mut self, _cx: &mut Context<''_>) -> Poll<Result<(), ()>> {\n        // Always ready to accept requests\n        Poll::Ready(Ok(()))\n    }\n\n    fn call(&mut self, req: i32) -> Pin<Box<dyn Future<Output = Result<i32, ()>>>> {\n        // Return a future that resolves to req + 1\n        Box::pin(async move {\n            Ok(req + 1)\n        })\n    }\n}\n\nfn main() {\n    println!(\"Tower abstracts ''Request -> Response'' logic.\");\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a7443cdd-3a4f-50de-b05d-007aef0aaa87', '64ec9a3a-6b15-57cd-9d1f-d33ccff3af86', '{"EN": "service_fn helper", "ES": "El helper service_fn"}', '{"EN": "# Removing Boilerplate\n\nImplementing the `Service` trait manually involves handling `Pin`, `Box`, and `Futures` explicitly, which is verbose.\n\n## tower::service_fn\nTower provides a helper function `service_fn` that turns a simple async closure or function into a full-fledged `Service`.\n\nThis is extremely useful for quick prototypes or simple endpoints where you don''t need complex state management inside the service struct.", "ES": "# Eliminando C\u00f3digo Repetitivo\n\nImplementar el trait `Service` manualmente implica manejar `Pin`, `Box` y `Futures` expl\u00edcitamente, lo cual es verboso.\n\n## tower::service_fn\nTower provee una funci\u00f3n de ayuda `service_fn` que convierte un closure o funci\u00f3n as\u00edncrona simple en un `Service` completo.\n\nEsto es extremadamente \u00fatil para prototipos r\u00e1pidos o endpoints simples donde no necesitas gesti\u00f3n de estado compleja dentro del struct del servicio."}', false, NULL, NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, 