se tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, E'// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, E'// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!(\"Hello, {}!\", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!(\"service_fn turns async functions into Services instantly.\");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!(\"Hello, {}!\", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!(\"service_fn turns async functions into Services instantly.\");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!("Hello, {}!", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!("service_fn turns async functions into Services instantly.");\n}', NULL, '// use tower::service_fn;\n\nasync fn handle_request(req: String) -> Result<String, String> {\n    Ok(format!(\"Hello, {}!\", req))\n}\n\nfn main() {\n    // let service = service_fn(handle_request);\n    \n    // Using the service involves:\n    // 1. service.poll_ready(...)\n    // 2. service.call(...)\n    \n    println!(\"service_fn turns async functions into Services instantly.\");\n}', 2);
INSERT INTO modules (id, course_id, title, "order") VALUES ('c755b3de-ddef-584a-9b65-b51dd099147a', '3b0900dd-7a79-5b0b-a7f8-8348bad75808', '{"EN": "2. Middleware & Layers", "ES": "2. Middleware y Capas"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('b2bd972b-2ab4-5e26-9956-d5e982253822', 'c755b3de-ddef-584a-9b65-b51dd099147a', '{"EN": "The Layer Trait", "ES": "El Trait Layer"}', '{"EN": "# Decorator Pattern\n\nMiddleware in Tower is implemented using the **Decorator Pattern**. A middleware is a Service that wraps another Service.\n\n## The Layer Trait\nWhile a `Service` handles the request, a `Layer` produces the service.\n```rust\npub trait Layer<S> {\n    type Service;\n    fn layer(&self, inner: S) -> Self::Service;\n}\n```\n\nThe `Layer` trait describes \"how to wrap\" a service. For example, a `TimeoutLayer` wraps an inner service into a `TimeoutService`. When `TimeoutService::call` is executed, it starts a timer and calls the inner service. If the timer finishes first, it returns an Error.", "ES": "# Patr\u00f3n Decorador\n\nEl Middleware en Tower se implementa usando el **Patr\u00f3n Decorador**. Un middleware es un Servicio que envuelve a otro Servicio.\n\n## El Trait Layer\nMientras un `Service` maneja la petici\u00f3n, un `Layer` (Capa) produce el servicio.\n\nEl trait `Layer` describe \"c\u00f3mo envolver\" un servicio. Por ejemplo, un `TimeoutLayer` envuelve un servicio interno en un `TimeoutService`. Cuando se ejecuta `TimeoutService::call`, inicia un temporizador y llama al servicio interno. Si el temporizador termina primero, retorna un Error."}', false, NULL, NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: \"api\" }.layer(my_service);', NULL, E'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, E'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, E'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: \"api\" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: \"api\" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: "api" }.layer(my_service);', NULL, 'struct LogService<S> {\n    inner: S,\n    target: String,\n}\n\n// Pseudo-code implementation of a Layer\nstruct LogLayer {\n    target: String\n}\n\nimpl<S> Layer<S> for LogLayer {\n    type Service = LogService<S>;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        LogService {\n            inner,\n            target: self.target.clone(),\n        }\n    }\n}\n\n// Usage:\n// let service = LogLayer { target: \"api\" }.layer(my_service);', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('948da7fc-9158-549b-a6f4-4a8d06f0a342', 'c755b3de-ddef-584a-9b65-b51dd099147a', '{"EN": "ServiceBuilder", "ES": "ServiceBuilder"}', '{"EN": "# Stacking Middleware\n\nManually wrapping services gets messy fast:\n`Timeout(Limit(Log(Auth(MyService))))`\n\n## ServiceBuilder\n`tower::ServiceBuilder` provides a fluent API to compose multiple layers. It applies layers in order. Note that because layers wrap the service, the order of execution is often \"First Layer added is the Outer-most layer\".\n\n1.  Request enters Outer Layer.\n2.  Outer Layer calls Inner Layer.\n3.  Eventually hits the Service.\n4.  Response bubbles back up.", "ES": "# Apilando Middleware\n\nEnvolver servicios manualmente se vuelve desordenado r\u00e1pido:\n`Timeout(Limit(Log(Auth(MiServicio))))`\n\n## ServiceBuilder\n`tower::ServiceBuilder` provee una API fluida para componer m\u00faltiples capas. Aplica capas en orden. Nota que como las capas envuelven al servicio, el orden de ejecuci\u00f3n es a menudo \"La primera capa a\u00f1adida es la m\u00e1s externa\".\n\n1.  La Petici\u00f3n entra en la Capa Externa.\n2.  La Capa Externa llama a la Interna.\n3.  Eventualmente llega al Servicio.\n4.  La Respuesta burbujea hacia arriba."}', false, NULL, NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!(\"ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler\");\n}', NULL, E'// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, E'// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, E'// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!(\"ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler\");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!(\"ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler\");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!("ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler");\n}', NULL, '// use tower::ServiceBuilder;\n\nfn main() {\n    // Hypothetical setup\n    /*\n    let service = ServiceBuilder::new()\n        .timeout(Duration::from_secs(10))\n        .concurrency_limit(100)\n        .layer(MyCustomLogLayer)\n        .service(my_handler);\n    */\n    \n    println!(\"ServiceBuilder creates the stack: Timeout -> Limit -> Log -> Handler\");\n}', 2);
INSERT INTO modules (id, course_id, title, "order") VALUES ('ec5c7621-64a3-57b2-8e6d-198fb8d634ff', '3b0900dd-7a79-5b0b-a7f8-8348bad75808', '{"EN": "3. Batteries Included", "ES": "3. Bater\u00edas Incluidas"}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('3bb9dfc1-aedc-5f8c-8c96-a57f56345080', 'ec5c7621-64a3-57b2-8e6d-198fb8d634ff', '{"EN": "Common Middleware", "ES": "Middleware Com\u00fan"}', '{"EN": "# Powerful Standard Layers\n\nTower comes with a set of standard middleware that solves distributed systems problems straight out of the box.\n\n*   **Timeout**: Fails the request if the inner service takes too long.\n*   **RateLimit**: Limits the number of requests per duration (e.g., 5 per second).\n*   **ConcurrencyLimit**: Limits the number of active in-flight requests (e.g., max 10 concurrent). Uses `poll_ready` to wait until a slot is free.\n*   **LoadShed**: Rejects requests immediately if the service is overloaded (instead of waiting).\n*   **Buffer**: Adds a confusingly named \"Buffer\". It actually spawns a worker task and communicates via a channel (mpsc). It turns a synchronous service call into an async one (handles `poll_ready` for you).", "ES": "# Capas Est\u00e1ndar Poderosas\n\nTower viene con un conjunto de middleware est\u00e1ndar que resuelve problemas de sistemas distribuidos desde la caja.\n\n*   **Timeout**: Falla la petici\u00f3n si el servicio interno tarda demasiado.\n*   **RateLimit**: Limita el n\u00famero de peticiones por duraci\u00f3n (ej. 5 por segundo).\n*   **ConcurrencyLimit**: Limita el n\u00famero de peticiones activas en vuelo (ej. m\u00e1x 10 concurrentes). Usa `poll_ready` para esperar a que un slot est\u00e9 libre.\n*   **LoadShed**: Rechaza peticiones inmediatamente si el servicio est\u00e1 sobrecargado (en lugar de esperar).\n*   **Buffer**: A\u00f1ade un \"Buffer\". En realidad lanza una tarea worker y comunica v\u00eda canal (mpsc). Convierte una llamada de servicio s\u00edncrona en as\u00edncrona."}', false, NULL, NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!(\"Using RateLimit prevents DoS attacks.\");\n    println!(\"Using Timeout prevents hung connections consuming resources.\");\n    println!(\"Using ConcurrencyLimit implements ''Backpressure''.\");\n}', NULL, E'// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, E'// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, E'// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!(\"Using RateLimit prevents DoS attacks.\");\n    println!(\"Using Timeout prevents hung connections consuming resources.\");\n    println!(\"Using ConcurrencyLimit implements ''Backpressure''.\");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!(\"Using RateLimit prevents DoS attacks.\");\n    println!(\"Using Timeout prevents hung connections consuming resources.\");\n    println!(\"Using ConcurrencyLimit implements ''Backpressure''.\");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!("Using RateLimit prevents DoS attacks.");\n    println!("Using Timeout prevents hung connections consuming resources.");\n    println!("Using ConcurrencyLimit implements ''Backpressure''.");\n}', NULL, '// use tower::limit::RateLimitLayer;\n// use tower::timeout::TimeoutLayer;\n\nfn main() {\n    println!(\"Using RateLimit prevents DoS attacks.\");\n    println!(\"Using Timeout prevents hung connections consuming resources.\");\n    println!(\"Using ConcurrencyLimit implements ''Backpressure''.\");\n}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('e0137c11-cf98-5f0b-af6d-2c70d0e578b4', 'ec5c7621-64a3-57b2-8e6d-198fb8d634ff', '{"EN": "Quiz: Tower", "ES": "Quiz: Tower"}', '{"EN": "Verify Tower concepts.", "ES": "Verifica conceptos de Tower."}', true, NULL, '[{"id": "q-tow-1", "question": {"EN": "What method must be called before `call`?", "ES": "\u00bfQu\u00e9 m\u00e9todo debe llamarse antes de `call`?"}, "options": {"EN": ["check_ready", "poll_ready", "is_ready"], "ES": ["check_ready", "poll_ready", "is_ready"]}, "correctIndex": 1, "explanation": {"EN": "`poll_ready` reserves capacity and checks if the service can handle the request.", "ES": "`poll_ready` reserva capacidad y verifica si el servicio puede manejar la petici\u00f3n."}}, {"id": "q-tow-2", "question": {"EN": "What trait creates a Service from another Service?", "ES": "\u00bfQu\u00e9 trait crea un Servicio desde otro Servicio?"}, "options": {"EN": ["Wrapper", "Middleware", "Layer"], "ES": ["Wrapper", "Middleware", "Layer"]}, "correctIndex": 2, "explanation": {"EN": "Layers wrap services to produce new services (Decorator pattern).", "ES": "Las Capas (Layers) envuelven servicios para producir nuevos servicios (patr\u00f3n Decorador)."}}]', NULL, '[{"id": "q-tow-1", "question": {"EN": "What method must be called before `call`?", "ES": "\u00bfQu\u00e9 m\u00e9todo debe llamarse antes de `call`?"}, "options": {"EN": ["check_ready", "poll_ready", "is_ready"], "ES": ["check_ready", "poll_ready", "is_ready"]}, "correctIndex": 1, "explanation": {"EN": "`poll_ready` reserves capacity and checks if the service can handle the request.", "ES": "`poll_ready` reserva capacidad y verifica si el servicio puede manejar la petici\u00f3n."}}, {"id": "q-tow-2", "question": {"EN": "What trait creates a Service from another Service?", "ES": "\u00bfQu\u00e9 trait crea un Servicio desde otro Servicio?"}, "options": {"EN": ["Wrapper", "Middleware", "Layer"], "ES": ["Wrapper", "Middlewa