INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('ae80a723-6499-5cc7-9896-91595b472bb3', 'rust-advanced', '{"EN": "Advanced Rust: Deep Dive", "ES": "Rust Avanzado: Profundizaci\u00f3n"}', '{"EN": "Deep ownership, HRTB lifetimes, interior mutability, macros, and unsafe invariants.", "ES": "Ownership profundo, lifetimes HRTB, mutabilidad interior, macros e invariantes unsafe."}', 'Advanced', 'https://placehold.co/800x500/8D2D1D/FFFFFF/png?text=Advanced+Rust&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('809c64be-c14b-52f0-9d4a-165440df568b', 'ae80a723-6499-5cc7-9896-91595b472bb3', '{"EN": "1. Unsafe Rust", "ES": "1. Rust Unsafe"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('5383be35-96ab-50f7-af14-c7e7508d81f3', '809c64be-c14b-52f0-9d4a-165440df568b', '{"EN": "Raw Pointers", "ES": "Punteros Crudos"}', '{"EN": "# Unsafe Rust\n\nRust has a second language hidden inside it. Unsafe Rust gives you superpowers, but removes the safety net. It is used when you need to interface with the OS or hardware directly, or when you need to build abstractions that the compiler''s borrow checker cannot verify but you know are correct.\n\n## Superpowers\n1. Dereference raw pointers.\n2. Call unsafe functions (FFI).\n3. Access or modify mutable static variables.\n4. Implement unsafe traits.", "ES": "# Rust Unsafe (Inseguro)\n\nRust tiene un segundo lenguaje oculto en su interior. Unsafe Rust te da superpoderes, pero quita la red de seguridad. Se usa para interactuar con el SO o hardware directamente, o cuando necesitas construir abstracciones que el borrow checker no puede verificar pero t\u00fa sabes que son correctas.\n\n## Superpoderes\n1. Desreferenciar punteros crudos.\n2. Llamar funciones inseguras (FFI).\n3. Acceder o modificar variables est\u00e1ticas mutables.\n4. Implementar traits inseguros."}', false, NULL, NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!(\"r1 is: {}\", *r1);\n        println!(\"r2 is: {}\", *r2);\n        \n        *r2 = 10;\n        println!(\"r2 is now: {}\", *r2);\n    }\n}', NULL, E'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, E'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, E'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!(\"r1 is: {}\", *r1);\n        println!(\"r2 is: {}\", *r2);\n        \n        *r2 = 10;\n        println!(\"r2 is now: {}\", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!(\"r1 is: {}\", *r1);\n        println!(\"r2 is: {}\", *r2);\n        \n        *r2 = 10;\n        println!(\"r2 is now: {}\", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!("r1 is: {}", *r1);\n        println!("r2 is: {}", *r2);\n        \n        *r2 = 10;\n        println!("r2 is now: {}", *r2);\n    }\n}', NULL, 'fn main() {\n    let mut num = 5;\n    \n    // Creating raw pointers is SAFE\n    let r1 = &num as *const i32;\n    let r2 = &mut num as *mut i32;\n    \n    // Dereferencing them is UNSAFE\n    unsafe {\n        println!(\"r1 is: {}\", *r1);\n        println!(\"r2 is: {}\", *r2);\n        \n        *r2 = 10;\n        println!(\"r2 is now: {}\", *r2);\n    }\n}', 1);
INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('0c3dcd09-404b-5cf0-a0c6-bb05e926a3a5', 'rust-backend', '{"EN": "Rust Backend Engineering", "ES": "Ingenier\u00eda Backend en Rust"}', '{"EN": "Build production services with gRPC, Axum, SQLx, and Tokio. Learn how to handle async tasks, database connections, and API design.", "ES": "Construye servicios en producci\u00f3n con gRPC, Axum, SQLx y Tokio. Aprende a manejar tareas as\u00edncronas, bases de datos y dise\u00f1o de APIs."}', 'Advanced', 'https://placehold.co/800x500/1F1F1F/CE412B/png?text=Rust+Backend&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('c52238ff-f4ef-533b-b6ba-561f803f01d8', '0c3dcd09-404b-5cf0-a0c6-bb05e926a3a5', '{"EN": "1. Async Runtime (Tokio)", "ES": "1. Runtime As\u00edncrono (Tokio)"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('172f3173-5858-5a82-9570-95b50a142ab1', 'c52238ff-f4ef-533b-b6ba-561f803f01d8', '{"EN": "Async/Await & The Actor Model", "ES": "Async/Await y el Modelo Actor"}', '{"EN": "# Async/Await in Depth\n\nRust''s `Future` trait is the building block of async. Unlike JS Promises which run immediately, Rust Futures are **lazy**. They do nothing until polled by an executor.\n\n## Tokio\nTokio is the standard runtime/executor. It provides:\n1. Multi-threaded scheduler (work-stealing).\n2. Async I/O primitives (TCP, UDP, FS) backed by OS event queues (epoll/kqueue).\n3. Timers.\n\n## Green Threads\nTokio spawns tasks onto OS threads. These tasks are lightweight \"Green Threads\". You can spawn thousands of them with minimal overhead.", "ES": "# Async/Await en Profundidad\n\nEl trait `Future` de Rust es el bloque de construcci\u00f3n. A diferencia de las Promesas de JS que corren de inmediato, los Futures de Rust son **perezosos (lazy)**. No hacen nada hasta que un ejecutor les hace poll.\n\n## Tokio\nTokio es el runtime/ejecutor est\u00e1ndar. Provee:\n1. Planificador multihilo (work-stealing).\n2. Primitivas I/O as\u00edncronas (TCP, UDP, FS) respaldadas por colas de eventos del SO (epoll/kqueue).\n3. Timers.\n\n## Green Threads\nTokio lanza tareas (spawns) en hilos del SO. Estas tareas son \"Green Threads\" ligeros. Puedes lanzar miles con sobrecarga m\u00ednima."}', false, NULL, NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        \"Task completed\"\n    });\n\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', NULL, E'#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, E'#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, E'#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        \"Task completed\"\n    });\n\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        \"Task completed\"\n    });\n\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        "Task completed"\n    });\n\n    let out = handle.await.unwrap();\n    println!("{}", out);\n}', NULL, '#[tokio::main]\nasync fn main() {\n    let handle = tokio::spawn(async {\n        \"Task completed\"\n    });\n\n    let out = handle.await.unwrap();\n    println!(\"{}\", out);\n}', 1);
INSERT INTO modules (id, course_id, title, "order") VALUES ('90eb2cd9-c760-58a1-a806-1f1b57f9ad8a', '0c3dcd09-404b-5cf0-a0c6-bb05e926a3a5', '{"EN": "2. Web Frameworks (Axum)", "ES": "2. Frameworks Web (Axum)"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('ed418e0f-d08a-575e-88cb-16e5495aa6bc', '90eb2cd9-c760-58a1-a806-1f1b57f9ad8a', '{"EN": "Handlers & Extractors", "ES": "Handlers y Extractors"}', '{"EN": "# Building APIs with Axum\n\nAxum is an ergonomic and modular web framework built with Tokio, Tower, and Hyper. It uses a macro-free API.\n\n## Handlers\nHandlers are async functions that accept requests and return responses.\n\n## Extractors\nAxum uses \"Extractors\" to get data from the request.\n*   `Json<T>`: Deserializes the request body.\n*   `Path<T>`: Extracts URL path parameters.\n*   `Query<T>`: Extracts query string parameters.\n*   `State<T>`: Extracts shared application state.", "ES": "# Construyendo APIs con Axum\n\nAxum es un framework web ergon\u00f3mico y modular construido con Tokio, Tower y Hyper. Usa una API libre de macros.\n\n## Handlers\nSon funciones as\u00edncronas que aceptan peticiones y retornan respuestas.\n\n## Extractors\nAxum usa \"Extractors\" para obtener datos de la petici\u00f3n.\n*   `Json<T>`: Deserializa el cuerpo de la petici\u00f3n.\n*   `Path<T>`: Extrae par\u00e1metros de la ruta URL.\n*   `Query<T>`: Extrae par\u00e1metros del query string.\n*   `State<T>`: Extrae estado compartido de la aplicaci\u00f3n."}', false, NULL, NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route(\"/\", get(|| async { \"H