 app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, E'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route(\"/\", get(|| async { \"Hello, World!\" }))\n        .route(\"/users\", post(create_user));\n\n    println!(\"Server running on port 3000\");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route(\"/\", get(|| async { \"Hello, World!\" }))\n        .route(\"/users\", post(create_user));\n\n    println!(\"Server running on port 3000\");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route("/", get(|| async { "Hello, World!" }))\n        .route("/users", post(create_user));\n\n    println!("Server running on port 3000");\n}', NULL, 'use axum::{\n    routing::{get, post},\n    Router,\n    Json,\n};\nuse serde::{Deserialize, Serialize};\n\n#[derive(Serialize, Deserialize)]\nstruct CreateUser {\n    username: String,\n}\n\n#[derive(Serialize)]\nstruct User {\n    id: u64,\n    username: String,\n}\n\nasync fn create_user(\n    Json(payload): Json<CreateUser>,\n) -> Json<User> {\n    let user = User {\n        id: 1337,\n        username: payload.username,\n    };\n    Json(user)\n}\n\n#[tokio::main]\nasync fn main() {\n    let app = Router::new()\n        .route(\"/\", get(|| async { \"Hello, World!\" }))\n        .route(\"/users\", post(create_user));\n\n    println!(\"Server running on port 3000\");\n}', 1);
INSERT INTO modules (id, course_id, title, "order") VALUES ('6d7a8415-7d12-58b3-848b-5a33bfe5b444', '0c3dcd09-404b-5cf0-a0c6-bb05e926a3a5', '{"EN": "3. Database Integration (SQLx)", "ES": "3. Integraci\u00f3n de Base de Datos (SQLx)"}', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('e5185723-87c2-5de6-a2c8-9c4f8e87237f', '6d7a8415-7d12-58b3-848b-5a33bfe5b444', '{"EN": "Async SQL with SQLx", "ES": "SQL As\u00edncrono con SQLx"}', '{"EN": "# SQLx: The Async SQL Toolkit\n\nSQLx provides an async, pure Rust SQL crate featuring compile-time checked queries. It is not an ORM; it is close to the metal but type-safe.\n\n## Key Features\n*   **Async from the ground up**: Built for Tokio/async-std.\n*   **Compile-time checks**: The `query!` macro connects to your DB at compile time to verify your SQL syntax.\n*   **Database Agnostic**: Supports Postgres, MySQL, SQLite, MSSQL.\n\n## Connection Pools\nCreating a connection for every request is slow. We use a `PgPool` (Postgres Connection Pool) to manage a set of open connections that can be reused.", "ES": "# SQLx: El Toolkit SQL As\u00edncrono\n\nSQLx provee un crate SQL as\u00edncrono y puro en Rust con consultas verificadas en tiempo de compilaci\u00f3n. No es un ORM; es cercano al metal pero seguro en tipos.\n\n## Caracter\u00edsticas Clave\n*   **As\u00edncrono desde la base**: Construido para Tokio/async-std.\n*   **Chequeos en compilaci\u00f3n**: La macro `query!` conecta a tu BD al compilar para verificar sintaxis SQL.\n*   **Agn\u00f3stico de BD**: Soporta Postgres, MySQL, SQLite, MSSQL.\n\n## Pools de Conexi\u00f3n\nCrear una conexi\u00f3n para cada petici\u00f3n es lento. Usamos un `PgPool` para gestionar un conjunto de conexiones abiertas reutilizables."}', false, NULL, NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!("Connecting to Postgres...");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect("postgres://user:pass@localhost/db").await?;\n\n    // let row: (i64,) = sqlx::query_as("INSERT INTO tickets (title) VALUES ($1) RETURNING id")\n    //    .bind("My Ticket")\n    //    .fetch_one(&pool).await?;\n\n    println!("Created ticket with ID: 1");\n    Ok(())\n}', NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!("Connecting to Postgres...");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect("postgres://user:pass@localhost/db").await?;\n\n    // let row: (i64,) = sqlx::query_as("INSERT INTO tickets (title) VALUES ($1) RETURNING id")\n    //    .bind("My Ticket")\n    //    .fetch_one(&pool).await?;\n\n    println!("Created ticket with ID: 1");\n    Ok(())\n}', NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!("Connecting to Postgres...");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect("postgres://user:pass@localhost/db").await?;\n\n    // let row: (i64,) = sqlx::query_as("INSERT INTO tickets (title) VALUES ($1) RETURNING id")\n    //    .bind("My Ticket")\n    //    .fetch_one(&pool).await?;\n\n    println!("Created ticket with ID: 1");\n    Ok(())\n}', NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!("Connecting to Postgres...");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect("postgres://user:pass@localhost/db").await?;\n\n    // let row: (i64,) = sqlx::query_as("INSERT INTO tickets (title) VALUES ($1) RETURNING id")\n    //    .bind("My Ticket")\n    //    .fetch_one(&pool).await?;\n\n    println!("Created ticket with ID: 1");\n    Ok(())\n}', NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!("Connecting to Postgres...");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect("postgres://user:pass@localhost/db").await?;\n\n    // let row: (i64,) = sqlx::query_as("INSERT INTO tickets (title) VALUES ($1) RETURNING id")\n    //    .bind("My Ticket")\n    //    .fetch_one(&pool).await?;\n\n    println!("Created ticket with ID: 1");\n    Ok(())\n}', NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!("Connecting to Postgres...");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect("postgres://user:pass@localhost/db").await?;\n\n    // let row: (i64,) = sqlx::query_as("INSERT INTO tickets (title) VALUES ($1) RETURNING id")\n    //    .bind("My Ticket")\n    //    .fetch_one(&pool).await?;\n\n    println!("Created ticket with ID: 1");\n    Ok(())\n}', NULL, 'use sqlx::postgres::{PgPoolOptions, PgRow};\nuse sqlx::{FromRow, Row};\n\n#[derive(Debug, FromRow)]\nstruct Ticket {\n    id: i64,\n    title: String,\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), sqlx::Error> {\n    println!(\"Connecting to Postgres...\");\n    \n    // In real code:\n    // let pool = PgPoolOptions::new()\n    //     .connect(\"postgres://user:pass@localhost/db\").await?;\n\n    // let row: (i64,) = sqlx::query_as(\"INSERT INTO tickets (title) VALUES ($1) RETURNING id\")\n    //    .bind(\"My Ticket\")\n    //    .fetch_one(&pool).await?;\n\n    println!(\"Created ticket with ID: 1\");\n    Ok(())\n}', NULL, E'u