INSERT INTO modules (id, course_id, title, "order") VALUES ('18e1c207-16b6-560d-a078-14a56080cf05', '0c3dcd09-404b-5cf0-a0c6-bb05e926a3a5', '{"EN": "4. gRPC Services (Tonic)", "ES": "4. Servicios gRPC (Tonic)"}', 4);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('095a5b78-6bf9-575b-8f2f-c922b505fd3e', '18e1c207-16b6-560d-a078-14a56080cf05', '{"EN": "Defining Services with Protocol Buffers", "ES": "Definiendo Servicios con Protocol Buffers"}', '{"EN": "# gRPC and Tonic\n\ngRPC is a high-performance RPC framework. Rust''s implementation is **Tonic**.\n\n## Protocol Buffers\nYou define your service and messages in a `.proto` file. This is language-agnostic.\n```protobuf\nservice Greeter {\n  rpc SayHello (HelloRequest) returns (HelloReply);\n}\n```\n\n## Tonic build\nTonic uses a `build.rs` script to compile `.proto` files into Rust code (`tonic_build`).\n\n## Implementation\nYou implement the generated trait for your service struct.", "ES": "# gRPC y Tonic\n\ngRPC es un framework RPC de alto rendimiento. La implementaci\u00f3n de Rust es **Tonic**.\n\n## Protocol Buffers\nDefines tu servicio y mensajes en un archivo `.proto`. Es agn\u00f3stico del lenguaje.\n\n## Tonic build\nTonic usa un script `build.rs` para compilar archivos `.proto` a c\u00f3digo Rust (`tonic_build`).\n\n## Implementaci\u00f3n\nImplementas el trait generado para tu struct de servicio."}', false, NULL, NULL, 'use tonic::{transport::Server, Request, Response, Status};\n\n// Mocking generated code from .proto\npub mod hello_world {\n    pub trait Greeter {\n        // In real code this is generated\n        async fn say_hello(&self, request: super::Request<HelloRequest>) \n            -> Result<super::Response<HelloReply>, super::Status>;\n    }\n    pub struct HelloRequest { pub name: String }\n    pub struct HelloReply { pub message: String }\n}\nuse hello_world::{Greeter, HelloRequest, HelloReply};\n\nstruct MyGreeter;\n\n// Implement the trait\nimpl Greeter for MyGreeter {\n    async fn say_hello(&self, request: Request<HelloRequest>) \n        -> Result<Response<HelloReply>, Status> {\n        let name = request.into_inner().name;\n        let reply = HelloReply {\n            message: format!("Hello {}!", name),\n        };\n        Ok(Response::new(reply))\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    println!("gRPC Server listening on [::1]:50051");\n}', NULL, 'use tonic::{transport::Server, Request, Response, Status};\n\n// Mocking generated code from .proto\npub mod hello_world {\n    pub trait Greeter {\n        // In real code this is generated\n        async fn say_hello(&self, request: super::Request<HelloRequest>) \n            -> Result<super::Response<HelloReply>, super::Status>;\n    }\n    pub struct HelloRequest { pub name: String }\n    pub struct HelloReply { pub message: String }\n}\nuse hello_world::{Greeter, HelloRequest, HelloReply};\n\nstruct MyGreeter;\n\n// Implement the trait\nimpl Greeter for MyGreeter {\n    async fn say_hello(&self, request: Request<HelloRequest>) \n        -> Result<Response<HelloReply>, Status> {\n        let name = request.into_inner().name;\n        let reply = HelloReply {\n            message: format!("Hello {}!", name),\n        };\n        Ok(Response::new(reply))\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    println!("gRPC Server listening on [::1]:50051");\n}', NULL, 'use tonic::{transport::Server, Request, Response, Status};\n\n// Mocking generated code from .proto\npub mod hello_world {\n    pub trait Greeter {\n        // In real code this is generated\n        async fn say_hello(&self, request: super::Request<HelloRequest>) \n            -> Result<super::Response<HelloReply>, super::Status>;\n    }\n    pub struct HelloRequest { pub name: String }\n    pub struct HelloReply { pub message: String }\n}\nuse hello_world::{Greeter, HelloRequest, HelloReply};\n\nstruct MyGreeter;\n\n// Implement the trait\nimpl Greeter for MyGreeter {\n    async fn say_hello(&self, request: Request<HelloRequest>) \n        -> Result<Response<HelloReply>, Status> {\n        let name = request.into_inner().name;\n        let reply = HelloReply {\n            message: format!("Hello {}!", name),\n        };\n        Ok(Response::new(reply))\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    println!("gRPC Server listening on [::1]:50051");\n}', NULL, 'use tonic::{transport::Server, Request, Response, Status};\n\n// Mocking generated code from .proto\npub mod hello_world {\n    pub trait Greeter {\n        // In real code this is generated\n        async fn say_hello(&self, request: super::Request<HelloRequest>) \n            -> Result<super::Response<HelloReply>, super::Status>;\n    }\n    pub struct HelloRequest { pub name: String }\n    pub struct HelloReply { pub message: String }\n}\nuse hello_world::{Greeter, HelloRequest, HelloReply};\n\nstruct MyGreeter;\n\n// Implement the trait\nimpl Greeter for MyGreeter {\n    async fn say_hello(&self, request: Request<HelloRequest>) \n        -> Result<Response<HelloReply>, Status> {\n        let name = request.into_inner().name;\n        let reply = HelloReply {\n            message: format!("Hello {}!", name),\n        };\n        Ok(Response::new(reply))\n    }\n}\n\n#[tokio::main]\nasync fn main() {\n    println!("gRPC Server listening on [::1]:50051");\n}', NULL, 'use tonic::{transport::Server, Request, Response, Status};\n\n// Mocking generated code from .proto\npub mod hello_world {\n    pub trait Greeter {\n        // In real code this is generated\n        async fn say_hello(&self, request: super::Request<HelloRequest>) \n            -> Result<super::Response<HelloReply>, super::Status>;\n    }\n    pub struct HelloRequest { pub name: String }\n    pub struct HelloReply { pub message: String }\n}\nuse hello_world::{Greeter, HelloRequest, HelloReply};\n\nstruct MyGreeter;\n\n// Implement the trait\nimpl Greeter for MyGreeter {\n    async fn say_hello(&self, request: Request<HelloRequest>) \n        -> Result<Response<HelloReply>, Status> {\n        let name = request.into_inner().name;\n        let reply = HelloReply {\n            message: format!("Hello {}!", name),\n        };\n    