INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('257b76d1-5e86-57c2-91ae-1940f469db0e', 'rust-ai', '{"EN": "AI & Machine Learning with Rust", "ES": "IA y Machine Learning con Rust"}', '{"EN": "Harness the power of Rust for high-performance AI. Learn to use Candle and Burn frameworks, implement neural networks, and deploy models to WASM.", "ES": "Aprovecha el poder de Rust para IA de alto rendimiento. Aprende a usar los frameworks Candle y Burn, implementa redes neuronales y despliega modelos en WASM."}', 'Advanced', 'https://placehold.co/800x500/083344/22D3EE/png?text=Rust+for+AI&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('7682c3de-bfc1-5016-81c0-37f66179dc2d', '257b76d1-5e86-57c2-91ae-1940f469db0e', '{"EN": "1. AI Foundations & Tensors", "ES": "1. Fundamentos de IA y Tensores"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('1d71d8f1-0c4f-55f2-ab27-0810e91c5903', '7682c3de-bfc1-5016-81c0-37f66179dc2d', '{"EN": "Why Rust for AI?", "ES": "\u00bfPor qu\u00e9 Rust para IA?"}', '{"EN": "# AI in the Rust Era\n\nTraditionally, Python has dominated AI due to its ease of use. However, as models scale, two problems emerge: **Memory Safety** and **Execution Overhead**.\n\n## The Performance Bottleneck\nPython relies on C++ bindings (PyTorch/TensorFlow). While the core kernels are fast, the \"glue code\" introduces latency. Rust allows for:\n1. **Zero-cost FFI**: Seamless interaction with CUDA and Metal.\n2. **In-place Mutations**: Optimized tensor operations without unnecessary allocations.\n3. **Safe Concurrency**: Distributing model weights across CPU cores without data races.\n\n## Candle Framework\nDeveloped by Hugging Face, **Candle** is a minimalist ML framework for Rust. It prioritizes small binary sizes and running models in the browser (WASM) or at the edge.", "ES": "# La IA en la Era de Rust\n\nTradicionalmente, Python ha dominado la IA. Sin embargo, al escalar modelos, surgen dos problemas: **Seguridad de Memoria** y **Sobrecarga de Ejecuci\u00f3n**.\n\n## El Cuello de Botella de Rendimiento\nPython depende de bindings de C++. Rust permite:\n1. **FFI de Costo Cero**: Interacci\u00f3n fluida con CUDA y Metal.\n2. **Mutaciones In-place**: Operaciones de tensores optimizadas sin asignaciones innecesarias.\n3. **Concurrencia Segura**: Distribuir pesos del modelo entre n\u00facleos sin carreras de datos.\n\n## Framework Candle\nDesarrollado por Hugging Face, **Candle** es un framework ML minimalista para Rust. Prioriza tama\u00f1os de binario peque\u00f1os y ejecuci\u00f3n en el navegador (WASM)."}', false, NULL, NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!("Initializing AI Environment...");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    // let b = a.matmul(&a).unwrap();\n    \n    println!("Tensor computation localized in Rust memory.");\n}', NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!("Initializing AI Environment...");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    // let b = a.matmul(&a).unwrap();\n    \n    println!("Tensor computation localized in Rust memory.");\n}', NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!("Initializing AI Environment...");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    // let b = a.matmul(&a).unwrap();\n    \n    println!("Tensor computation localized in Rust memory.");\n}', NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!("Initializing AI Environment...");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    // let b = a.matmul(&a).unwrap();\n    \n    println!("Tensor computation localized in Rust memory.");\n}', NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!("Initializing AI Environment...");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    // let b = a.matmul(&a).unwrap();\n    \n    println!("Tensor computation localized in Rust memory.");\n}', NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!("Initializing AI Environment...");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    // let b = a.matmul(&a).unwrap();\n    \n    println!("Tensor computation localized in Rust memory.");\n}', NULL, '// Using Candle for Tensor Math\n// use candle_core::{Device, Tensor};\n\nfn main() {\n    println!(\"Initializing AI Environment...\");\n    // let a = Tensor::new(&[1f32, 2., 3., 4.], &Device::Cpu).unwrap();\n    //