INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('6e07fb3a-17bc-5464-a66e-527668cf8f42', '7682c3de-bfc1-5016-81c0-37f66179dc2d', '{"EN": "Quiz: AI Fundamentals", "ES": "Quiz: Fundamentos de IA"}', '{"EN": "Verify AI patterns in Rust.", "ES": "Verifica patrones de IA en Rust."}', true, NULL, '[{"id": "q-ai-1", "question": {"EN": "What is a primary benefit of using Rust for AI inference?", "ES": "\u00bfCu\u00e1l es un beneficio principal de usar Rust para inferencia de IA?"}, "options": {"EN": ["More libraries than Python", "Lower memory footprint and higher execution speed", "It is easier to write than Python"], "ES": ["M\u00e1s librer\u00edas que Python", "Menor huella de memoria y mayor velocidad de ejecuci\u00f3n", "Es m\u00e1s f\u00e1cil de escribir que Python"]}, "correctIndex": 1, "explanation": {"EN": "Rust eliminates the overhead of the Python interpreter and provides safe, high-performance memory management.", "ES": "Rust elimina la sobrecarga del int\u00e9rprete de Python y provee una gesti\u00f3n de memoria segura y de alto rendimiento."}}]', NULL, '[{"id": "q-ai-1", "question": {"EN": "What is a primary benefit of using Rust for AI inference?", "ES": "\u00bfCu\u00e1l es un beneficio principal de usar Rust para inferencia de IA?"}, "options": {"EN": ["More libraries than Python", "Lower memory footprint and higher execution speed", "It is easier to write than Python"], "ES": ["M\u00e1s librer\u00edas que Python", "Menor huella de memoria y mayor velocidad de ejecuci\u00f3n", "Es m\u00e1s f\u00e1cil de escribir que Python"]}, "correctIndex": 1, "explanation": {"EN": "Rust eliminates the overhead of the Python interpreter and provides safe, high-performance memory management.", "ES": "Rust elimina la sobrecarga del int\u00e9rprete de Python y provee una gesti\u00f3n de memoria segura y de alto rendimiento."}}]', NULL, '[{"id": "q-ai-1", "question": {"EN": "What is a primary benefit of using Rust for AI inference?", "E