INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('898cad9d-bd7e-56f1-9c18-543b46485883', 'rust-web3', '{"EN": "Blockchain & WASM", "ES": "Blockchain y WASM"}', '{"EN": "Build decentralized systems, smart contracts tools, and WASM modules for the web. From bindgen to cryptography.", "ES": "Construye sistemas descentralizados, herramientas de contratos inteligentes y m\u00f3dulos WASM. Desde bindgen hasta criptograf\u00eda."}', 'Advanced', 'https://placehold.co/800x500/151515/E69F88/png?text=Web3+%26+WASM&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('7e513952-e999-5069-bfe1-36ccd3de0420', '898cad9d-bd7e-56f1-9c18-543b46485883', '{"EN": "1. Advanced WebAssembly Architecture", "ES": "1. Arquitectura Avanzada WebAssembly"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('df047635-303f-5cd6-a6de-5cdbca87ce6f', '7e513952-e999-5069-bfe1-36ccd3de0420', '{"EN": "The WASM Stack Machine & Linear Memory", "ES": "Stack Machine y Memoria Lineal"}', '{"EN": "# The Abstract Machine\nWebAssembly is not just \"bytecode for the web\"; it is a distinct architecture based on a **Stack Machine**. Unlike x86 or ARM (Register Machines), WASM instructions push and pop values from an implicit operand stack.\n\n## Linear Memory Model\nWASM has no access to the host''s memory address space. It operates in a sandboxed, contiguous byte array called **Linear Memory**.\n*   **Structure**: It is a resizable ArrayBuffer.\n*   **Pages**: Memory grows in 64KB pages.\n*   **Addressing**: Pointers are simply `u32` offsets (indices) into this array. This implies a hard limit of 4GB addressable memory for `wasm32`.\n\n## The \"Harvard Architecture\" Nuance\nWASM separates code and data.\n1.  **Code**: Stored in a separate address space, unreadable and unwritable by the program itself (preventing Code Injection attacks).\n2.  **Data**: Stored in Linear Memory (Stack and Heap mixed together).\n3.  **The Stack**: Note that WASM has *two* stacks. The \"Execution Stack\" (trusted, managed by the VM, holds return addresses) and the \"Linear Memory Stack\" (untrusted, managed by Rust shadow stack pointer, holds local variables).\n\n## Table of Indirect Functions\nSince code memory is inaccessible, function pointers are implemented using **Tables**. A table is an array of opaque function references. A \"function pointer\" in Rust compiles to an index into this table using the `call_indirect` instruction.", "ES": "# La M\u00e1quina Abstracta\nWebAssembly no es solo \"bytecode para la web\"; es una arquitectura distinta basada en una **M\u00e1quina de Pila (Stack Machine)**. A diferencia de x86 o ARM (M\u00e1quinas de Registros), las instrucciones WASM hacen push y pop en una pila de operandos impl\u00edcita.\n\n## Modelo de Memoria Lineal\nWASM no tiene acceso al espacio de direcciones del host. Opera en un array de bytes contiguos y aislado llamado **Memoria Lineal**.\n*   **Estructura**: Es un ArrayBuffer redimensionable.\n*   **P\u00e1ginas**: La memoria crece en p\u00e1ginas de 64KB.\n*   **Direccionamiento**: Los punteros son simples offsets `u32` (\u00edndices) en este array. Esto implica un l\u00edmite duro de 4GB para `wasm32`.\n\n## El Matiz de \"Arquitectura Harvard\"\nWASM separa c\u00f3digo y datos.\n1.  **C\u00f3digo**: En un espacio separado, ilegible e inescribible por el programa (previene inyecci\u00f3n de c\u00f3digo).\n2.  **Datos**: En Memoria Lineal (Stack y Heap mezclados).\n3.  **Las Pilas**: WASM tiene *dos* stacks. El \"Stack de Ejecuci\u00f3n\" (confiable, gestionado por la VM, guarda direcciones de retorno) y el \"Stack de Memoria Lineal\" (no confiable, gestionado por el puntero de stack de Rust, guarda variables locales).\n\n## Tabla de Funciones Indirectas\nComo la memoria de c\u00f3digo es inaccesible, los punteros a funci\u00f3n usan **Tablas**. Una tabla es un array de referencias opacas. Un \"puntero a funci\u00f3n\" en Rust compila a un \u00edndice en esta tabla usando la instrucci\u00f3n `call_indirect`."}', false, NULL, NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, E'// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, E'// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, E'// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', NULL, '// Representation of Linear Memory in JS\nconst memory = new WebAssembly.Memory({ initial: 10, maximum: 100 });\nconst buffer = new Uint8Array(memory.buffer);\n\n// Rust pointer (u32) simply points to an index here\n// If Rust returns pointer ''1024'', JS reads:\n// buffer.slice(1024, 1024 + length)', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('8caf0c00-7931-5c2d-b92e-9a57c196f83d', '7e513952-e999-5069-bfe1-36ccd3de0420', '{"EN": "Wasm-Bindgen Internals (ABI)", "ES": "Internos de Wasm-Bindgen (ABI)"}', '{"EN": "# Crossing the Boundary\nRust types (`String`, `Struct`) do not exist in WASM. WASM only understands `i32`, `i64`, `f32`, `f64`. So how do we pass a String?\n\n## The Bindgen Protocol\nWhen you use `#[wasm_bindgen]`, the macro generates elaborate glue code (shims).\n\n### Rust to JS (Returning a String)\n1.  Rust allocates memory in the Linear Memory for the string bytes (UTF-8).\n2.  Rust returns two `i32` values: the **pointer** (offset) and the **length**.\n3.  Since WASM functions can typically return only one value (historically), bindgen usually writes these two values into a shared memory location or uses Multi-Value returns.\n4.  The generated JS wrapper reads the pointer/length, slices the `WebAssembly.Memory`, and uses `TextDecoder` to create a JS String.\n5.  Finally, Rust must free that memory if ownership was transferred.\n\n### JS to Rust (Passing Objects)\nWASM cannot hold a reference to a JS Object (GC root).\n1.  **Heap Table**: The generated JS glue code maintains a standard array `heap = []`.\n2.  When passing an object to Rust, JS puts the object in `heap[i]`.\n3.  JS passes the index `i` (`u32`) to WASM.\n4.  Rust treats this `u32` as a handle (`JsValue`). To use it, Rust calls import functions, passing the index back to JS.\n\n## Overhead\nEvery boundary crossing involves:\n*   UTF-8 encoding/decoding (O(n)).\n*   Serialization (if using Serde).\n*   Table lookups.\n**Optimization Rule**: Minimize \"chattiness\". Don''t call small functions in a loop across the boundary. Batch data.", "ES": "# Cruzando la Frontera\nLos tipos Rust no existen en WASM. WASM solo entiende n\u00fameros. \u00bfC\u00f3mo pasamos un String?\n\n## El Protocolo Bindgen\nCuando usas `#[wasm_bindgen]`, la macro genera c\u00f3digo pegamento complejo.\n\n### Rust a JS (Retornar String)\n1.  Rust asigna memoria en la Memoria Lineal para los bytes (UTF-8).\n2.  Rust retorna dos `i32`: el **puntero** y la **longitud**.\n3.  El envoltorio JS lee el puntero/longitud, hace slice de `WebAssembly.Memory`, y usa `TextDecoder` para crear un String JS.\n4.  Finalmente, Rust debe liberar esa memoria si se transfiri\u00f3 la propiedad.\n\n### JS a Rust (Pasar Objetos)\nWASM no puede tener referencias a Objetos JS (GC).\n1.  **Tabla Heap**: El c\u00f3digo JS generado mantiene un array `heap = []`.\n2.  Al pasar un objeto, JS lo pone en `heap[i]`.\n3.  JS pasa el \u00edndice `i` (`u32`) a WASM.\n4.  Rust trata este `u32` como un handle (`JsValue`).\n\n## Sobrecarga\nCada cruce implica encoding UTF-8 (O(n)) o b\u00fasquedas en tabla. **Regla**: Minimiza la \"locuacidad\". No llames funciones peque\u00f1as en bucle a trav\u00e9s de la frontera."}', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('41212cf7-dc22-5714-9e31-b19d4fe80fc9', '7e513952-e999-5069-bfe1-36ccd3de0420', '{"EN": "Allocators: wee_alloc vs dlmalloc", "ES": "Allocators: wee_alloc vs dlmalloc"}', '{"EN": "# Memory Management Strategy\nRust needs a Global Allocator to manage the Heap within Linear Memory (implementation of `malloc`/`free`).\n\n## dlmalloc (Default)\nRust uses a port of `dlmalloc` by default.\n*   **Pros**: Fast, efficient, handles fragmentation well.\n*   **Cons**: Adds ~20KB of code size to your `.wasm` binary.\n\n## wee_alloc\nOptimized for code size.\n*   **Pros**: Adds only ~1KB overhead.\n*   **Cons**: Much slower. **It does not release memory back to the OS/Page**. It relies on memory growing infinitely until the tab is closed. It is often a \"bump allocator\" with minimal reuse logic.\n*   **Status**: Currently unmaintained/deprecated in favor of `lol_alloc` or optimizing standard allocators, but crucial to understand for historical WASM optimization context.\n\n## Custom Allocators\nIn advanced Web3 cryptography (e.g., ZK Provers), you might implement a custom allocator to align memory to specific boundaries required by SIMD instructions (if enabled via `wasm_simd128`).", "ES": "# Estrategia de Gesti\u00f3n de Memoria\nRust necesita un Allocator Global para gestionar el Heap dentro de la Memoria Lineal.\n\n## dlmalloc (Por defecto)\n*   **Pros**: R\u00e1pido, eficiente, maneja bien la fragmentaci\u00f3n.\n*   **Contras**: A\u00f1ade ~20KB al binario `.wasm`.\n\n## wee_alloc\nOptimizado para tama\u00f1o.\n*   **Pros**: Solo ~1KB de sobrecarga.\n*   **Contras**: Mucho m\u00e1s lento. **No libera memoria**. Depende de que la memoria crezca hasta cerrar la pesta\u00f1a.\n*   **Estado**: Actualmente descontinuado a favor de `lol_alloc`.\n\n## Allocators Personalizados\nEn criptograf\u00eda Web3 avanzada (ej. ZK Provers), podr\u00edas implementar un allocator propio para alinear memoria a l\u00edmites espec\u00edficos requeridos por instrucciones SIMD."}', false, NULL, NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = [\"wee_alloc\"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, E'// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, E'// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, E'// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = [\"wee_alloc\"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = [\"wee_alloc\"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = ["wee_alloc"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', NULL, '// Configuring a custom allocator\n// Cargo.toml: features = [\"wee_alloc\"]\n\n#[global_allocator]\nstatic ALLOC: wee_alloc::WeeAlloc = wee_alloc::WeeAlloc::INIT;', 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('7307c5cf-f2d6-5218-adb5-1d58f7da25ba', '7e513952-e999-5069-bfe1-36ccd3de0420', '{"EN": "Quiz: Advanced Architecture", "ES": "Quiz: Arquitectura Avanzada"}', '{"EN": "Comprehensive check on internals.", "ES": "Chequeo exhaustivo de internos."}', true, NULL, '[{"id": "q-w3-1", "question": {"EN": "Why is passing a String from Rust to JS O(n)?", "ES": "\u00bfPor qu\u00e9 pasar un String de Rust a JS es O(n)?"}, "options": {"EN": ["Because references are slow", "Because the bytes must be copied and decoded from Linear Memory to the JS Heap", "Because of table lookups"], "ES": ["Porque las referencias son lentas", "Porque los bytes deben copiarse y decodificarse de Memoria Lineal al Heap de JS", "Por b\u00fasquedas en tabla"]}, "correctIndex": 1, "explanation": {"EN": "JS cannot read Rust memory directly as a String. It must read the raw bytes from the ArrayBuffer and create a new JS String object (copying data).", "ES": "JS no puede leer memoria Rust directamente como String. Debe leer bytes crudos del ArrayBuffer y crear un nuevo objeto String JS (copia)."}}, {"id": "q-w3-2", "question": {"EN": "What technically is a `JsValue` in Rust?", "ES": "\u00bfQu\u00e9 es t\u00e9cnicamente un `JsValue` en Rust?"}, "options": {"EN": ["A pointer to a C++ object", "A u32 index into a JS-side array", "A direct reference to V8 memory"], "ES": ["Un puntero a objeto C++", "Un \u00edndice u32 en un array del lado de JS", "Una referencia directa a memoria V8"]}, "correctIndex": 1, "explanation": {"EN": "`wasm-bindgen` maintains a `heap` array in JS. The `JsValue` holds the index to locate the object in that array.", "ES": "`wasm-bindgen` mantiene un array `heap` en JS. `JsValue` guarda el \u00edndice para ubicar el objeto all\u00ed."}}, {"id": "q-w3-3", "question": {"EN": "How does WASM prevent Code Injection attacks?", "ES": "\u00bfC\u00f3mo previene WASM ataques de Inyecci\u00f3n de C\u00f3digo?"}, "options": {"EN": ["By scanning code with antivirus", "Harvard Architecture: Code memory is separate and unwriteable", "Using a firewall"], "ES": ["Escaneando con antivirus", "Arquitectura Harvard: La memoria de c\u00f3digo es separada y no escribible", "Usando firewall"]}, "correctIndex": 1, "explanation": {"EN": "The running program cannot access instructions as data. It cannot overwrite its own code at runtime.", "ES": "El programa en ejecuci\u00f3n no puede acceder instrucciones como datos. No puede sobrescribir su propio c\u00f3digo en runtime."}}, {"id": "q-w3-4", "question": {"EN": "What happens if you use `std::fs::File::create` in `wasm32-unknown-unknown`?", "ES": "\u00bfQu\u00e9 pasa si usas `std::fs::File::create` en `wasm32-unknown-unknown`?"}, "options": {"EN": ["It creates a file in local storage", "It creates a file on the server", "It compiles but panics/fails at runtime"], "ES": ["Crea archivo en local storage", "Crea archivo en servidor", "Compila pero entra en p\u00e1nico/falla en runtime"]}, "correctIndex": 2, "explanation": {"EN": "The target has stub implementations for FS that simply return ''Unsupported'' errors or panic.", "ES": "El target tiene implementaciones ''stub'' para FS que simplemente retornan errores ''No soportado'' o p\u00e1nico."}}]', NULL, '[{"id": "q-w3-1", "question": {"EN": "Why is passing a String from Rust to JS O(n)?", "ES": "\u00bfPor qu\u00e9 pasar un String de Rust a JS es O(n)?"}, "options": {"EN": ["Because references are slow", "Because the bytes must be copied and decoded from Linear Memory to the JS Heap", "Because of table lookups"], "ES": ["Porque las referencias son lentas", "Porque los bytes deben copiarse y decodificarse de Memoria Lineal al Heap de JS", "Por b\u00fasquedas en tabla"]}, "correctIndex": 1, "explanation": {"EN": "JS cannot read Rust memory directly as a String. It must read the raw bytes from the ArrayBuffer and create a new JS String object (copying data).", "ES": "JS no puede leer memoria Rust directamente como String. Debe leer bytes crudos del ArrayBuffer y crear un nuevo objeto String JS (copia)."}}, {"id": "q-w3-2", "question": {"EN": "What technically is a `JsValue` in Rust?", "ES": "\u00bfQu\u00e9 es t\u00e9cnicamente un `JsValue` en Rust?"}, "options": {"EN": ["A pointer to a C++ object", "A u32 index into a JS-side array", "A direct reference to V8 memory"], "ES": ["Un puntero a objeto C++", "Un \u00edndice u32 en un array del lado de JS", "Una referencia directa a memoria V8"]}, "correctIndex": 1, "explanation": {"EN": "`wasm-bindgen` maintains a `heap` array in JS. The `JsValue` holds the index to locate the object in that array.", "ES": "`wasm-bindgen` mantiene un array `heap` en JS. `JsValue` guarda el \u00edndice para ubicar el objeto all\u00ed."}}, {"id": "q-w3-3", "question": {"EN": "How does WASM prevent Code Injection attacks?", "ES": "\u00bfC\u00f3mo previene WASM ataques de Inyecci\u00f3n de C\u00f3digo?"}, "options": {"EN": ["By scanning code with antivirus", "Harvard Architecture: Code memory is separate and unwriteable", "Using a firewall"], "ES": ["Escaneando con antivirus", "Arquitectura Harvard: La memoria de c\u00f3digo es separada y no escribible", "Usando firewall"]}, "correctIndex": 1, "explanation": {"EN": "The running program cannot access instructions as data. It cannot overwrite its own code at runtime.", "ES": "El programa en ejecuci\u00f3n no puede acceder instrucciones como datos. No puede sobrescribir su propio c\u00f3digo en runtime."}}, {"id": "q-w3-4", "question": {"EN": "What happens if you use `std::fs::File::create` in `wasm32-unknown-unknown`?", "ES": "\u00bfQu\u00e9 pasa si usas `std::fs::File::create` en `wasm32-unknown-unknown`?"}, "options": {"EN": ["It creates a file in local storage", "It creates a file on the server", "It compiles but panics/fails at runtime"], "ES": ["Crea archivo en local storage", "Crea archivo en servidor", "Compila pero entra en p\u00e1nico/falla en runtime"]}, "correctIndex": 2, "explanation": {"EN": "The target has stub implementations for FS that simply return ''Unsupported'' errors or panic.", "ES": "El target tiene implementaciones ''stub'' para FS que simplemente retornan errores ''No soportado'' o p\u00e1nico."}}]', NULL, '[{"id": "q-w3-1", "question": {"EN": "Why is passing a String from Rust to JS O(n)?", "ES": "\u00bfPor qu\u00e9 pasar un String de Rust a JS es O(n)?"}, "options": {"EN": ["Because references are slow", "Because the bytes must be copied and decoded from Linear Memory to the JS Heap", "Because of table lookups"], "ES": ["Porque las referencias son lentas", "Porque los bytes deben copiarse y decodificarse de Memoria Lineal al Heap de JS", "Por b\u00fasquedas en tabla"]}, "correctIndex": 1, "explanation": {"EN": "JS cannot read Rust memory directly as a String. It must read the raw bytes from the ArrayBuffer and create a new JS String object (copying data).", "ES": "JS no puede leer memoria Rust directamente como String. Debe leer bytes crudos del ArrayBuffer y crear un nuevo objeto String JS (copia)."}}, {"id": "q-w3-2", "question": {"EN": "What technically is a `JsValue` in Rust?", "ES": "\u00bfQu\u00e9 es t\u00e9cnicamente un `JsValue` en Rust?"}, "options": {"EN": ["A pointer to a C++ object", "A u32 index into a JS-side array", "A direct reference to V8 memory"], "ES": ["Un puntero a objeto C++", "Un \u00edndice u32 en un array del lado de JS", "Una referencia directa a memoria V8"]}, "correctIndex": 1, "explanation": {"EN": "`wasm-bindgen` maintains a `heap` array in JS. The `JsValue` holds the index to locate the object in that array.", "ES": "`wasm-bindgen` mantiene un array `heap` en JS. `JsValue` guarda el \u00edndice para ubicar el objeto all\u00ed."}}, {"id": "q-w3-3", "question": {"EN": "How does WASM prevent Code Injection attacks?", "ES": "\u00bfC\u00f3mo previene WASM ataques de Inyecci\u00f3n de C\u00f3digo?"}, "options": {"EN": ["By scanning code with antivirus", "Harvard Architecture: Code memory is separate and unwriteable", "Using a firewall"], "ES": ["Escaneando con antivirus", "Arquitectura Harvard: La memoria de c\u00f3digo es separada y no escribible", "Usando firewall"]}, "correctIndex": 1, "explanation": {"EN": "The running program cannot access instructions as data. It cannot overwrite its own code at runtime.", "ES": "El programa en ejecuci\u00f3n no puede acceder instrucciones como datos. No puede sobrescribir su propio c\u00f3digo en runtime."}}, {"id": "q-w3-4", "question": {"EN": "What happens if you use `std::fs::File::create` in `wasm32-unknown-unknown`?", "ES": "\u00bfQu\u00e9 pasa si usas `std::fs::File::create` en `wasm32-unknown-unknown`?"}, "options": {"EN": ["It creates a file in local storage", "It creates a file on the server", "It compiles but panics/fails at runtime"], "ES": ["Crea archivo en local storage", "Crea archivo en servidor", "Compila pero entra en p\u00e1nico/falla en runtime"]}, "correctIndex": 2, "explanation": {"EN": "The target has stub implementations for FS that simply return ''Unsupported'' errors or panic.", "ES": "El target tiene implementaciones ''stub'' para FS que simplemente retornan errores ''No soportado'' o p\u00e1nico."}}]', NULL, '[{"id": "q-w3-1", "question": {"EN": "Why is passing a String from Rust to JS O(n)?", "ES": "\u00bfPor qu\u00e9 pasar un String de Rust a JS es O(n)?"}, "options": {"EN": ["Because references are slow", "Because the bytes must be copied and decoded from Linear Memory to the JS Heap", "Because of table lookups"], "ES": ["Porque las referencias son lentas", "Porque los bytes deben copiarse y decodificarse de Memoria Lineal al Heap de JS", "Por b\u00fasquedas en tabla"]}, "correctIndex": 1, "explanation": {"EN": "JS cannot read Rust memory directly as a String. It must read the raw bytes from the ArrayBuffer and create a new JS String object (copying data).", "ES": "JS no puede leer memoria Rust directamente como String. Debe leer bytes crudos del ArrayBuffer y crear un nuevo objeto String JS (copia)."}}, {"id": "q-w3-2", "question": {"EN": "What technically is a `JsValue` in Rust?", "ES": "\u00bfQu\u00e9 es t\u00e9cnicamente un `JsValue` en Rust?"}, "options": {"EN": ["A pointer to a C++ object", "A u32 index into a JS-side array", "A direct reference to V8 memory"], "ES": ["Un puntero a objeto C++", "Un \u00edndice u32 en un array del lado de JS", "Una referencia directa a memoria V8"]}, "correctIndex": 1, "explanation": {"EN": "`wasm-bindgen` maintains a `heap` array in JS. The `JsValue` holds the index to locate the object in that array.", "ES": "`wasm-bindgen` mantiene un array `heap` en JS. `JsValue` guarda el \u00edndice para ubicar el objeto all\u00ed."}}, {"id": "q-w3-3", "question": {"EN": "How does WASM prevent Code Injection attacks?", "ES": "\u00bfC\u00f3mo previene WASM ataques de Inyecci\u00f3n de C\u00f3digo?"}, "options": {"EN": ["By scanning code with antivirus", "Harvard Architecture: Code memory is separate and unwriteable", "Using a firewall"], "ES": ["Escaneando con antivirus", "Arquitectura Harvard: La memoria de c\u00f3digo es separada y no escribible", "Usando firewall"]}, "correctIndex": 1, "explanation": {"EN": "The running program cannot access instructions as data. It cannot overwrite its own code at runtime.", "ES": "El programa en ejecuci\u00f3n no puede acceder instrucciones como datos. No puede sobrescribir su propio c\u00f3digo en runtime."}}, {"id": "q-w3-4", "question": {"EN": "What happens if you use `std::fs::File::create` in `wasm32-unknown-unknown`?", "ES": "\u00bfQu\u00e9 pasa si usas `std::fs::File::create` en `wasm32-unknown-unknown`?"}, "options": {"EN": ["It creates a file in local storage", "It creates a file on the server", "It compiles but panics/fails at runtime"], "ES": ["Crea archivo en local storage", "Crea archivo en servidor", "Compila pero entra en p\u00e1nico/falla en runtime"]}, "correctIndex": 2, "explanation": {"EN": "The target has stub implementations for FS that simply return ''Uns