 en `wasm32-unknown-unknown`?"}, "options": {"EN": ["It creates a file in local storage", "It creates a file on the server", "It compiles but panics/fails at runtime"], "ES": ["Crea archivo en local storage", "Crea archivo en servidor", "Compila pero entra en p\u00e1nico/falla en runtime"]}, "correctIndex": 2, "explanation": {"EN": "The target has stub implementations for FS that simply return ''Unsupported'' errors or panic.", "ES": "El target tiene implementaciones ''stub'' para FS que simplemente retornan errores ''No soportado'' o p\u00e1nico."}}]', NULL, 4);
INSERT INTO modules (id, course_id, title, "order") VALUES ('b50aa425-ea5a-5213-93d5-5fa8c8a0b1c5', '898cad9d-bd7e-56f1-9c18-543b46485883', '{"EN": "2. The web-sys Ecosystem", "ES": "2. El Ecosistema web-sys"}', 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('5d427b1d-4103-51f4-9d2e-d562cf96d82b', 'b50aa425-ea5a-5213-93d5-5fa8c8a0b1c5', '{"EN": "The DOM & Feature Flags", "ES": "El DOM y Feature Flags"}', '{"EN": "# Feature Flags Hell\nThe `web-sys` crate maps the entire Web IDL specifications to Rust. It is massive. To keep compile times sane, everything is gated behind feature flags.\n*   If you want `window.document`, you need `features = [\"Window\", \"Document\"]`.\n*   If you want `element.add_event_listener`, you need `features = [\"EventTarget\"]`.\nMissing a flag results in methods simply \"not existing\" on the struct.\n\n## Type Hierarchy & Casting\nThe DOM is object-oriented (`HTMLDivElement` inherits `HTMLElement` inherits `Element` inherits `Node` inherits `EventTarget`).\nRust structs don''t inherit. `web-sys` uses the `AsRef` and `From` traits for upcasting, and `wasm_bindgen::JsCast` for downcasting.\n*   **Upcast**: `let target: &EventTarget = div.as_ref();` (Safe, zero cost).\n*   **Downcast**: `let canvas: HtmlCanvasElement = element.dyn_into().unwrap();` (Runtime check, instanceOf).", "ES": "# Infierno de Feature Flags\n`web-sys` mapea todas las especificaciones Web IDL a Rust. Es masivo. Todo est\u00e1 detr\u00e1s de flags.\n*   Si quieres `window.document`, necesitas `features = [\"Window\", \"Document\"]`.\n*   Si quieres `element.add_event_listener`, necesitas `features = [\"EventTarget\"]`.\n\n## Jerarqu\u00eda de Tipos y Casting\nEl DOM es orientado a objetos. Los structs de Rust no heredan.\n*   **Upcast** (Subir): Usa `AsRef`. `let target: &EventTarget = div.as_ref();` (Seguro).\n*   **Downcast** (Bajar): Usa `JsCast`. `let canvas: HtmlCanvasElement = element.dyn_into().unwrap();` (Chequeo en runtime)."}', false, NULL, NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context("2d").unwrap();\n    }\n}', NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context("2d").unwrap();\n    }\n}', NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context("2d").unwrap();\n    }\n}', NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context("2d").unwrap();\n    }\n}', NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context("2d").unwrap();\n    }\n}', NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context("2d").unwrap();\n    }\n}', NULL, 'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now we have canvas methods\n        canvas.get_context(\"2d\").unwrap();\n    }\n}', NULL, E'use wasm_bindgen::JsCast;\nuse web_sys::{HtmlCanvasElement, HtmlDivElement};\n\nfn handle_element(element: HtmlDivElement) {\n    // Upcasting to Node (Automatic via Deref or explicit AsRef)\n    let node: &web_sys::Node = element.as_ref();\n    \n    // Trying to cast generic Element to Canvas\n    // Equivalent to JS: if (element instanceof HTMLCanvasElement)\n    if let Ok(canvas) = element.dyn_into::<HtmlCanvasElement>() {\n        // Now 