INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('793176a6-0519-527a-9971-c52d7a626647', 'b50aa425-ea5a-5213-93d5-5fa8c8a0b1c5', '{"EN": "Closures & Memory Leaks", "ES": "Closures y Fugas de Memoria"}', '{"EN": "# The Lifetime Mismatch\nJS Event Listeners are long-lived. Rust closures passed to them usually die at the end of the creating function scope.\nTo pass a closure to `addEventListener`, it must be valid for the lifetime `''static`.\n\n## The Closure::wrap Pattern\n1.  **Wrap**: `Closure::wrap(Box::new(move |event| { ... }))`. This moves the Rust closure to the Heap.\n2.  **Convert**: Turn it into a `Function` or `JsValue` to pass to JS.\n3.  **Forget**: Crucial step. If you drop the `Closure` struct in Rust, it removes the handle from the JS side, effectively killing the listener. For infinite listeners (like clicks), we must intentionally **leak** memory using `closure.forget()` so JS keeps it alive.\n4.  **Drop**: For one-off listeners, you must manually manage the Drop to prevent memory leaks over time.", "ES": "# Desajuste de Lifetimes\nLos Listeners de JS viven mucho tiempo. Los closures de Rust mueren al final del \u00e1mbito.\n\n## El Patr\u00f3n Closure::wrap\n1.  **Wrap**: `Closure::wrap(...)`. Mueve el closure al Heap.\n2.  **Convertir**: A `Function` o `JsValue`.\n3.  **Forget (Olvidar)**: Paso crucial. Si eliminas el struct `Closure`, matas el listener. Para listeners infinitos, debemos **fugar** memoria intencionalmente con `closure.forget()`.\n4.  **Drop**: Para listeners de un solo uso, debes gestionar manualmente el Drop para evitar fugas."}', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('d4bad756-41f7-526c-9bc4-85be72194a29', 'b50aa425-ea5a-5213-93d5-5fa8c8a0b1c5', '{"EN": "Async: Futures vs Promises", "ES": "Async: Futuros vs Promesas"}', '{"EN": "# The Bridge\n*   **Rust**: Poll-based Futures. Lazy.\n*   **JS**: Callback-based Promises. Eager.\n\n## wasm-bindgen-futures\nThis crate bridges the gap.\n*   **JsFuture::from(promise)**: Takes a JS Promise, creates a Rust Future. When polled, it attaches a `.then()` callback to the Promise that wakes up the Waker.\n*   **future_to_promise(future)**: Takes a Rust Future, spawns it on a local executor (on the microtask queue), and returns a JS Promise.\n\n## Spawn Local\nUnlike Tokio which uses thread pools, WASM is single-threaded (mostly). `wasm_bindgen_futures::spawn_local` runs the future on the current thread, yielding to the JS Event Loop on every await.", "ES": "# El Puente\n*   **Rust**: Futuros basados en Poll. Perezosos.\n*   **JS**: Promesas basadas en Callbacks. Ansiosas.\n\n## wasm-bindgen-futures\n*   **JsFuture::from**: Convierte Promesa a Futuro. Adjunta un `.then()` que despierta el Waker.\n*   **future_to_promise**: Convierte Futuro a Promesa. Lo lanza en la cola de microtareas.\n\n## Spawn Local\nWASM es single-threaded. `spawn_local` corre el futuro en el hilo actual, cediendo al Event Loop de JS en cada await."}', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('361505a8-dab0-54da-911a-3d4a27bf847e', 'b50aa425-ea5a-5213-93d5-5fa8c8a0b1c5', '{"EN": "Quiz: Web Sys", "ES": "Quiz: Web Sys"}', '{"EN": "Check DOM manipulation mastery.", "ES": "Revisar maestr\u00eda en manipulaci\u00f3n DOM."}', true, NULL, '[{"id": "q-w3-2-1", "question": {"EN": "Why must we invoke `forget()` on a Closure passed to an event listener?", "ES": "\u00bfPor qu\u00e9 debemos invocar `forget()` en un Closure pasado a un event listener?"}, "options": {"EN": ["To optimize performance", "To prevent Rust from dropping the memory, which would invalidate the JS callback", "It is optional"], "ES": ["Para optimizar rendimiento", "Para evitar que Rust libere la memoria, invalidando el callback JS", "Es opcional"]}, "correctIndex": 1, "explanation": {"EN": "Rust''s ownership model drops values when they go out of scope. JS needs the function to stay alive. `forget()` leaks it intentionally.", "ES": "El modelo de ownership de Rust libera valores al salir de \u00e1mbito. JS necesita que la funci\u00f3n siga viva. `forget()` la fuga intencionalmente."}}, {"id": "q-w3-2-2", "question": {"EN": "How does `wasm_bindgen_futures` execute Rust async code?", "ES": "\u00bfC\u00f3mo ejecuta `wasm_bindgen_futures` c\u00f3digo async de Rust?"}, "options": {"EN": ["It creates a new OS thread", "It blocks the browser until finished", "It schedules tasks on the JS Microtask Queue (Event Loop)"], "ES": ["Crea un nuevo hilo del SO", "Bloquea el navegador hasta terminar", "Agenda tareas en la Microtask Queue de JS (Event Loop)"]}, "correctIndex": 2, "explanation": {"EN": "It integrates with the JS Event Loop, allowing Rust futures to yield control back to the browser UI.", "ES": "Se integra con el Event Loop de JS, permitiendo a los futuros de Rust ceder control a la UI del navegador."}}, {"id": "q-w3-2-3", "question": {"EN": "What happens if you try to use `window()` without enabling the ''Window'' feature in Cargo.toml?", "ES": "\u00bfQu\u00e9 pasa si intentas usar `window()` sin habilitar la feature ''Window''?"}, "options": {"EN": ["Runtime Error", "Compiler Error (Function not found)", "It returns null"], "ES": ["Error de Runtime", "Error de Compilaci\u00f3n (Funci\u00f3n no encontrada)", "Retorna null"]}, "correctIndex": 1, "explanation": {"EN": "The function definition is literally compiled out via `#[cfg(feature = ...)]`.", "ES": "La definici\u00f3n de la funci\u00f3n es literalmente excluida de la compilaci\u00f3n v\u00eda `#[cfg(feature = ...)]`."}}]', NULL, '[{"id": "q-w3-2-1", "question": {"EN": "Why must we invoke `forget()` on a Closure passed to an event listener?", "ES": "\u00bfPor qu\u00e9 debemos invocar `forget()` en un Closure pasado a un event listener?"}, "options": {"EN": ["To optimize performance", "To prevent Rust from dropping the memory, which would invalidate the JS callback", "It is optional"], "ES": ["Para optimizar rendimiento", "Para evitar que Rust libere la memoria, invalidando el callback JS", "Es opcional"]}, "correctIndex": 1, "explanation": {"EN": "Rust''s ownership model drops values when they go out of scope. JS needs the function to stay alive. `forget()` leaks it intentionally.", "ES": "El modelo de ownership de Rust libera valores al salir de \u00e1mbito. JS necesita que la funci\u00f3n siga viva. `forget()` la fuga intencionalmente."}}, {"id": "q-w3-2-2", "question": {"EN": "How does `wasm_bindgen_futures` execute Rust async code?", "ES": "\u00bfC\u00f3mo ejecuta `wasm_bindgen_futures` c\u00f3digo async de Rust?"}, "options": {"EN": ["It creates a new OS thread", "It blocks the browser until finished", "It schedules tasks on the JS Microtask Queue (Event Loop)"], "ES": ["Crea un nuevo hilo del SO", "Bloquea el navegador hasta terminar", "Agenda tareas en la Microtask Queue de JS (Event Loop)"]}, "correctIndex": 2, "explanation": {"EN": "It integrates with the JS Event Loop, allowing Rust futures to yield control back to the browser UI.", "ES": "Se integra con el Event Loop de JS, permitiendo a los futuros de Rust ceder control a la UI del navegador."}}, {"id": "q-w3-2-3", "question": {"EN": "What happens if you try to use `window()` without enabling the ''Window'' feature in Cargo.toml?", "ES": "\u00bfQu\u00e9 pasa si intentas usar `window()` sin habilitar la feature ''Window''?"}, "options": {"EN": ["Runtime Error", "Compiler Error (Function not found)", "It returns null"], "ES": ["Error de Runtime", "Error de Compilaci\u00f3n (Funci\u00f3n no encontrada)", "Retorna null"]}, "correctIndex": 1, "explanation": {"EN": "The function definition is literally compiled out via `#[cfg(feature = ...)]`.", "ES": "La definici\u00f3n de la funci\u00f3n es literalmente excluida de la compilaci\u00f3n v\u00eda `#[cfg(feature = ...)]`."}}]', NULL, '[{"id": "q-w3-2-1", "question": {"EN": "Why must we invoke `forget()` on a Closure passed to an event listener?", "ES": "\u00bfPor qu\u00e9 debemos invocar `forget()` en un Closure pasado a un event listener?"}, "options": {"EN": ["To optimize performance", "To prevent Rust from dropping the memory, which would invalidate the JS callback", "It is optional"], "ES": ["Para optimizar rendimiento", "Para evitar que Rust libere la memoria, invalidando el callback JS", "Es opcional"]}, "correctIndex": 1, "explanation": {"EN": "Rust''s ownership model drops values when they go out of scope. JS needs the function to stay alive. `forget()` leaks it intentionally.", "ES": "El modelo de ownership de Rust libera valores al salir de \u00e1mbito. JS necesita que la funci\u00f3n siga viva. `forget()` la fuga intencionalmente."}}, {"id": "q-w3-2-2", "question": {"EN": "How does `wasm_bindgen_futures` execute Rust async code?", "ES": "\u00bfC\u00f3mo ejecuta `wasm_bindgen_futures` c\u00f3digo async de Rust?"}, "options": {"EN": ["It creates a new OS thread", "It blocks the browser until finished", "It schedules tasks on the JS Microtask Queue (Event Loop)"], "