INSERT INTO modules (id, course_id, title, "order") VALUES ('b4ec7c98-fa37-5a7f-9792-3247a50bbb1e', '898cad9d-bd7e-56f1-9c18-543b46485883', '{"EN": "5. EVM Integration (Alloy)", "ES": "5. Integraci\u00f3n EVM (Alloy)"}', 5);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('4695b7a9-bae1-5265-9e89-5747f9123cb4', 'b4ec7c98-fa37-5a7f-9792-3247a50bbb1e', '{"EN": "Alloy Architecture", "ES": "Arquitectura Alloy"}', '{"EN": "# Alloy vs Ethers-rs\nAlloy is the next-generation Rust Ethereum library (rewrite of ethers-rs).\n*   **Performance**: Heavy use of generic specialization and fewer allocations.\n*   **WASM Support**: Designed with `wasm-bindgen` in mind. The `ReqwestClient` handles HTTP/WS transport seamlessly in both Node and Browser.\n\n## Type Safety\nAlloy maps Solidity types directly to Rust types (e.g., `solidity::uint256` -> `alloy::U256`).", "ES": "# Alloy vs Ethers-rs\nAlloy es la librer\u00eda Ethereum de siguiente generaci\u00f3n.\n*   **Rendimiento**: Uso pesado de especializaci\u00f3n gen\u00e9rica y menos asignaciones.\n*   **Soporte WASM**: Dise\u00f1ado con `wasm-bindgen` en mente.\n\n## Seguridad de Tipos\nAlloy mapea tipos Solidity directamente a Rust (ej. `U256`)."}', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('5c76b795-4e57-5a79-a837-0511e3a982d6', 'b4ec7c98-fa37-5a7f-9792-3247a50bbb1e', '{"EN": "The sol! Macro internals", "ES": "Internos de la Macro sol!"}', '{"EN": "# The sol! Macro\n`sol!` is a procedural macro that parses Solidity syntax at *compile time*.\n1.  **Input**: Solidity code (interfaces, structs, events).\n2.  **Expansion**: Generates Rust structs implementing `SolType`, `SolEvent`, etc.\n3.  **Encoding**: The generated code handles ABI encoding/decoding efficiently.\n\nThis guarantees that if your Rust code compiles, your interaction with the contract ABI is correct.", "ES": "# La Macro sol!\nEs una macro procedimental que parsea sintaxis Solidity en *tiempo de compilaci\u00f3n*.\n1.  **Entrada**: C\u00f3digo Solidity.\n2.  **Expansi\u00f3n**: Genera structs Rust implementando `SolType`.\n3.  **Codificaci\u00f3n**: El c\u00f3digo generado maneja ABI encoding.\n\nGarantiza que si tu c\u00f3digo compila, tu interacci\u00f3n con la ABI es correcta."}', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 2);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('0737a508-a463-5eb4-805a-1ca8466c8e43', 'b4ec7c98-fa37-5a7f-9792-3247a50bbb1e', '{"EN": "Signing in WASM", "ES": "Firmando en WASM"}', '{"EN": "# Signing Strategies\n1.  **Local Key**: Loading a private key into WASM memory.\n    *   *Pros*: Full control, automation.\n    *   *Cons*: **Security Risk**. If the browser is compromised (XSS), the key is stolen.\n2.  **External Provider (Metamask/EIP-1193)**:\n    *   Rust calls `window.ethereum.request`.\n    *   The signing happens in the Extension/Wallet (sandboxed).\n    *   Rust only receives the signature bytes. This is the recommended path for DApps.", "ES": "# Estrategias de Firma\n1.  **Clave Local**: Cargar clave privada en memoria WASM.\n    *   *Riesgo*: Si el navegador se compromete (XSS), la clave es robada.\n2.  **Proveedor Externo (Metamask)**:\n    *   Rust llama `window.ethereum`.\n    *   La firma ocurre en la Wallet (sandboxed).\n    *   Rust solo recibe la firma. Recomendado para DApps."}', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 3);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('68114373-018b-5462-994f-7f166b851440', 'b4ec7c98-fa37-5a7f-9792-3247a50bbb1e', '{"EN": "Quiz: EVM & Alloy", "ES": "Quiz: EVM y Alloy"}', '{"EN": "Advanced EVM checks.", "ES": "Chequeos EVM avanzados."}', true, NULL, '[{"id": "q-w3-5-1", "question": {"EN": "What is the safest way to sign transactions in a Browser DApp?", "ES": "\u00bfCu\u00e1l es la forma m\u00e1s segura de firmar transacciones en una DApp de navegador?"}, "options": {"EN": ["Store the Private Key in LocalStorage", "Hardcode the key in WASM", "Use an external provider via EIP-1193 (Metamask)"], "ES": ["Guardar la Clave Privada en LocalStorage", "Hardcodear la clave en WASM", "Usar proveedor externo v\u00eda EIP-1193 (Metamask)"]}, "correctIndex": 2, "explanation": {"EN": "Keeping the key outside the browser context prevents XSS attacks from draining funds.", "ES": "Mantener la clave fuera del contexto del navegador previene que ataques XSS roben fondos."}}, {"id": "q-w3-5-2", "question": {"EN": "What does the `sol!` macro generate?", "ES": "\u00bfQu\u00e9 genera la macro `sol!`?"}, "options": {"EN": ["Solidity Bytecode", "Rust structs and traits for ABI encoding", "A local blockchain"], "ES": ["Bytecode Solidity", "Structs y traits de Rust para codificaci\u00f3n ABI", "Una blockchain local"]}, "correctIndex": 1, "explanation": {"EN": "It creates type-safe Rust bindings that map to the Solidity definitions provided.", "ES": "Crea bindings de Rust seguros que mapean a las definiciones Solidity provistas."}}, {"id": "q-w3-5-3", "question": {"EN": "Can Alloy in WASM use TCP connections?", "ES": "\u00bfPuede Alloy en WASM usar conexiones TCP?"}, "options": {"EN": ["Yes, natively", "No, browsers restrict raw TCP. It must use HTTP or WebSockets", "Only via proxy"], "ES": ["S\u00ed, nativamente", "No, navegadores restringen TCP crudo. Debe usar HTTP o WebSockets", "Solo v\u00eda proxy"]}, "correctIndex": 1, "explanation": {"EN": "Browser sandboxing forbids raw TCP syscalls. Communication must go through standard Web APIs.", "ES": "El sandboxing del navegador proh\u00edbe syscalls TCP crudas. La comunicaci\u00f3n debe ir por Web APIs est\u00e1ndar."}}]', NULL, '[{"id": "q-w3-5-1", "question": {"EN": "What is the safest way to sign transactions in a Browser DApp?", "ES": "\u00bfCu\u00e1l es la forma m\u00e1s segura de firmar transacciones en una DApp de navegador?"}, "options": {"EN": ["Store the Private Key in LocalStorage", "Hardcode the key in WASM", "Use an external provider via EIP-1193 (Metamask)"], "ES": ["Guardar la Clave Privada en LocalStorage", "Hardcodear la clave en WASM", "Usar proveedor externo v\u00eda EIP-1193 (Metamask)"]}, "correctIndex": 2, "explanation": {"EN": "Keeping the key outside the browser context prevents XSS attacks from draining funds.", "ES": "Mantener la clave fuera del contexto del navegador previene que ataques XSS roben fondos."}}, {"id": "q-w3-5-2", "question": {"EN": "What does the `sol!` macro generate?", "ES": "\u00bfQu\u00e9 genera la macro `sol!`?"}, "options": {"EN": ["Solidity Bytecode", "Rust structs and traits for ABI encoding", "A local blockchain"], "ES": ["Bytecode Solidity", "Structs y traits de Rust para codificaci\u00f3n ABI", "Una blockchain local"]}, "correctIndex": 1, "explanation": {"EN": "It creates type-safe Rust bindings that map to the Solidity definitions provided.", "ES": "Crea bindings de Rust seguros que mapean a las definiciones Solidity provistas."}}, {"id": "q-w3-5-3", "question": {"EN": "Can Alloy in WASM use TCP connections?", "ES": "\u00bfPuede Alloy en WASM usar conexiones TCP?"}, "options": {"EN": ["Yes, natively", "No, browsers restrict raw TCP. It must use HTTP or WebSockets", "Only via proxy"], "ES": ["S\u00ed, nativamente", "No, navegadores restringen TCP crudo. Debe usar HTTP o WebSockets", "Solo v\u00eda proxy"]}, "correctIndex": 1, "explanation": {"EN": "Browser sandboxing forbids raw TCP syscalls. Communication must go through standard Web APIs.", "ES": "El sandboxing del navegador proh\u00edbe syscalls TCP crudas. La comunicaci\u00f3n debe ir por Web APIs est\u00e1ndar."}}]', NULL, '[{"id": "q-w3-5-1", "question": {"EN": "What is the safest way to sign transactions in a Browser DApp?", "ES": "\u00bfCu\u00e1l es la forma m\u00e1s segura de firmar transacciones en una DApp de navegador?"}, "options": {"EN": ["Store the Private Key in LocalStorage", "Hardcode the key in WASM", "Use an external provider via EIP-1193 (Metamask)"], "ES": ["Guardar la Clave Privada en LocalStorage", "Hardcodear la clave en WASM", "Usar proveedor externo v\u00eda EIP-1193 (Metamask)"]}, "correctIndex": 2, "explanation": {"EN": "Keeping the key outside the browser context prevents XSS attacks from draining funds.", "ES": "Mantener la clave fuera del contexto del navegador previene que ataques XSS roben fondos."}}, {"id": "q-w3-5-2", "question": {"EN": "What does the `sol!` macro generate?", "ES": "\u00bfQu\u00e9 genera la macro `sol!`?"}, "options": {"EN": ["Solidity Bytecode", "Rust structs and traits for ABI encoding", "A local blockchain"], "ES": ["Bytecode Solidity", "Structs y traits de Rust para codificaci\u00f3n ABI", "Una blockchain local"]}, "correctIndex": 1, "explanation": {"EN": "It creates type-safe Rust bindings that map to the Solidity definitions provided.", "ES": "Crea bindings de Rust seguros que mapean a las definiciones Solidity provistas."}}, {"id": "q-w3-5-3", "question": {"EN": "Can Alloy in WASM use TCP connections?", "ES": "\u00bfPuede Alloy en WASM usar conexiones TCP?"}, "options": {"EN": ["Yes, natively", "No, browsers restrict raw TCP. It must use HTTP or WebSockets", "Only via proxy"], "ES": ["S\u00ed, nativamente", "No, navegadores restringen TCP crudo. Debe usar HTTP o WebSockets", "Solo v\u00eda proxy"]}, "correctIndex": 1, "explanation": {"EN": "Browser sandboxing forbids raw TCP syscalls. Communication must go through standard Web APIs.", "ES": "El sand