INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('103749f7-221d-5075-8527-1eee518f543d', '02ab5693-1000-54c7-a6be-3c3fd28e90ce', '{"EN": "Quiz: PDAs", "ES": "Quiz: PDAs"}', '{"EN": "PDA mastery.", "ES": "Maestr\u00eda en PDAs."}', true, NULL, '[{"id": "q-sol-3-1", "question": {"EN": "Does a PDA have a private key?", "ES": "\u00bfTiene una PDA clave privada?"}, "options": {"EN": ["Yes", "No", "Only the program knows it"], "ES": ["S\u00ed", "No", "Solo el programa la conoce"]}, "correctIndex": 1, "explanation": {"EN": "PDAs are derived to be *off* the Ed25519 curve, so they have no corresponding private key.", "ES": "Las PDAs se derivan para estar *fuera* de la curva Ed25519, as\u00ed que no tienen clave privada."}}, {"id": "q-sol-3-2", "question": {"EN": "What is the ''bump''?", "ES": "\u00bfQu\u00e9 es el ''bump''?"}, "options": {"EN": ["A fee", "A seed offset to ensure the address is off-curve", "A version number"], "ES": ["Una tarifa", "Un offset de seed para asegurar que la direcci\u00f3n est\u00e9 fuera de curva", "Un n\u00famero de versi\u00f3n"]}, "correctIndex": 1, "explanation": {"EN": "It iterates (255 down to 0) to find a valid PDA address.", "ES": "Itera (255 a 0) para encontrar una direcci\u00f3n PDA v\u00e1lida."}}]', NULL, '[{"id": "q-sol-3-1", "question": {"EN": "Does a PDA have a private key?", "ES": "\u00bfTiene una PDA clave privada?"}, "options": {"EN": ["Yes", "No", "Only the program knows it"], "ES": ["S\u00ed", "No", "Solo el programa la conoce"]}, "correctIndex": 1, "explanation": {"EN": "PDAs are derived to be *off* the Ed25519 curve, so they have no corresponding private key.", "ES": "Las PDAs se derivan para estar *fuera* de la curva Ed25519, as\u00ed que no tienen clave privada."}}, {"id": "q-sol-3-2", "question": {"EN": "What is the ''bump''?", "ES": "\u00bfQu\u00e9 es el ''bump''?"}, "options": {"EN": ["A fee", "A seed offset to ensure the address is off-curve", "A version number"], "ES": ["Una ta