INSERT INTO courses (id, slug, title, description, level, image_url) VALUES ('089ec648-f6bb-5332-b784-3710c2384a53', 'polkadot-smart-contracts', '{"EN": "Polkadot Smart Contracts (ink!)", "ES": "Smart Contracts en Polkadot (ink!)"}', '{"EN": "Build next-generation WASM smart contracts for the Polkadot ecosystem using ink!. Learn storage layouts, cross-contract calls, and safe testing.", "ES": "Construye smart contracts WASM de pr\u00f3xima generaci\u00f3n para el ecosistema Polkadot usando ink!. Aprende layouts de almacenamiento, llamadas entre contratos y testing seguro."}', 'Advanced', 'https://placehold.co/800x500/E6007A/FFFFFF/png?text=Polkadot+ink!&font=roboto');
INSERT INTO modules (id, course_id, title, "order") VALUES ('6e14b4d2-f679-5131-9988-43568bf8696c', '089ec648-f6bb-5332-b784-3710c2384a53', '{"EN": "1. ink! Architecture", "ES": "1. Arquitectura ink!"}', 1);
INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('7987d479-3b44-5d76-ad99-0a933ca338eb', '6e14b4d2-f679-5131-9988-43568bf8696c', '{"EN": "Substrate & Contracts Pallet", "ES": "Substrate y Contracts Pallet"}', '{"EN": "ink! targets the contracts pallet.", "ES": "ink! apunta al pallet de contratos."}', false, NULL, NULL, '// ink! smart contract structure\n#![cfg_attr(not(feature = "std"), no_std)]\n\n#[ink::contract]\nmod flipper {\n    /// Defines the storage of your contract.\n    #[ink(storage)]\n    pub struct Flipper {\n        value: bool,\n    }\n\n    impl Flipper {\n        /// Constructor: Initializes the contract\n        #[ink(constructor)]\n        pub fn new(init_value: bool) -> Self {\n            Self { value: init_value }\n        }\n\n        /// Message: A public function that can be called by users\n        /// Flips the current value of the boolean.\n        #[ink(message)]\n        pub fn flip(&mut self) {\n            self.value = !self.value;\n        }\n\n        /// Message: Simply returns the current value.\n        #[ink(message)]\n        pub fn get(&self) -> bool {\n            self.value\n        }\n    }\n}\n\nfn main() {\n    println!("ink! contracts compile to WASM for the Polkadot ecosystem.");\n}', NULL, '// ink! smart contract structure\n#![cfg_attr(not(feature = "std"), no_std)]\n\n#[ink::contract]\nmod flipper {\n    /// Defines the storage of your contract.\n    #[ink(storage)]\n    pub struct Flipper {\n        value: bool,\n    }\n\n    impl Flipper {\n        /// Constructor: Initializes the contract\n        #[ink(constructor)]\n        pub fn new(init_value: bool) -> Self {\n            Self { value: init_value }\n        }\n\n        /// Message: A public function that can be called by users\n        /// Flips the current value of the boolean.\n        #[ink(message)]\n        pub fn flip(&mut self) {\n            self.value = !self.value;\n        }\n\n        /// Message: Simply r