INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a92230a5-a05e-5123-b469-3995268f2841', '2092b487-55fe-528b-af70-b8a055253432', '{"EN": "Quiz: Storage", "ES": "Quiz: Almacenamiento"}', '{"EN": "Storage check.", "ES": "Chequeo de almacenamiento."}', true, NULL, '[{"id": "q-ink-2-1", "question": {"EN": "Why use `ink::storage::Mapping` instead of `HashMap`?", "ES": "\u00bfPor qu\u00e9 usar `ink::storage::Mapping` en lugar de `HashMap`?"}, "options": {"EN": ["It is faster in RAM", "It loads values lazily from storage", "It supports more types"], "ES": ["Es m\u00e1s r\u00e1pido en RAM", "Carga valores perezosamente del almacenamiento", "Soporta m\u00e1s tipos"]}, "correctIndex": 1, "explanation": {"EN": "`HashMap` loads all data into memory (gas expensive). `Mapping` only loads the requested key.", "ES": "`HashMap` carga todo en memoria (caro en gas). `Mapping` solo carga la clave pedida."}}, {"id": "q-ink-2-2", "question": {"EN": "What encoding does Substrate/ink! use?", "ES": "\u00bfQu\u00e9 codificaci\u00f3n usa Substrate/ink!?"}, "options": {"EN": ["JSON", "Protobuf", "SCALE"], "ES": ["JSON", "Protobuf", "SCALE"]}, "correctIndex": 2, "explanation": {"EN": "Simple Concatenated Aggregate Little-Endian (SCALE) is the standard lightweight codec.", "ES": "Simple Concatenated Aggregate Little-Endian (SCALE) es el codec ligero est\u00e1ndar."}}]', NULL, '[{"id": "q-ink-2-1", "question": {"EN": "Why use `ink::storage::Mapping` instead of `HashMap`?", "ES": "\u00bfPor qu\u00e9 usar `ink::storage::Mapping` en lugar de `HashMap`?"}, "options": {"EN": ["It is faster in RAM", "It loads values lazily from storage", "It supports more types"], "ES": ["Es m\u00e1s r\u00e1pido en RAM", "Carga valores perezosamente del almacenamiento", "Soporta m\u00e1s tipos"]}, "correctIndex": 1, "explanation": {"EN": "`HashMap` loads all data into memory (gas expensive). `Mapping` only loads the requested key.", "ES": "`HashMap` carga todo en memoria (caro e