INSERT INTO chapters (id, module_id, title, content, is_quiz, quiz_data, "order") VALUES ('a37dd57a-6d94-5617-8b71-a346fa3df9f9', '110fe194-b2b0-5042-bb14-0b074c22b891', '{"EN": "Ports & Adapters", "ES": "Puertos y Adaptadores"}', '{"EN": "# Hexagonal Architecture\n\nAlso known as Ports and Adapters. The goal is to isolate your core business logic (Domain) from the outside world (DB, HTTP, UI).\n\n## The Pattern in Rust\n1. **Domain**: Pure Rust structs. No dependencies on SQLx or Axum.\n2. **Ports**: Traits defined in the domain layer that define *how* the domain interacts with the world (e.g., `UserRepository`).\n3. **Adapters**: Implementations of those traits (e.g., `PostgresUserRepository`) or things that drive the domain (e.g., HTTP Handlers).", "ES": "# Arquitectura Hexagonal\n\nTambi\u00e9n conocida como Puertos y Adaptadores. El objetivo es aislar tu l\u00f3gica de negocio central (Dominio) del mundo exterior (BD, HTTP, UI).\n\n## El Patr\u00f3n en Rust\n1. **Dominio**: Structs de Rust puros. Sin dependencias de SQLx o Axum.\n2. **Puertos**: Traits definidos en la capa de dominio que definen *c\u00f3mo* el dominio interact\u00faa con el mundo (ej. `UserRepository`).\n3. **Adaptadores**: Implementaciones de esos traits (ej. `PostgresUserRepository`) o cosas que manejan el dominio (ej. Handlers HTTP)."}', false, NULL, NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from("Alice"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from("Alice"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from("Alice"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from("Alice"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from("Alice"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn mai