epends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from(\"Alice\"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!("Saving ''{}'' to Postgres...", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from("Alice"));\n}', NULL, 'trait Repository {\n    fn save(&self, data: String);\n}\n\nstruct PostgresRepo;\nimpl Repository for PostgresRepo {\n    fn save(&self, data: String) {\n        println!(\"Saving ''{}'' to Postgres...\", data);\n    }\n}\n\n// Service depends on Trait, not implementation\nfn create_user(repo: &impl Repository, name: String) {\n    repo.save(name);\n}\n\nfn main() {\n    let repo = PostgresRepo;\n    create_user(&repo, String::from(\"Alice\"));\n}', 1);
